-- 6001_main_ep01.csv (22 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"肌を焦がすような乾いた風が、荒涼たる砂丘を撫でる。ここはローランド聖王国の辺境。かつて栄華を極めた王国の威光も、この村までは届かない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text_village","choices":[{"label":"続ける","next":"text_village"}]},"text_village":{"text":"崩れかけた土壁。痩せた家畜。乾いた井戸の底に溜まった泥水。そんな場所から——君の物語は始まる。","type":"text","bg_key":"bg_road_day","next":"text_board","choices":[{"label":"続ける","next":"text_board"}]},"text_board":{"text":"村の入口の掲示板に釘で留められた黄ばんだ紙。「傭兵募集——王国軍輸送部隊の護衛。報酬は銀貨十五枚。死亡時の補償はなし」銀貨十五枚。この村で一ヶ月は食いつなげる額だ。迷う理由はなかった。","type":"text","bg_key":"bg_road_day","next":"text_cargo","choices":[{"label":"続ける","next":"text_cargo"}]},"text_cargo":{"text":"荷馬車が三台。積まれた木箱の中身は「軍需物資」とだけ書かれている。兵士が六人。全員、目が死んでいた。","type":"text","bg_key":"bg_road_day","next":"text_gawain_appear","choices":[{"label":"続ける","next":"text_gawain_appear"}]},"text_gawain_appear":{"text":"木箱を数え終えようとした時——背後から、しゃがれた太い声が飛んできた。「おい、そこの新入り！ ぼんやりするな。太陽が高くなれば、野盗の連中がいつ湧いてきてもおかしくないぞ！」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_look","choices":[{"label":"続ける","next":"text_gawain_look"}]},"text_gawain_look":{"text":"振り返ると、甲冑の上に砂埃を被った大柄な男が立っていた。額の傷跡が古い。歴戦の証だ。","type":"text","bg_key":"bg_road_day","next":"text_gawain_intro","choices":[{"label":"続ける","next":"text_gawain_intro"}]},"text_gawain_intro":{"text":"男はこちらを値踏みするように見てから、顎をしゃくった。「で、お前が今日の新しい肉壁か。剣の腕はどうだ。振れるか？ それとも、振るフリだけか？」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"choice1","choices":[{"label":"「急いで積み込みます」","next":"text_gawain_react"},{"label":"「あんたはここで指図するだけか？」","next":"text_gawain_react"}]},"text_gawain_react":{"text":"男は鼻で笑った。だが、目は笑っていなかった。「威勢はいいが、口ほどにもない奴はすぐ死ぬのが戦場だ。俺はこの二十年で、そういう奴を百人以上見送った」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_name","choices":[{"label":"続ける","next":"text_gawain_name"}]},"text_gawain_name":{"text":"「俺はガウェイン。この部隊の小隊長にして——お前たち新米を死なせないための監視役だ」ガウェインは砂漠の地平線を見た。その目には——疲労と、それでも消えない何かが残っていた。","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"text":"ガウェインがパーティに加わった。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_gawain"},"next":"text_alarm","choices":[{"label":"続ける","next":"text_alarm"}]},"text_alarm":{"text":"ガウェインが何かを言いかけた、その瞬間——砂埃の向こうから、けたたましい怒声と馬の嘶きが迫ってきた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text_scout","choices":[{"label":"続ける","next":"text_scout"}]},"text_scout":{"text":"丘の上から斥候が転がり落ちてきた。「小隊長！ 前方の丘より正体不明の集団が接近！十、いや二十……武器を持っています。野盗です！」","type":"text","bg_key":"bg_road_day","next":"text_gawain_order","choices":[{"label":"続ける","next":"text_gawain_order"}]},"text_gawain_order":{"text":"ガウェインが素早く抜刀した。「チッ……言葉の先からこれだ。おい新入り、あの木箱は死守しろ。荷を奪われりゃ俺たちの首が飛ぶ。——文字通りにな」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_bandit_taunt","choices":[{"label":"続ける","next":"text_bandit_taunt"}]},"text_bandit_taunt":{"text":"野盗の頭目らしき男が、丘の上から叫んだ。「おう、王国の犬ども！ おとなしく荷を置いて消えな！抵抗するなら——女房と子供に遺言を書く暇くらいはやるぜ！」","type":"text","bg_key":"bg_road_day","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"己の力と生き残る意志を示す最初の手柄を立てる時が来た。震える手で武器を握り直せ！","type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"200","choices":[{"label":"迎撃する","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"剣を振り抜き、最後の一人を砂に沈めた。荒い息を吐く。手が震えている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text_bandit_dying","choices":[{"label":"続ける","next":"text_bandit_dying"}]},"text_bandit_dying":{"text":"足元に転がった野盗が、薄れゆく目でこちらを見上げた。「……へへ。やるじゃねえか、新入り。だがな——俺たちを雇ったのは、お前らの国の連中だぜ」男の目から光が消えた。","type":"text","bg_key":"bg_road_day","next":"text_gawain_look2","choices":[{"label":"続ける","next":"text_gawain_look2"}]},"text_gawain_look2":{"text":"ガウェインが死体を一瞥した。その顔は、何かを察したように険しかった。","type":"text","bg_key":"bg_road_day","next":"text_gawain_praise","choices":[{"label":"続ける","next":"text_gawain_praise"}]},"text_gawain_praise":{"text":"「……悪くない太刀筋だ。初陣にしては、な。これなら戦場でも生き残れるかもしれん」ガウェインは一度だけ、こちらの肩を叩いた。岩のように硬い手だった。","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_depart","choices":[{"label":"続ける","next":"text_gawain_depart"}]},"text_gawain_depart":{"text":"「さあ、荷馬車を出すぞ。日が暮れる前に次の宿場に着かなければ、今度は本物の盗賊団に囲まれる」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"text":"宿場に着き、任務完了。ガウェインは部隊と共に別行動を取ることになった。「また会うこともあるだろう。……死ぬなよ、新入り」大きな背中が砂埃の向こうに消えていく。","type":"leave","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"初めての実戦を終え、君の傭兵としての旅路が幕を開けた。死に際の野盗が遺した言葉が、耳の奥で反芻していた。「俺たちを雇ったのは、お前らの国の連中だ」——考えるのは、後にしよう。今はただ、生きている。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]}}}'::jsonb, rewards = '{"gold":150,"exp":80,"reputation":5}'::jsonb WHERE id = 6001;

-- 6002_main_ep02.csv (20 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"野盗撃退の働きが認められ、ガウェインの推薦で国境警備任務に配属された。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text_deploy","choices":[{"label":"続ける","next":"text_deploy"}]},"text_deploy":{"text":"配属先は、ローランドとマルカンド砂塵王国の国境地帯。赤茶けた荒野が地平線まで続いている。吹きつける砂風だけが唯一の挨拶だ。","type":"text","bg_key":"bg_road_day","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"text":"ガウェインがパーティに加わった。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_gawain"},"next":"text_patrol","choices":[{"label":"続ける","next":"text_patrol"}]},"text_patrol":{"text":"国境の荒野を並んで歩く。見渡す限りの赤茶けた土と、吹き荒れる空風の音。兵士たちの間には、得体の知れない緊張感が蔓延していた。","type":"text","bg_key":"bg_road_day","next":"text_gawain_suspicion","choices":[{"label":"続ける","next":"text_gawain_suspicion"}]},"text_gawain_suspicion":{"text":"「最近、この辺りでは武装した集団が頻繁に出没している。ただのゴロツキにしては、妙に動きに統率が取れているのが気掛かりだ」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_weapons","choices":[{"label":"続ける","next":"text_gawain_weapons"}]},"text_gawain_weapons":{"text":"ガウェインは歩きながら、地面に残された足跡を見ていた。軍靴の跡。等間隔。訓練された歩幅だ。「それに——あの野盗どもが使っていた武器の質。紋章は削ってあったが、鋼の色でわかる。あれはどこかの正規軍の官給品だ」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_hunch","choices":[{"label":"続ける","next":"text_gawain_hunch"}]},"text_gawain_hunch":{"text":"声を落とした。「……嫌な予感がするんだよ。二十年の勘がな」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"choice1","choices":[{"label":"「隣国マルカンドの兵士では？」","next":"text_gawain_reply"},{"label":"「誰であろうと、斬るだけです」","next":"text_gawain_reply"}]},"text_gawain_reply":{"text":"「……かもしれん。マルカンド側も、我が王国の膨張を警戒して水面下で動いているという噂はある」ガウェインは砂を蹴った。","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_doubt","choices":[{"label":"続ける","next":"text_gawain_doubt"}]},"text_gawain_doubt":{"text":"「だがな。もし逆だったらどうする。——あの武器を持たせたのが、俺たちの側だったら」沈黙。風だけが吹いている。「いずれにせよ、油断するなよ」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_approach","choices":[{"label":"続ける","next":"text_approach"}]},"text_approach":{"text":"砂丘の向こうから、黒い布で顔を覆った集団が現れた。小隊を半包囲するような陣形。音もなく、等間隔で展開している。練度を積んだ軍人の歩法だ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text_formation","choices":[{"label":"続ける","next":"text_formation"}]},"text_formation":{"text":"「……来たか。見ろ、あの展開速度。野盗がこんな動きをするものか」ガウェインが剣を抜いた。「陣形を崩すな。背中を取られるなよ。——死にたくなければ、隣の奴を守れ！」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_enemy_taunt","choices":[{"label":"続ける","next":"text_enemy_taunt"}]},"text_enemy_taunt":{"text":"黒布の男の一人が叫んだ。声には訛りがない。訓練された発声だった。「——王国の犬は、ここまで鼻が利くのか。仕方ない。証拠は残すな。全員殺せ」","type":"text","bg_key":"bg_road_day","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"正体不明の武装集団との戦闘！統率された軍人相手の実戦だ！","type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"202","choices":[{"label":"迎撃する","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"統率の取れた激しい攻撃を辛くも凌ぎ切った。最後の一人が膝をついた。黒布の下の顔は——若い。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text_dying","choices":[{"label":"続ける","next":"text_dying"}]},"text_dying":{"text":"「……お前たちも、いずれわかる。命令に従わなければ、家族が殺される。俺たちには……選択肢がなかった」男は砂の上に倒れた。","type":"text","bg_key":"bg_road_day","next":"text_corpse","choices":[{"label":"続ける","next":"text_corpse"}]},"text_corpse":{"text":"死体の顔を確認しようと布を剥ぐ。認識章は一切持っていない。だが、落とした武器には——意図的に削り潰された「正規軍の紋章」の痕跡が残されていた。","type":"text","bg_key":"bg_road_day","next":"text_gawain_silent","choices":[{"label":"続ける","next":"text_gawain_silent"}]},"text_gawain_silent":{"text":"ガウェインが武器を拾い上げ、紋章の痕跡を親指でなぞった。長い沈黙の後、武器を砂の上に投げ捨てた。","type":"text","bg_key":"bg_road_day","next":"text_gawain_report","choices":[{"label":"続ける","next":"text_gawain_report"}]},"text_gawain_report":{"text":"「……国境地帯に、泥沼の戦乱を予感させる不穏な空気が漂っている。俺は本隊に報告してくる。お前は宿営地で待て」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"text":"ガウェインは報告のため本隊へ戻ることになった。「また別の任務で会うだろう。……死ぬなよ」振り返らなかった。","type":"leave","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"武装集団の正体は、結局わからなかった。だが、一つだけ確かなことがある。あの若い兵士が最後に言った言葉。「命令に従わなければ、家族が殺される」——この戦いは、誰のためのものなのか。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]}}}'::jsonb, rewards = '{"gold":200,"exp":100,"reputation":5}'::jsonb WHERE id = 6002;

-- 6003_main_ep03.csv (19 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"マルカンド砂塵王国の商業都市ジャハーラ。砂漠の交差点に位置するオアシス都市だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"text_city","choices":[{"label":"続ける","next":"text_city"}]},"text_city":{"text":"色とりどりの布屋根が並ぶ市場。香辛料と炭火焼きの匂い。異国の音楽と笑い声。だが——何かが違う。","type":"text","bg_key":"bg_desert","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"text":"ガウェインがパーティに加わった。","type":"guest_join","bg_key":"bg_desert","params":{"guest_id":"npc_guest_gawain"},"next":"text_suspicion","choices":[{"label":"続ける","next":"text_suspicion"}]},"text_suspicion":{"text":"「……気づいたか。この街の人間、自分たちを見る目が変わった」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_suspicion2","choices":[{"label":"続ける","next":"text_suspicion2"}]},"text_suspicion2":{"text":"ガウェインが水筒の水を捨てた。匂いを嗅いで、顔を歪めた。「あの露天商、笑顔で水を売りながら——目が笑っていない」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_water","choices":[{"label":"続ける","next":"text_water"}]},"text_water":{"text":"都市の水源であるオアシスの池に行き着いた。水面が微かに変色していた。淡い紫色。","type":"text","bg_key":"bg_desert","next":"text_water2","choices":[{"label":"続ける","next":"text_water2"}]},"text_water2":{"text":"「……毒だ。誰かが水脈に毒を流している。このまま放置すれば、住民全員が死ぬ」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_trace","choices":[{"label":"続ける","next":"text_trace"}]},"text_trace":{"text":"水脈を辿って上流へ。砂漠の地下水路を進むと——洞窟の奥に毒薬の瓶が大量に隠されていた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"text_trace2","choices":[{"label":"続ける","next":"text_trace2"}]},"text_trace2":{"text":"そしてその隅に、逃げ遅れた工作員が一人。","type":"text","bg_key":"bg_desert","next":"text_spy_taunt","choices":[{"label":"続ける","next":"text_spy_taunt"}]},"text_spy_taunt":{"text":"工作員は観念したように笑った。「へぇ。見つけたか、大したもんだ」","type":"text","bg_key":"bg_desert","next":"text_spy_taunt2","choices":[{"label":"続ける","next":"text_spy_taunt2"}]},"text_spy_taunt2":{"text":"「だが知っているか？ もう三つの都市に仲間が散っている。——それが、自分たちの仕事だ」","type":"text","bg_key":"bg_desert","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"工作員の毒使いとの戦闘！ 奴を倒して解毒の手がかりを得ろ！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle","enemy_group_id":"201","choices":[{"label":"毒を止めるために戦う","next":"text_dying_spy"}],"battle_success_next":"text_dying_spy"},"text_dying_spy":{"text":"工作員が崩れ落ちた。「……自分は任務を果たした。国のため……」男の手から紋章の欠片が落ちた。","type":"text","bg_key":"bg_desert","next":"text_emblem","choices":[{"label":"続ける","next":"text_emblem"}]},"text_emblem":{"text":"ガウェインが欠片を拾い上げた。顔が蒼白になった。「……この紋章は。……まさか」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_emblem2","choices":[{"label":"続ける","next":"text_emblem2"}]},"text_emblem2":{"text":"紋章は——ローランド聖王国の特務機関のものだった。","type":"text","bg_key":"bg_desert","next":"text_gawain_shock","choices":[{"label":"続ける","next":"text_gawain_shock"}]},"text_gawain_shock":{"text":"「嘘だろ……。毒を撒いたのが王国の人間なら……自分たちは何を守っているんだ」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_shock2","choices":[{"label":"続ける","next":"text_gawain_shock2"}]},"text_gawain_shock2":{"text":"ガウェインは紋章を握りつぶした。「……行くぞ。考えるのは後だ。今は——この街の人間を助けることが先だ」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"text":"「工作員の解毒剤レシピを元に、本隊へ報告と救援要請に向かう。……後は任せたぞ」","type":"leave","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"応急処置で街の水源は辛うじて浄化された。だが、紋章の事実は重い。ガウェインの目が、日に日に険しくなっていく。","type":"end","result":"success","bg_key":"bg_desert","choices":[]}}}'::jsonb, rewards = '{"gold":300,"exp":120,"reputation":5}'::jsonb WHERE id = 6003;

-- 6004_main_ep04.csv (32 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"オアシス都市での毒物事件から数日。ガウェインの小隊と共に、マルカンド領内の交易路の安全確認任務に就いていた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"text":"ガウェインがパーティに加わった。","type":"guest_join","bg_key":"bg_desert","params":{"guest_id":"npc_guest_gawain"},"next":"text_patrol","choices":[{"label":"続ける","next":"text_patrol"}]},"text_patrol":{"text":"砂漠の交易路を馬で進む。荷馬車の轍は残っているが、行き交う商人の姿が少ない。","type":"text","bg_key":"bg_desert","next":"text_patrol2","choices":[{"label":"続ける","next":"text_patrol2"}]},"text_patrol2":{"text":"以前はラクダの隊列が途切れなかったこの道が、妙に静かだった。","type":"text","bg_key":"bg_desert","next":"text_rumor","choices":[{"label":"続ける","next":"text_rumor"}]},"text_rumor":{"text":"「おかしいな。この道はマルカンド有数の交易路のはずだが」ガウェインが馬の手綱を引いた。","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_rumor2","choices":[{"label":"続ける","next":"text_rumor2"}]},"text_rumor2":{"text":"「……最近、商人が消えているという噂を聞いた」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_merchant","choices":[{"label":"続ける","next":"text_merchant"}]},"text_merchant":{"text":"交易路の中継点に着いた。普段なら賑わう隊商宿が、閑散としている。","type":"text","bg_key":"bg_desert","next":"text_merchant2","choices":[{"label":"続ける","next":"text_merchant2"}]},"text_merchant2":{"text":"宿の主人が怯えた顔でこちらを見ている。奥から、血まみれの男がよろめき出てきた。","type":"text","bg_key":"bg_desert","next":"text_merchant_plea","choices":[{"label":"続ける","next":"text_merchant_plea"}]},"text_merchant_plea":{"text":"「た、助けてくれ……！ 賞金稼ぎだ。奴らが……商隊を襲った。仲間は皆殺しにされた」","type":"text","bg_key":"bg_desert","next":"text_merchant_plea2","choices":[{"label":"続ける","next":"text_merchant_plea2"}]},"text_merchant_plea2":{"text":"「自分だけ、荷馬車の下に隠れて逃げてきたんだ……」男は震えながら、砂漠の東を指さした。","type":"text","bg_key":"bg_desert","next":"text_gawain_analysis","choices":[{"label":"続ける","next":"text_gawain_analysis"}]},"text_gawain_analysis":{"text":"「賞金稼ぎだと？ この辺りで活動する賞金稼ぎは、通常は懸賞金リストの犯罪者しか狙わない」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_analysis2","choices":[{"label":"続ける","next":"text_gawain_analysis2"}]},"text_gawain_analysis2":{"text":"「ましてや中立の商人を襲う理由がない。——王国の依頼でなければ、な」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_analysis3","choices":[{"label":"続ける","next":"text_gawain_analysis3"}]},"text_gawain_analysis3":{"text":"「消えている商人に共通点がある。全員、ローランドとの交易に反対する有力者だ」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_trail","choices":[{"label":"続ける","next":"text_trail"}]},"text_trail":{"text":"商人の証言を頼りに、砂漠の東へ向かった。岩場の陰に、野営の跡があった。","type":"text","bg_key":"bg_wasteland","next":"text_trail2","choices":[{"label":"続ける","next":"text_trail2"}]},"text_trail2":{"text":"消した焚き火。砂に埋められた食料の残骸。——そして、複数の足跡が一方向に向かっている。","type":"text","bg_key":"bg_wasteland","next":"text_ambush_site","choices":[{"label":"続ける","next":"text_ambush_site"}]},"text_ambush_site":{"text":"岩場の先に、開けた場所があった。賞金稼ぎの一団が、別の商隊を包囲しているのが見えた。","type":"text","bg_key":"bg_wasteland","next":"text_ambush_site2","choices":[{"label":"続ける","next":"text_ambush_site2"}]},"text_ambush_site2":{"text":"商人たちが荷車の陰に隠れ、震えている。","type":"text","bg_key":"bg_wasteland","next":"text_hunter_reveal","choices":[{"label":"続ける","next":"text_hunter_reveal"}]},"text_hunter_reveal":{"text":"賞金稼ぎのリーダーらしき男が、馬から降りて商人の前に立った。","type":"text","bg_key":"bg_wasteland","next":"text_hunter_reveal2","choices":[{"label":"続ける","next":"text_hunter_reveal2"}]},"text_hunter_reveal2":{"text":"「——悪く思うなよ。これは仕事だ。お前たちの名前は、リストに載っている」","type":"text","bg_key":"bg_wasteland","next":"text_hunter_reveal3","choices":[{"label":"続ける","next":"text_hunter_reveal3"}]},"text_hunter_reveal3":{"text":"男の腰に、見覚えのある紋章が刻まれた許可証が光った。ローランド王国の公印だ。","type":"text","bg_key":"bg_wasteland","next":"text_hunter_taunt","choices":[{"label":"続ける","next":"text_hunter_taunt"}]},"text_hunter_taunt":{"text":"こちらに気づいたリーダーが、薄ら笑いを浮かべた。","type":"text","bg_key":"bg_wasteland","next":"text_hunter_taunt2","choices":[{"label":"続ける","next":"text_hunter_taunt2"}]},"text_hunter_taunt2":{"text":"「おや、お節介な連中が来たか。お前たちも標的リストに載っているぞ。マルカンドに協力する裏切り者としてな」","type":"text","bg_key":"bg_wasteland","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"王国公認の賞金稼ぎとの戦闘！ 商人たちを守り、追跡者を撃退しろ！","type":"battle","bg_key":"bg_wasteland","bgm":"bgm_battle","enemy_group_id":"230","choices":[{"label":"生き延びるために戦う","next":"text_aftermath"}],"battle_success_next":"text_aftermath"},"text_aftermath":{"text":"賞金稼ぎたちを撃退した。リーダーの男が岩壁にもたれかかり、荒い息をついている。","type":"text","bg_key":"bg_wasteland","next":"text_aftermath2","choices":[{"label":"続ける","next":"text_aftermath2"}]},"text_aftermath2":{"text":"「……ふ。まさか、こんなところで負けるとはな」","type":"text","bg_key":"bg_wasteland","next":"text_identity","choices":[{"label":"続ける","next":"text_identity"}]},"text_identity":{"text":"男の懐から、折り畳まれた書類が落ちた。拾い上げると——王国軍の身分証だった。","type":"text","bg_key":"bg_wasteland","next":"text_identity2","choices":[{"label":"続ける","next":"text_identity2"}]},"text_identity2":{"text":"「ローランド王国軍・第三遠征大隊・元伍長」退役した正規兵だ。王国が賞金稼ぎを装わせて、汚れ仕事をさせていた。","type":"text","bg_key":"bg_wasteland","next":"text_gawain_omen","choices":[{"label":"続ける","next":"text_gawain_omen"}]},"text_gawain_omen":{"text":"ガウェインが身分証を見つめた。長い沈黙の後、口を開いた。","type":"text","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_omen2","choices":[{"label":"続ける","next":"text_gawain_omen2"}]},"text_gawain_omen2":{"text":"「……賞金稼ぎを使って邪魔者を消す。工作員で世論を操る。そしてその次は——正規軍が来る」","type":"text","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_omen3","choices":[{"label":"続ける","next":"text_gawain_omen3"}]},"text_gawain_omen3":{"text":"「これは戦争の前哨戦だ。もう——止められないかもしれん」","type":"text","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"text":"「この身分証があれば、王国の関与を証明できる。——だが、上が握り潰す可能性もある」背を向ける直前、低く呟いた。「……時間がない」","type":"leave","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"助けた商人たちが、何度も頭を下げて去っていった。だが——これは氷山の一角に過ぎない。戦争の歯車は、もう回り始めている。","type":"end","result":"success","bg_key":"bg_wasteland","choices":[]}}}'::jsonb, rewards = '{"gold":400,"exp":150,"reputation":10}'::jsonb WHERE id = 6004;

-- 6005_main_ep05.csv (19 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"嫌な予感は的中した。王国が「反逆者」としてガウェインの名を公表した。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_tense","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"虐殺の真実を報告しようとしただけで。王国軍の精鋭部隊「鉄騎隊」がこちらに向かっている。","type":"text","bg_key":"bg_bandit_camp","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"text":"ガウェインがパーティに加わった。","type":"guest_join","bg_key":"bg_bandit_camp","params":{"guest_id":"npc_guest_gawain"},"next":"text_ambush","choices":[{"label":"続ける","next":"text_ambush"}]},"text_ambush":{"text":"逃走中のマルカンド前線拠点付近。四方から包囲された。精鋭部隊が、音もなく陣形を敷いていた。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_crisis","next":"text_commander","choices":[{"label":"続ける","next":"text_commander"}]},"text_commander":{"text":"部隊長が馬上から見下ろした。若い。三十前後。だが——目が据わっている。","type":"text","bg_key":"bg_bandit_camp","next":"text_commander2","choices":[{"label":"続ける","next":"text_commander2"}]},"text_commander2":{"text":"「反逆者ガウェイン。王命により、ここで処断する。投降すれば一思いに殺してやる」","type":"text","bg_key":"bg_bandit_camp","next":"text_gawain_resolve","choices":[{"label":"続ける","next":"text_gawain_resolve"}]},"text_gawain_resolve":{"text":"ガウェインが剣を抜いた。「お前がこの目で見たものは全て真実だ」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_resolve2","choices":[{"label":"続ける","next":"text_gawain_resolve2"}]},"text_gawain_resolve2":{"text":"「王国が何をしているか——世界に知らせなければならない。自分たちが何のために戦っているのかを」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_sacrifice","choices":[{"label":"続ける","next":"text_gawain_sacrifice"}]},"text_gawain_sacrifice":{"text":"「ここは自分が引き受ける。お前は東へ行け。夜刀神国の国境を越えれば、王国の手は届かない」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_first_wave","choices":[{"label":"続ける","next":"text_first_wave"}]},"text_first_wave":{"text":"ガウェインの言葉を遮るように、第一波の兵士たちが突撃してきた。","type":"text","bg_key":"bg_bandit_camp","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"王国軍精鋭部隊・第一波との戦闘！","type":"battle","bg_key":"bg_bandit_camp","bgm":"bgm_battle_strong","enemy_group_id":"203","choices":[{"label":"切り抜ける","next":"text_wave1_clear"}],"battle_success_next":"text_wave1_clear"},"text_wave1_clear":{"text":"第一波を退けた。だが次の波が来る。ガウェインが背中を押した。「行け！今だ！」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_commander_second","choices":[{"label":"続ける","next":"text_commander_second"}]},"text_commander_second":{"text":"部隊長が叫んだ。「第二隊、回り込め！逃がすな！」新たな兵士たちが迫る。","type":"text","bg_key":"bg_bandit_camp","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"王国軍精鋭部隊・第二波との戦闘！","type":"battle","bg_key":"bg_bandit_camp","bgm":"bgm_battle_strong","enemy_group_id":"203","choices":[{"label":"道を切り拓く","next":"text_gawain_last"}],"battle_success_next":"text_gawain_last"},"text_gawain_last":{"text":"第二波を退けた。だが——ガウェインが膝をついた。背中に矢が三本刺さっている。","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_gawain_last2","choices":[{"label":"続ける","next":"text_gawain_last2"}]},"text_gawain_last2":{"text":"「お前は生き延びろ。生き延びて、この目で世界の果てを見届けろ。自分の分まで……な……」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"text":"ガウェインは立ち上がり、残る兵士たちの前に一人で立ちはだかった。もう振り返らなかった。","type":"leave","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text_run","choices":[{"label":"続ける","next":"text_run"}]},"text_run":{"text":"走った。振り返らなかった。背後で剣戟の音がした。叫び声。——そして、静寂。","type":"text","bg_key":"bg_bandit_camp","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"走り続けた。太陽が沈むまで。東へ。ただ東へ。「生き延びて、この目で世界の果てを見届けろ」","type":"end","result":"success","bg_key":"bg_bandit_camp","choices":[]}}}'::jsonb, rewards = '{"gold":500,"exp":200,"reputation":15}'::jsonb WHERE id = 6005;

-- 6006_main_ep06.csv (27 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"泥と血に塗れた敗残兵の群れに紛れ、前線拠点から逃げ延びた。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"東へ。ただ東へ走った。何日走ったかわからない。","type":"text","bg_key":"bg_forest_day","next":"text_start3","choices":[{"label":"続ける","next":"text_start3"}]},"text_start3":{"text":"気がつけば——鬱蒼とした密林の中にいた。夜刀神国の国境域。人の気配はない。","type":"text","bg_key":"bg_forest_day","next":"text_wound","choices":[{"label":"続ける","next":"text_wound"}]},"text_wound":{"text":"肩の傷が熱を持っている。水筒はとうに空。食料も底をついた。","type":"text","bg_key":"bg_forest_day","next":"text_wound2","choices":[{"label":"続ける","next":"text_wound2"}]},"text_wound2":{"text":"座り込みたい。だが——座ったら、もう立てない気がした。","type":"text","bg_key":"bg_forest_day","next":"text_flashback","choices":[{"label":"続ける","next":"text_flashback"}]},"text_flashback":{"text":"目を閉じれば、フラッシュバックする。無数の槍に貫かれながら——笑った老騎士の顔。","type":"text","bg_key":"bg_forest_day","next":"text_flashback2","choices":[{"label":"続ける","next":"text_flashback2"}]},"text_flashback2":{"text":"「生き延びて、この目で世界の果てを見届けろ」呪いのような。祈りのような。その言葉だけが、折れそうな膝を支えていた。","type":"text","bg_key":"bg_forest_day","next":"text_pursuit","choices":[{"label":"続ける","next":"text_pursuit"}]},"text_pursuit":{"text":"王国の残党狩りは執拗だった。戦場から逃げた傭兵や脱走兵は、見つけ次第処刑される。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"text_pursuit2","choices":[{"label":"続ける","next":"text_pursuit2"}]},"text_pursuit2":{"text":"「裏切り者に慈悲はない」——それが王国軍の鉄の掟だ。","type":"text","bg_key":"bg_forest_day","next":"text_dogs","choices":[{"label":"続ける","next":"text_dogs"}]},"text_dogs":{"text":"遠くから軍用犬の吠え声が聞こえた。軍靴が落ち葉を踏む音。近い。","type":"text","bg_key":"bg_forest_day","next":"text_dogs2","choices":[{"label":"続ける","next":"text_dogs2"}]},"text_dogs2":{"text":"前方に道が二本。険しいけもの道と、開けた川沿いの道。","type":"text","bg_key":"bg_forest_day","next":"choice1","choices":[{"label":"険しいけもの道を進む","next":"text_path_hard"},{"label":"見つかりやすいが川沿いを急ぐ","next":"text_river"}]},"text_path_hard":{"text":"崖沿いのけもの道を選んだ。足場は最悪だ。蔦が足首に絡みつき、棘が腕を引っ掻く。","type":"text","bg_key":"bg_forest_day","next":"text_path_hard2","choices":[{"label":"続ける","next":"text_path_hard2"}]},"text_path_hard2":{"text":"岩場を這い上がるたびに肩の傷が開く。だが——追手の犬の声が、少しずつ遠くなっていく。","type":"text","bg_key":"bg_forest_day","next":"text_path_exhaust","choices":[{"label":"続ける","next":"text_path_exhaust"}]},"text_path_exhaust":{"text":"険しい道の甲斐あって、追手の目を完全に欺くことに成功した。","type":"text","bg_key":"bg_forest_day","next":"text_path_exhaust2","choices":[{"label":"続ける","next":"text_path_exhaust2"}]},"text_path_exhaust2":{"text":"最後の崖を登りきった時——膝が折れた。だが——密林の向こうに、木造の建物が見えた。夜刀神国の関所だ。","type":"text","bg_key":"bg_forest_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"text_river":{"text":"川沿いの道を選んだ。せせらぎの音が耳に心地よい。手を伸ばして水を掬い、乾いた喉に流し込んだ。","type":"text","bg_key":"bg_river","next":"text_river2","choices":[{"label":"続ける","next":"text_river2"}]},"text_river2":{"text":"冷たい。生き返る心地がした。だが——開けた場所に出た代償は、すぐに支払わされることになった。","type":"text","bg_key":"bg_river","next":"text_ambush","choices":[{"label":"続ける","next":"text_ambush"}]},"text_ambush":{"text":"茂みが揺れた。黒い軍服を着た男たちが、川の両岸から姿を現した。","type":"text","bg_key":"bg_river","next":"text_ambush2","choices":[{"label":"続ける","next":"text_ambush2"}]},"text_ambush2":{"text":"追討部隊だ。全員、剣を抜いている。","type":"text","bg_key":"bg_river","next":"text_hunter_taunt","choices":[{"label":"続ける","next":"text_hunter_taunt"}]},"text_hunter_taunt":{"text":"部隊長が鼻で笑った。「見つけたぞ、マルカンドの残党が」","type":"text","bg_key":"bg_river","next":"text_hunter_taunt2","choices":[{"label":"続ける","next":"text_hunter_taunt2"}]},"text_hunter_taunt2":{"text":"「殺してもいいが——首は綺麗に刎ねろ。戦果報告に使う。一人でも多けりゃ、俺たちの飯の種になる」","type":"text","bg_key":"bg_river","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"王国軍追討部隊との戦闘！ 生き延びると決めたんだ。こんなところで犬死にするわけにはいかない！","type":"battle","bg_key":"bg_river","bgm":"bgm_battle","enemy_group_id":"406","choices":[{"label":"生き残る","next":"text_hunter_dying"}],"battle_success_next":"text_hunter_dying"},"text_hunter_dying":{"text":"部隊長が川辺に倒れた。水が赤く染まっていく。","type":"text","bg_key":"bg_river","next":"text_hunter_dying2","choices":[{"label":"続ける","next":"text_hunter_dying2"}]},"text_hunter_dying2":{"text":"「……へへ。やるじゃねえか、残党。だがな……俺たちは先遣だ。後ろに……あと三十人いる」目が閉じた。背後から犬の声が近づいてくる。","type":"text","bg_key":"bg_river","next":"text_run","choices":[{"label":"続ける","next":"text_run"}]},"text_run":{"text":"血のついた剣を洗いもせずに走り出した。走った。ただ走った。","type":"text","bg_key":"bg_river","next":"text_run2","choices":[{"label":"続ける","next":"text_run2"}]},"text_run2":{"text":"——密林が途切れた。木造の建物が見えた。夜刀神国の関所だ。","type":"text","bg_key":"bg_river","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"関所の影が立ちはだかっている。振り返った。追手の姿は——ない。膝をついた。——生きている。ガウェイン。自分は、まだ生きている。","type":"end","result":"success","bg_key":"bg_forest_day","choices":[]}}}'::jsonb, rewards = '{"gold":200,"exp":150,"reputation":5}'::jsonb WHERE id = 6006;

-- 6007_main_ep07.csv (24 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"密林を抜けた先に、巨大な木組みの門が聳えていた。夜刀神国の国境関所だ。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_mystery","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"柱の太さは一抱え以上。屋根には注連縄が渡されている。門の両脇に、甲冑姿の関守が二人。","type":"text","bg_key":"bg_bandit_camp","next":"text_gate","choices":[{"label":"続ける","next":"text_gate"}]},"text_gate":{"text":"関所の前には入国を待つ行商人や旅人の列ができていた。だが——ほとんど動いていない。","type":"text","bg_key":"bg_bandit_camp","next":"text_gate2","choices":[{"label":"続ける","next":"text_gate2"}]},"text_gate2":{"text":"戦乱を受けて入国審査は異常なほど厳格化されていた。通行証はない。身分証明もない。","type":"text","bg_key":"bg_bandit_camp","next":"text_document","choices":[{"label":"続ける","next":"text_document"}]},"text_document":{"text":"懐に手を当てた。紙の感触がある。道中で息絶えたローランドの兵士が最後の力で差し出した書類。","type":"text","bg_key":"bg_bandit_camp","next":"text_document2","choices":[{"label":"続ける","next":"text_document2"}]},"text_document2":{"text":"「……頼む。これを……然るべき者へ……」王国の機密書。使い方次第では、門を開ける鍵にもなるだろう。","type":"text","bg_key":"bg_bandit_camp","next":"text_guard_block","choices":[{"label":"続ける","next":"text_guard_block"}]},"text_guard_block":{"text":"関守の頭目が冷たい目で見下ろしてきた。四十代半ば。額に古傷。","type":"text","bg_key":"bg_bandit_camp","next":"text_guard_block2","choices":[{"label":"続ける","next":"text_guard_block2"}]},"text_guard_block2":{"text":"「止まれ。何者だ。通行証を持たぬ流れ者は通せぬ。——さっさと立ち去れ」","type":"text","bg_key":"bg_bandit_camp","next":"choice1","choices":[{"label":"「機密書を渡すので通してくれ」","next":"text_betray"},{"label":"「傭兵として雇ってくれ」","next":"text_normal"}]},"text_betray":{"text":"懐から機密書を取り出し差し出した。関守の表情が変わった。","type":"text","bg_key":"bg_bandit_camp","next":"text_betray2","choices":[{"label":"続ける","next":"text_betray2"}]},"text_betray2":{"text":"「……ほう。裏切りの代償か。……良かろう。通れ。——だが覚えておけ。裏切りで得た安全は、長くは持たんぞ」","type":"text","bg_key":"bg_bandit_camp","next":"text_betray_guilt","choices":[{"label":"続ける","next":"text_betray_guilt"}]},"text_betray_guilt":{"text":"関所の門が開いた。だが足が重い。あの兵士が最後に見せた目を思い出していた。","type":"text","bg_key":"bg_bandit_camp","next":"text_betray_guilt2","choices":[{"label":"続ける","next":"text_betray_guilt2"}]},"text_betray_guilt2":{"text":"死者の想いを安全と引き換えにした。その事実が、胸の奥に冷たい石のように沈んでいく。","type":"text","bg_key":"bg_bandit_camp","next":"betray_rep_penalty","choices":[{"label":"続ける","next":"betray_rep_penalty"}]},"betray_rep_penalty":{"text":"裏切りの代価","type":"modify_reputation","params":{"amount":-30},"next":"end_betray","choices":[{"label":"続ける","next":"end_betray"}]},"end_betray":{"text":"異国の風が吹き抜ける。湿った空気。木と土の匂い。だが——生きている。門を潜った。振り返らなかった。","type":"end","result":"success","bg_key":"bg_bandit_camp","choices":[]},"text_normal":{"text":"「腕には自信がある。傭兵として雇ってくれないか」関守の頭目が鼻で笑った。","type":"text","bg_key":"bg_bandit_camp","next":"text_normal2","choices":[{"label":"続ける","next":"text_normal2"}]},"text_normal2":{"text":"「傭兵だと？ ボロボロの敗残兵にか？ だが——ちょうど手を焼いていることがある」","type":"text","bg_key":"bg_bandit_camp","next":"text_tengu_intro","choices":[{"label":"続ける","next":"text_tengu_intro"}]},"text_tengu_intro":{"text":"「裏山の竹林に天狗が巣食っていてな。旅人が三人やられた。あの天狗を追い払って証拠を持ってくれば、通行を許可してやろう」","type":"text","bg_key":"bg_bandit_camp","next":"text_tengu_forest","choices":[{"label":"続ける","next":"text_tengu_forest"}]},"text_tengu_forest":{"text":"裏山の竹林。薄暗い。血と獣の臭い。竹を掻き分けた瞬間——頭上から鋭い風切り音が響いた。","type":"text","bg_key":"bg_bandit_camp","next":"text_tengu_appear","choices":[{"label":"続ける","next":"text_tengu_appear"}]},"text_tengu_appear":{"text":"見上げると——長い嘴と黒い翼を持つ異形が、竹の梢に佇んでいた。こちらを獲物と見定めている。","type":"text","bg_key":"bg_bandit_camp","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"裏山の天狗との戦闘！ 飢えた体で化け物じみた怪鳥に立ち向かえ！","type":"battle","bg_key":"bg_bandit_camp","bgm":"bgm_battle","enemy_group_id":"205","choices":[{"label":"勝利","next":"text_tengu_dead"}],"battle_success_next":"text_tengu_dead"},"text_tengu_dead":{"text":"血まみれの天狗の羽を関所の中庭に投げ込んだ。兵士たちが後ずさりした。","type":"text","bg_key":"bg_bandit_camp","next":"text_tengu_dead2","choices":[{"label":"続ける","next":"text_tengu_dead2"}]},"text_tengu_dead2":{"text":"関守の頭目がしばらく羽を見つめ——ゆっくりと振り返った。目が変わっていた。","type":"text","bg_key":"bg_bandit_camp","next":"text_guard_impressed","choices":[{"label":"続ける","next":"text_guard_impressed"}]},"text_guard_impressed":{"text":"「……見事な腕だ。通れ。夜刀神国はお前のような強者を歓迎する。——せいぜい長生きしろよ。この国も、外と同じくらい物騒だ」","type":"text","bg_key":"bg_bandit_camp","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"重い音を立てて関所の門が開いた。異国の風が吹き抜ける。夜刀神国。知らない土地。知らない言葉。だが——生きている。門を潜った。振り返らなかった。","type":"end","result":"success","bg_key":"bg_bandit_camp","choices":[]}}}'::jsonb, rewards = '{"gold":300,"exp":180,"reputation":10}'::jsonb WHERE id = 6007;

-- 6008_main_ep08.csv (22 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"夜刀神国に入境して数日が経った。都からは遠く離れた、辺境の寂れた宿屋。","type":"text","bg_key":"bg_tavern_night","bgm":"bgm_quest_tense","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"粗末な寝台。薄い布団。久しぶりに屋根の下で眠れる。それだけで十分に贅沢だった。","type":"text","bg_key":"bg_tavern_night","next":"text_rest","choices":[{"label":"続ける","next":"text_rest"}]},"text_rest":{"text":"横になった。肩の傷はまだ痛む。だが熱は引いた。三日ぶりの白米は、涙が出るほど美味かった。","type":"text","bg_key":"bg_tavern_night","next":"text_rest2","choices":[{"label":"続ける","next":"text_rest2"}]},"text_rest2":{"text":"目を閉じた。——だが、傭兵として染みついた勘が、眠りを浅くしていた。","type":"text","bg_key":"bg_tavern_night","next":"text_sound","choices":[{"label":"続ける","next":"text_sound"}]},"text_sound":{"text":"真夜中。ふと目が覚めた。虫の声が——止まっている。","type":"text","bg_key":"bg_tavern_night","next":"text_sound2","choices":[{"label":"続ける","next":"text_sound2"}]},"text_sound2":{"text":"窓の外で衣擦れの音。窓ガラスが細かく不自然に振動している。——鍵を探っている。三方向から気配がある。","type":"text","bg_key":"bg_tavern_night","next":"text_analysis","choices":[{"label":"続ける","next":"text_analysis"}]},"text_analysis":{"text":"ゆっくりと身を起こした。枕元の剣の柄を握った。囲まれている。しかもプロだ。","type":"text","bg_key":"bg_tavern_night","next":"text_analysis2","choices":[{"label":"続ける","next":"text_analysis2"}]},"text_analysis2":{"text":"この国は平穏に見えて、裏では各勢力が血みどろの暗闘を繰り広げている。","type":"text","bg_key":"bg_tavern_night","next":"text_door_break","choices":[{"label":"続ける","next":"text_door_break"}]},"text_door_break":{"text":"次の瞬間——扉が音もなく吹き飛んだ。煙幕。白い煙が部屋を満たす。視界がゼロになった。","type":"text","bg_key":"bg_tavern_night","next":"text_assassin_first","choices":[{"label":"続ける","next":"text_assassin_first"}]},"text_assassin_first":{"text":"煙の中から声がした。感情が一切ない声。「——標的を確認。これより排除する」鋭い刃が暗闇から迫った。","type":"text","bg_key":"bg_tavern_night","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"暗殺者第一波との戦闘！ 闇の中で迎撃しろ！","type":"battle","bg_key":"bg_tavern_night","bgm":"bgm_battle","enemy_group_id":"206","choices":[{"label":"迎撃する","next":"text_first_wave"}],"battle_success_next":"text_first_wave"},"text_first_wave":{"text":"三人を切り伏せた。だが死体は音もなく崩れ落ちた。悲鳴一つ上げない。","type":"text","bg_key":"bg_tavern_night","next":"text_first_wave2","choices":[{"label":"続ける","next":"text_first_wave2"}]},"text_first_wave2":{"text":"顔に表情がない。ただのゴロツキではない。夜刀の暗部——国が飼っている暗殺組織だ。","type":"text","bg_key":"bg_tavern_night","next":"text_first_wave3","choices":[{"label":"続ける","next":"text_first_wave3"}]},"text_first_wave3":{"text":"息をつく暇もなく、窓から新たな影が滑り込んできた。","type":"text","bg_key":"bg_tavern_night","next":"text_assassin_second","choices":[{"label":"続ける","next":"text_assassin_second"}]},"text_assassin_second":{"text":"二人目の暗殺者が月明かりの中で刃を構えた。格が違う。立ち姿に隙がない。","type":"text","bg_key":"bg_tavern_night","next":"text_assassin_second2","choices":[{"label":"続ける","next":"text_assassin_second2"}]},"text_assassin_second2":{"text":"低い声。女の声だった。「抵抗は無意味だ。貴様はここで夜霧に消える運命にある。——恨むなら、この国に足を踏み入れた己を恨め」","type":"text","bg_key":"bg_tavern_night","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"暗殺者精鋭との戦闘！ 月明かりに照らされた刃が乱舞する！","type":"battle","bg_key":"bg_tavern_night","bgm":"bgm_battle","enemy_group_id":"207","choices":[{"label":"生き残る","next":"text_silence"}],"battle_success_next":"text_silence"},"text_silence":{"text":"最後の刺客を窓の外へ蹴り落とした。","type":"text","bg_key":"bg_tavern_night","next":"text_silence2","choices":[{"label":"続ける","next":"text_silence2"}]},"text_silence2":{"text":"女の暗殺者は落ちる寸前に一言だけ残した。「……強いな。だが——これで終わりではない。我らの主は、貴様を放ってはおかぬ」","type":"text","bg_key":"bg_tavern_night","next":"text_silence3","choices":[{"label":"続ける","next":"text_silence3"}]},"text_silence3":{"text":"夜刀の闇は深い。底知れないほど——冷たい。","type":"text","bg_key":"bg_tavern_night","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"朝が来た。宿の主人が血だまりを見て腰を抜かした。金を置いて宿を出た。","type":"text","bg_key":"bg_tavern_night","next":"end_node2","choices":[{"label":"続ける","next":"end_node2"}]},"end_node2":{"text":"誰が、何の目的で刺客を差し向けたのか。それを知るには——もっと深く、この国の闇に踏み込むしかない。","type":"end","result":"success","bg_key":"bg_tavern_night","choices":[]}}}'::jsonb, rewards = '{"gold":350,"exp":200,"reputation":10}'::jsonb WHERE id = 6008;

-- 6009_main_ep09.csv (24 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"暗殺者による襲撃を凌いだ。その腕前が裏社会で囁かれ始めた頃——有力な大名から直接指名で護衛依頼が舞い込んだ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"報酬は破格。だが——依頼主の目が、妙に泳いでいた。","type":"text","bg_key":"bg_mountain","next":"text_procession","choices":[{"label":"続ける","next":"text_procession"}]},"text_procession":{"text":"依頼内容は領地内を横断する大名行列の護衛。表向きは「近隣の古社へ向けた祭礼行事の移動」。","type":"text","bg_key":"bg_mountain","next":"text_procession2","choices":[{"label":"続ける","next":"text_procession2"}]},"text_procession2":{"text":"だが——荷車が多すぎる。車輪の跡が異常に深い。中身がとてつもなく重いのだ。","type":"text","bg_key":"bg_mountain","next":"text_captain_order","choices":[{"label":"続ける","next":"text_captain_order"}]},"text_captain_order":{"text":"護衛団長が声を張り上げた。「皆の者、決して油断するな！ いつ何時、野盗や『逆賊』が襲いかかるとも知れんぞ！」","type":"text","bg_key":"bg_mountain","next":"text_captain_order2","choices":[{"label":"続ける","next":"text_captain_order2"}]},"text_captain_order2":{"text":"逆賊。その言葉に、護衛の兵士たちが微妙な顔をした。","type":"text","bg_key":"bg_mountain","next":"text_mountain","choices":[{"label":"続ける","next":"text_mountain"}]},"text_mountain":{"text":"行軍が険しい山道に差し掛かった時だった。突然、両側の崖上から大量の岩が落とされた。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_crisis","next":"text_mountain2","choices":[{"label":"続ける","next":"text_mountain2"}]},"text_mountain2":{"text":"地面が震え、行列の足が強制的に止まる。","type":"text","bg_key":"bg_mountain","next":"text_mob_appear","choices":[{"label":"続ける","next":"text_mob_appear"}]},"text_mob_appear":{"text":"土埃の向こうから——ボロボロの着物を纏い、農具や竹槍で武装した集団が雪崩のように押し寄せてきた。","type":"text","bg_key":"bg_mountain","next":"text_mob_appear2","choices":[{"label":"続ける","next":"text_mob_appear2"}]},"text_mob_appear2":{"text":"野盗ではない。餓えた獣のような必死さだ。子供がいる。女がいる。老人がいる。","type":"text","bg_key":"bg_mountain","next":"text_mob_leader","choices":[{"label":"続ける","next":"text_mob_leader"}]},"text_mob_leader":{"text":"先頭の男が血を吐くように叫んだ。痩せこけている。","type":"text","bg_key":"bg_mountain","next":"text_mob_leader2","choices":[{"label":"続ける","next":"text_mob_leader2"}]},"text_mob_leader2":{"text":"「米を返せ！！ その荷台に乗っているのは、俺たちの村から不当に収奪した年貢の米だ！」","type":"text","bg_key":"bg_mountain","next":"text_mob_leader3","choices":[{"label":"続ける","next":"text_mob_leader3"}]},"text_mob_leader3":{"text":"「家族が餓死しそうなのに——何が祭礼だ！！」男の後ろで、子供が泣いていた。","type":"text","bg_key":"bg_mountain","next":"text_captain_rage","choices":[{"label":"続ける","next":"text_captain_rage"}]},"text_captain_rage":{"text":"護衛団長が顔を真っ赤にした。「黙れ逆賊ども！！ 者ども、討ち捨てい！！」","type":"text","bg_key":"bg_mountain","next":"text_captain_rage2","choices":[{"label":"続ける","next":"text_captain_rage2"}]},"text_captain_rage2":{"text":"刀を抜いた。兵士たちが農民に向かって駆け出す。——自分もその一人だ。金を受け取った傭兵。雇い主を守る刃。","type":"text","bg_key":"bg_mountain","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"一揆勢との戦闘。彼らは逆賊か、それとも強欲な権力者の被害者か。だが——自分は金を受け取った傭兵だ。","type":"battle","bg_key":"bg_mountain","bgm":"bgm_battle","enemy_group_id":"404","choices":[{"label":"刃で応える","next":"text_aftermath"}],"battle_success_next":"text_aftermath"},"text_aftermath":{"text":"剣が閃くたびに悲痛な叫び声が上がった。農民たちが倒れていく。","type":"text","bg_key":"bg_mountain","next":"text_aftermath2","choices":[{"label":"続ける","next":"text_aftermath2"}]},"text_aftermath2":{"text":"鎌を振り上げた男が斬られて膝をついた。「……お前も……あいつらの犬か……」","type":"text","bg_key":"bg_mountain","next":"text_aftermath3","choices":[{"label":"続ける","next":"text_aftermath3"}]},"text_aftermath3":{"text":"「俺の村では……子供が三人……飯が食えずに死んだ。——それでもお前は……剣を振るうのか……」目が閉じた。","type":"text","bg_key":"bg_mountain","next":"text_captain_reward","choices":[{"label":"続ける","next":"text_captain_reward"}]},"text_captain_reward":{"text":"一揆は瞬く間に鎮圧された。護衛団長が満足げに笑った。","type":"text","bg_key":"bg_mountain","next":"text_captain_reward2","choices":[{"label":"続ける","next":"text_captain_reward2"}]},"text_captain_reward2":{"text":"「ふん、虫ケラどもが。……おい傭兵、よくやった。後で特別手当を払ってやろう」倒れた農民を踏みつけて荷車の方へ歩いていった。","type":"text","bg_key":"bg_mountain","next":"text_broken_tools","choices":[{"label":"続ける","next":"text_broken_tools"}]},"text_broken_tools":{"text":"倒れた農民たちの手には折れた鍬や鎌がこびりついていた。錆びた刃。藁で補修された柄。武器ではない。農具だ。","type":"text","bg_key":"bg_mountain","next":"text_broken_tools2","choices":[{"label":"続ける","next":"text_broken_tools2"}]},"text_broken_tools2":{"text":"血に染まった農具を見つめながら、冷たくなった剣を鞘に納めた。——今日、自分が何をしたのか。考えないようにした。","type":"text","bg_key":"bg_mountain","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"大名行列は無事に目的地に到着した。報酬は約束通り支払われた。だが——金貨の入った袋が、異様に重く感じた。","type":"end","result":"success","bg_key":"bg_mountain","choices":[]}}}'::jsonb, rewards = '{"gold":500,"exp":250,"reputation":15}'::jsonb WHERE id = 6009;

-- 6010_main_ep10.csv (23 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"夜刀神国の深奥部。誰も立ち入らないとされる禁域の古代神殿。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_crisis","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"一揆、暗殺者の暗躍、大名の不正——それら全てを裏で操っていた「何か」の痕跡を追って、ここまで来た。","type":"text","bg_key":"bg_boss_altar","next":"text_start3","choices":[{"label":"続ける","next":"text_start3"}]},"text_start3":{"text":"苔むした石段を登りきると、巨大な石の扉が口を開けていた。まるで——招かれているかのように。","type":"text","bg_key":"bg_boss_altar","next":"text_interior","choices":[{"label":"続ける","next":"text_interior"}]},"text_interior":{"text":"神殿の内部は異様な空気に満ちていた。苔むした石畳。天井が見えないほど高い。","type":"text","bg_key":"bg_boss_altar","next":"text_interior2","choices":[{"label":"続ける","next":"text_interior2"}]},"text_interior2":{"text":"壁の古代文字が淡く光っている。奥に——巨大な祭壇が、神々しい光を放っていた。","type":"text","bg_key":"bg_boss_altar","next":"text_visions","choices":[{"label":"続ける","next":"text_visions"}]},"text_visions":{"text":"祭壇の表面は水晶のように透明だった。中に世界が映っている。","type":"text","bg_key":"bg_boss_altar","next":"text_visions2","choices":[{"label":"続ける","next":"text_visions2"}]},"text_visions2":{"text":"炎上するマルカンドの砂漠。血に染まるローランドの城壁。夜刀の竹林で鎌を握ったまま倒れた農民。","type":"text","bg_key":"bg_boss_altar","next":"text_visions3","choices":[{"label":"続ける","next":"text_visions3"}]},"text_visions3":{"text":"全てが記録映像のように再生されていた。その上に——死者数、破壊された都市の数が数値化されて浮かんでいた。","type":"text","bg_key":"bg_boss_altar","next":"text_voice","choices":[{"label":"続ける","next":"text_voice"}]},"text_voice":{"text":"祭壇が脈打った。声が頭の中に直接響いた。感情がない非情な声。","type":"text","bg_key":"bg_boss_altar","next":"text_voice2","choices":[{"label":"続ける","next":"text_voice2"}]},"text_voice2":{"text":"『……地上の穢れ、規定量に達す。闘争の気、収穫を完了。これより第3フェーズ——地上の大浄化へ移行する』","type":"text","bg_key":"bg_boss_altar","next":"text_realization","choices":[{"label":"続ける","next":"text_realization"}]},"text_realization":{"text":"背筋が凍った。理解した。全てが繋がった。","type":"text","bg_key":"bg_boss_altar","next":"text_realization2","choices":[{"label":"続ける","next":"text_realization2"}]},"text_realization2":{"text":"ローランドの大義も、マルカンドの防衛も、夜刀の一揆も——全ては天上の「神々」によって仕組まれた「間引き」の遊戯に過ぎなかった。","type":"text","bg_key":"bg_boss_altar","next":"text_realization3","choices":[{"label":"続ける","next":"text_realization3"}]},"text_realization3":{"text":"ガウェインが命を賭けて守ろうとした「大義」は——脚本だった。","type":"text","bg_key":"bg_boss_altar","next":"text_rage","choices":[{"label":"続ける","next":"text_rage"}]},"text_rage":{"text":"剣を抜いた。手が震えている。","type":"text","bg_key":"bg_boss_altar","next":"text_rage2","choices":[{"label":"続ける","next":"text_rage2"}]},"text_rage2":{"text":"ふざけるな——自分たちが流した血は、あの老騎士が命を懸けた戦いは、盤上の駒の戯れだったというのか。声にならない叫びが喉を焼いた。","type":"text","bg_key":"bg_boss_altar","next":"text_rage3","choices":[{"label":"続ける","next":"text_rage3"}]},"text_rage3":{"text":"祭壇に向かって剣を突きつけた。","type":"text","bg_key":"bg_boss_altar","next":"text_dragon_summon","choices":[{"label":"続ける","next":"text_dragon_summon"}]},"text_dragon_summon":{"text":"祭壇が反応した。『不浄なる因子の接近を感知。神の理に刃向かう愚者よ。——神代の守護竜、顕現せよ』","type":"text","bg_key":"bg_boss_altar","next":"text_dragon_summon2","choices":[{"label":"続ける","next":"text_dragon_summon2"}]},"text_dragon_summon2":{"text":"空間が裂け、そこから現れたのは圧倒的な質量を持った純白の巨竜だった。","type":"text","bg_key":"bg_boss_altar","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"神代の守護竜との戦闘！ 神の理に叛逆する！","type":"battle","bg_key":"bg_boss_altar","bgm":"bgm_battle_boss","enemy_group_id":"209","choices":[{"label":"神の理に叛逆する","next":"text_aftermath"}],"battle_success_next":"text_aftermath"},"text_aftermath":{"text":"幾度も死の淵を彷徨いながら、剣がついに守護竜の逆鱗を貫いた。","type":"text","bg_key":"bg_boss_altar","next":"text_aftermath2","choices":[{"label":"続ける","next":"text_aftermath2"}]},"text_aftermath2":{"text":"巨竜が光の粒子となって崩壊していく。荒い息を吐いた。立っているのがやっとだった。","type":"text","bg_key":"bg_boss_altar","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"守護竜は消えた。だが祭壇の水晶はまだ光っている。「天上の神々」の傲慢な瞳が、未だ世界中を見下ろしている。","type":"text","bg_key":"bg_boss_altar","next":"end_node2","choices":[{"label":"続ける","next":"end_node2"}]},"end_node2":{"text":"神々の遊戯は終わっていない。答えを求めて西へ。華龍神朝の地を目指す。あの国には「天に届く塔」の伝説がある。（第2部完）","type":"end","result":"success","bg_key":"bg_boss_altar","choices":[]}}}'::jsonb, rewards = '{"gold":600,"exp":300,"reputation":20}'::jsonb WHERE id = 6010;

-- 6011_main_ep11.csv (24 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"夜刀の古代神殿で知った世界の真実。天上の神々による「大粛清」——人間同士の戦争は全て仕組まれた間引きであり、規定量に達すれば次の段階として地上そのものが焼かれる。それを阻止するために、東方の超大国「華龍神朝」へと足を踏み入れた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text_karyu","choices":[{"label":"続ける","next":"text_karyu"}]},"text_karyu":{"text":"華龍の大地は広かった。豊かな穀倉地帯。雄大な河。独自の文化と活気に満ちた市場。子供たちが凧を揚げ、老人が碁を打っている。ローランドやマルカンドとは違う——ここには、まだ平和が残っていた。","type":"text","bg_key":"bg_road_day","next":"text_sky","choices":[{"label":"続ける","next":"text_sky"}]},"text_sky":{"text":"辺境の村に身を休めた翌朝。空が——おかしい。太陽が三つある。いや、違う。太陽のように見える巨大な光球が、雲の上に浮かんでいる。空全体が異様な黄金色に染まり始めた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_crisis","next":"text_villagers","choices":[{"label":"続ける","next":"text_villagers"}]},"text_villagers":{"text":"村人たちが外に出てきた。空を指差している。「なんだあの空は……太陽が……三つ？」老婆が膝をついた。子供が母親にしがみついている。犬が吠えている。鳥が一羽もいない。——逃げたのだ。","type":"text","bg_key":"bg_road_day","next":"text_voice","choices":[{"label":"続ける","next":"text_voice"}]},"text_voice":{"text":"空を覆う黄金の雲の中から——声が響いた。人間の声ではない。感情がない。温度がない。頭の中に直接、刻み込まれるような声。『地上の穢れを焼却せよ。　これより——神罰の執行を開始する』","type":"text","bg_key":"bg_ruins_field","next":"text_angels","choices":[{"label":"続ける","next":"text_angels"}]},"text_angels":{"text":"声と共に、雲を割って無数の光の輪が降り注いだ。輪の中から——現れた。白磁の装甲。純白の翼。人間の形をしているが、人間ではない。「上位使徒」——天使の群れだ。彼らは言葉を発しない。表情がない。意志がない。ただ——命令を実行する機械のように、手にした光の槍を構えた。","type":"text","bg_key":"bg_ruins_field","next":"text_slaughter","choices":[{"label":"続ける","next":"text_slaughter"}]},"text_slaughter":{"text":"最初の槍が投げられた。村の家屋が一撃で消し飛んだ。逃げ惑う村人の背中に、二本目の槍が突き刺さった。煙と悲鳴が交差する。人間と神兵とでは——文字通り、次元が違った。","type":"text","bg_key":"bg_ruins_field","next":"text_stand","choices":[{"label":"続ける","next":"text_stand"}]},"text_stand":{"text":"足が震えている。勝てるわけがない。見ればわかる。あの一体一体が、ローランドの精鋭部隊を単独で壊滅させるだけの力を持っている。だが——目の前で人が死んでいる。震える足を叩いた。剣を抜いた。「こんな一方的な虐殺が——許されてたまるか！」","type":"text","bg_key":"bg_ruins_field","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"上位使徒との戦闘！人間の力で、神の兵器に立ち向かえ！","type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"210","choices":[{"label":"続ける","next":"text_aftermath"}],"battle_success_next":"text_aftermath"},"text_aftermath":{"text":"使徒の一体を退けた。だが——剣が酷く刃こぼれしている。腕が痺れて、感覚がない。空を見上げた。倒した数の十倍以上の使徒が、新たに降下してきている。光の輪が、空を埋め尽くしていた。","type":"text","bg_key":"bg_ruins_field","next":"text_second_wave","choices":[{"label":"続ける","next":"text_second_wave"}]},"text_second_wave":{"text":"逃げる暇もなく、第二波が押し寄せた。一体目よりも動きが速い。連携している。包囲されかけたその時——隣で戦っていた村の自警団の男が叫んだ。「東に抜けろ！ あっちにまだ道がある！」男は使徒に飛びかかった。その背中を見届ける余裕はなかった。","type":"text","bg_key":"bg_ruins_field","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"第二波の使徒が迫る！ 退路を確保しろ！","type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"210","choices":[{"label":"続ける","next":"text_retreat"}],"battle_success_next":"text_retreat"},"text_retreat":{"text":"死に物狂いで使徒を退け、燃え盛る村を背に走った。振り返った。村が——燃えていた。昨日、粥を分けてくれた場所が。一人では無理だ。だが——どうすればいい。","type":"text","bg_key":"bg_ruins_field","next":"text_volg_appear","choices":[{"label":"続ける","next":"text_volg_appear"}]},"text_volg_appear":{"text":"街道沿いの焚き火の前に——一人の男が座っていた。無精髭。酒瓶を傾けている。だが——近づいた瞬間、空気が変わった。背に負った大剣は刀身だけで人の背丈ほどある。周囲に転がる使徒の残骸。五体。いや、七体。——この男が、一人で。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_tense","next":"text_volg_look","choices":[{"label":"続ける","next":"text_volg_look"}]},"text_volg_look":{"text":"男がこちらを見た。瞳の奥に異常なほど獰猛な光が宿っている。「……よくここまで生き延びたな、若僧。　だがお前の眼はもう限界だと叫んでいるぜ。　壁にぶつかった奴の目だ」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_challenge","choices":[{"label":"続ける","next":"text_volg_challenge"}]},"text_volg_challenge":{"text":"「神だか何だか知らねェが、　相手が強すぎるって顔だ。　だがな、壁を越えられねぇ奴はここで死ぬ。　生き恥を晒して老いさらばえるか、　世界を変える特異点になるか——　俺に証明してみせろ！」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_draw","choices":[{"label":"続ける","next":"text_volg_draw"}]},"text_volg_draw":{"text":"ヴォルグが大剣を抜いた瞬間、周囲の空気が重く沈み込んだ。焚き火が消えた。先ほど黄河で対峙した使徒すら凌駕するほどの濃密な殺気が全身を包み込む。「不死の傭兵王」ヴォルグ。数え切れないほどの戦場を渡り歩き、死線を超え続けてきた生きた伝説——その大剣が、こちらに向けられた。","type":"text","bg_key":"bg_bandit_camp","next":"battle3","choices":[{"label":"続ける","next":"battle3"}]},"battle3":{"text":"不死の傭兵王ヴォルグとの戦闘！お前の覚悟を、全力で示せ！","type":"battle","bg_key":"bg_bandit_camp","bgm":"bgm_battle_strong","enemy_group_id":"213","choices":[{"label":"続ける","next":"text_close_call"}],"battle_success_next":"text_close_call"},"text_close_call":{"text":"火花の散る激しい打ち合い。体力はとっくに尽きていた。だが死地で研ぎ澄まされた戦意が、仲間と共に最後の攻勢を押し通した。渾身の一撃をヴォルグの胸元に叩き込み、大剣の切っ先が地面に突き刺さった。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_calm","next":"text_volg_approve","choices":[{"label":"続ける","next":"text_volg_approve"}]},"text_volg_approve":{"text":"「……フン、悪くない。　ギリギリで命を拾ったな」ヴォルグは満足げに笑い、大剣を下ろした。「面白ェ奴だ。しばらく付き合ってやるよ。　——ただし、立ち止まったら俺が斬る。覚えておけ」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_decision","choices":[{"label":"続ける","next":"text_volg_decision"}]},"text_volg_decision":{"text":"「俺はさっき、あの白い化け物を七体ほど叩き斬った。　一体一体は大したことねえ。だが数が多すぎる。　次から次へと空から降ってきやがる」ヴォルグが焚き火の残り火を踏み消した。「ここで潰しても意味がねぇ。　奴らが降りてくる元——都を狙っている。　マルカンドの首都、イスハークに向かうぞ」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_departure","choices":[{"label":"続ける","next":"text_departure"}]},"text_departure":{"text":"ヴォルグの背中を追って、西へ向かった。振り返ると、まだ空が黄金色に染まっている。光の輪が断続的に降り注いでいた。村を——救えなかった。だが、立ち止まっている暇はない。次の戦場が待っている。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"一人では超えられなかった壁。だが今——隣に、生ける伝説がいる。天使が世界中の都市を焼こうとしている。華龍の辺境は序章に過ぎない。マルカンドの首都イスハークに、急がなければ。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"力尽きて、地面に倒れた。視界の端で、光の槍が村を貫いている。「……ここで……終わるのか……」何も——守れなかった。","type":"end","result":"failure","bg_key":"bg_ruins_field","choices":[]}}}'::jsonb, rewards = '{"gold":1200,"exp":300,"reputation":15}'::jsonb WHERE id = 6011;

-- 6012_main_ep12.csv (22 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"ヴォルグと共に、西へ急いだ。道中、東から西へ逃げる避難民の列とすれ違った。焼け焦げた衣服。泣き叫ぶ子供。目に光のない老人たちが、力なく足を引きずっている。「イスハークが……イスハークが燃えている……」呟く女の言葉が、嫌な予感を裏付けた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_crisis","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"text":"ヴォルグがパーティに加わった。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"text_arrival","choices":[{"label":"続ける","next":"text_arrival"}]},"text_arrival":{"text":"黄金都市イスハーク。マルカンドの首都であり、砂漠の中の楽園と謳われた都。だが——目の前に広がる光景は、楽園の面影を留めていなかった。黄金のドームが半壊している。市場の屋台が炭になっている。噴水の水が蒸発し、乾いた噴水台だけが残されていた。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_flames","choices":[{"label":"続ける","next":"text_flames"}]},"text_flames":{"text":"空から降り注ぐ炎の柱が、街区を一つずつ焼いている。通常の火災ではない。炎が意思を持っているかのように、建物を舐め尽くしていく。水をかけても消えない。燃え尽きるまで止まらない。これが——天使の力。人間の消火など、意味を為さない。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_refugees","choices":[{"label":"続ける","next":"text_refugees"}]},"text_refugees":{"text":"瓦礫の影に、逃げ遅れた住民がいた。母親が二人の子供を庇っている。商人が焼けた店の前で立ち尽くしている。兵士が一人、折れた槍を杖代わりに呻いていた。「逃げろ！ 北門はまだ開いている！」叫んだ。だが——北門の方角にも、炎の柱が落ちた。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_volg_fury","choices":[{"label":"続ける","next":"text_volg_fury"}]},"text_volg_fury":{"text":"ヴォルグが大剣を抜いた。「チッ——間に合わなかったか。　だが、まだ全部は焼けちゃいねェ」炎の柱の根元——空中に浮かぶ光の存在を睨んだ。「あの野郎が元凶だ。　あいつを叩けば、この炎も止まる。行くぞ！」","type":"text","bg_key":"bg_ishaq_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_plaza","choices":[{"label":"続ける","next":"text_plaza"}]},"text_plaza":{"text":"中央広場に向かって走った。かつて賑わった大市場は瓦礫の山と化していた。砕けた陶器。焦げた絨毯。散乱する香辛料の袋。砂漠の都の富と文化が、灰に変わっていく。広場の中央に——白い使徒の一団が展開していた。住民が逃げる道を塞いでいる。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_apostle_block","choices":[{"label":"続ける","next":"text_apostle_block"}]},"text_apostle_block":{"text":"使徒が光の槍を構えた。無表情。無感情。逃げ惑う人間たちを、害虫の如く処理しようとしている。住民たちの退路を確保するには、まずこの使徒の壁を突破するしかない。","type":"text","bg_key":"bg_ishaq_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"使徒の前衛が行く手を阻む！住民の退路を確保するため、突破せよ！","type":"battle","bg_key":"bg_ishaq_ruined","bgm":"bgm_battle","enemy_group_id":"211","choices":[{"label":"続ける","next":"text_path_clear"}],"battle_success_next":"text_path_clear"},"text_path_clear":{"text":"使徒の一団を退けた。住民たちが瓦礫の隙間を縫って北へ逃げていく。母親が子供の手を引いて走る姿が見えた。だが——空が、一際強く輝いた。広場の上空に、巨大な光の存在が降りてくる。六枚の翼。全身が炎で構成された人型の存在。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_uriel_descent","choices":[{"label":"続ける","next":"text_uriel_descent"}]},"text_uriel_descent":{"text":"熱波が押し寄せた。肌が焼けるような熱さに、思わず腕で顔を覆った。使徒たちとは次元が違う。存在そのものが——炎だ。大天使ウリエル。炎を司る審判者が、イスハークの上空に君臨していた。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_uriel_voice","choices":[{"label":"続ける","next":"text_uriel_voice"}]},"text_uriel_voice":{"text":"ウリエルが口を開いた。炎が言葉の形を取るような、灼熱の声。『穢レタ砂ノ都ヨ。　汝ラノ贅沢ト強欲ガ、天ヲ汚シタ。　炎ニヨリ清メラレヨ——コレハ慈悲デアル』慈悲——この惨状が、慈悲だと。","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"大天使ウリエル","speaker":"大天使ウリエル","next":"text_uriel_judgment","choices":[{"label":"続ける","next":"text_uriel_judgment"}]},"text_uriel_judgment":{"text":"ウリエルの手に、巨大な炎の剣が現れた。振り下ろされれば、広場ごと消し飛ぶ。まだ逃げきれていない住民がいる。ここで止めなければ——全員が灰になる。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_volg_charge","choices":[{"label":"続ける","next":"text_volg_charge"}]},"text_volg_charge":{"text":"ヴォルグが大剣を肩に担いで、にやりと笑った。「慈悲だぁ？ 笑わせるな。　テメェの慈悲とやらが、何人の命を灰にした？　——おい若僧、ビビってる暇はねェぞ。　あのデカブツ、一緒にぶっ倒すぞ！」","type":"text","bg_key":"bg_ishaq_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"大天使ウリエルとの戦闘！炎の審判者を撃退し、イスハークを救え！","type":"battle","bg_key":"bg_ishaq_ruined","bgm":"bgm_battle_strong","enemy_group_id":"9040","choices":[{"label":"続ける","next":"text_uriel_retreat"}],"battle_success_next":"text_uriel_retreat"},"text_uriel_retreat":{"text":"渾身の一撃がウリエルの翼を捉えた。炎の翼が砕け、光の粒となって散った。ウリエルの巨体が揺らぐ。『……人間ノ抵抗ハ、予定ニナカッタ。　ダガ——コレハ始マリニ過ギナイ。　他ノ同胞ガ、他ノ都ヲ裁イテイル』光に包まれ、ウリエルが天へ退いていった。空を覆っていた炎の柱が、一つずつ消えていく。","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"大天使ウリエル","speaker":"大天使ウリエル","next":"text_aftermath","choices":[{"label":"続ける","next":"text_aftermath"}]},"text_aftermath":{"text":"ウリエルが去り、炎が止んだ。だが——都市の半分は既に焼け落ちていた。黄金のドームは黒く煤け、市場は瓦礫の山だ。生き残った住民たちが、茫然と焼け跡を見つめている。泣く気力すら残っていない者もいた。","type":"text","bg_key":"bg_ishaq_ruined","next":"text_survivors","choices":[{"label":"続ける","next":"text_survivors"}]},"text_survivors":{"text":"「奴が言っていた。　『他の同胞が、他の都を裁いている』——　つまり、ここだけじゃねえってことだ」ヴォルグが東を指差した。「次は華龍の首都、龍京だ。　あそこが落ちたら、東方全域が終わる。　急ぐぞ——のんびりしてる暇はねェ」","type":"text","bg_key":"bg_ishaq_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"text":"ヴォルグが離脱した。「先に行って偵察してくる。龍京で合流だ」大剣を背負い直し、東へ走り去っていった。その足は、使徒を七体斬り伏せた男のものとは思えないほど速い。","type":"leave","bg_key":"bg_ishaq_ruined","next":"text_next_destination","choices":[{"label":"続ける","next":"text_next_destination"}]},"text_next_destination":{"text":"イスハークの住民に水と食料を分け、東へ向かった。焼けた都市を背に、砂漠の道を急ぐ。空の色は普通に戻っていたが、東の地平線に——また、黄金の光が見えた。龍京が、次の標的にされている。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"大天使ウリエルを退けたが、勝利とは言い難い。イスハークは半壊し、多くの命が失われた。だが——残った命がある。守れた命がある。次は龍京。あの街を、同じ目には遭わせない。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"炎の中に倒れた。ウリエルの灼熱が、意識を焼き尽くしていく。イスハークの炎が——止まらない。","type":"end","result":"failure","bg_key":"bg_ishaq_ruined","choices":[]}}}'::jsonb, rewards = '{"gold":1500,"exp":350,"reputation":15}'::jsonb WHERE id = 6012;

-- 6013_main_ep13.csv (22 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"イスハークの炎を消し、東へ急いだ。大天使は一人ではない。ウリエルが退き際に残した言葉が耳に残っている。『他ノ同胞ガ、他ノ都ヲ裁イテイル』次の標的は——華龍の首都、龍京。ヴォルグとの合流地点へ向かった。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"text":"ヴォルグがパーティに加わった。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"text_arrival","choices":[{"label":"続ける","next":"text_arrival"}]},"text_arrival":{"text":"龍京の城門が見えた。だが——おかしい。門番がいない。見張り台に人影がない。旗が、風に揺れているだけだ。城門は開いたまま。まるで——この都市が、死んだかのように。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_silence","choices":[{"label":"続ける","next":"text_silence"}]},"text_silence":{"text":"城門をくぐった。市場に人がいない。茶館の椅子が倒れている。鍋の火が消えかけたまま放置されている。——いや、人はいた。道端に、座り込んだまま動かない人々がいる。目を閉じている。呼吸はある。だが——呼びかけても、揺すっても、目を覚まさない。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_sleeping_city","choices":[{"label":"続ける","next":"text_sleeping_city"}]},"text_sleeping_city":{"text":"通りを進むほど、倒れている人が増えていった。兵士が槍を握ったまま眠っている。子供が母親にしがみついたまま、二人とも動かない。犬までもが、目を閉じて横たわっていた。都市全体が——眠りに落ちている。異常な静寂が、耳鳴りのように響いた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_volg_unease","choices":[{"label":"続ける","next":"text_volg_unease"}]},"text_volg_unease":{"text":"「……気に入らねぇな。　炎で焼くのとは違う。もっと陰湿だ」ヴォルグが眠る兵士の脈を取った。「生きちゃいる。だが起きねぇ。　まるで魂だけ抜かれたみてぇだ。　これがあの天使の仕業か——？」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_soldiers","choices":[{"label":"続ける","next":"text_soldiers"}]},"text_soldiers":{"text":"宮城の前に、かろうじて意識を保っている兵士がいた。壁に寄りかかり、朦朧とした目でこちらを見る。「天極城に……光の存在が……　あれが来てから……みんな……眠って……」声が途切れた。兵士の目が閉じていく。——宮城の中に、元凶がいる。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_raphael_presence","choices":[{"label":"続ける","next":"text_raphael_presence"}]},"text_raphael_presence":{"text":"天極城に近づくほど、空気が重くなった。甘い香りが漂っている。花のような、果実のような。だが——その甘さの中に、意識を蝕む何かが混じっている。瞼が重い。足が鈍る。思考が霞がかかったように曖昧になっていく。頬を叩いた。歯を食いしばった。眠るわけにはいかない。","type":"text","bg_key":"bg_ryukyo_ruined","bgm":"bgm_quest_crisis","next":"text_apostle_guard","choices":[{"label":"続ける","next":"text_apostle_guard"}]},"text_apostle_guard":{"text":"宮城の門前に、使徒の一団が並んでいた。他の使徒と違い、武器を構えていない。両手を広げて——祈っている。その周囲に、淡い光の膜が漂っていた。あの光に触れた者が、眠りに落ちているのだ。祈る使徒たちを突破しなければ、宮城には入れない。","type":"text","bg_key":"bg_ryukyo_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"眠りの使徒が行く手を阻む！意識を保ったまま、突破せよ！","type":"battle","bg_key":"bg_ryukyo_ruined","bgm":"bgm_battle","enemy_group_id":"211","choices":[{"label":"続ける","next":"text_throne_approach"}],"battle_success_next":"text_throne_approach"},"text_throne_approach":{"text":"使徒を退け、宮城の大広間に踏み込んだ。玉座の前に——光の存在が浮かんでいた。六枚の翼。だがウリエルの炎とは違う。柔らかな光。温かな光。見つめていると——安らかな気持ちになってくる。その安らぎが、罠なのだと頭ではわかっていた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_raphael_appear","choices":[{"label":"続ける","next":"text_raphael_appear"}]},"text_raphael_appear":{"text":"大天使ラファエル。「癒し」を司る天使。その名の通り、ラファエルの力は傷を癒し、苦痛を取り除く。だが——癒しの果てにあるのは、永遠の眠り。痛みも恐怖もない代わりに、目覚めることも、生きることもない世界。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_raphael_voice","choices":[{"label":"続ける","next":"text_raphael_voice"}]},"text_raphael_voice":{"text":"ラファエルが微笑んだ。温かく、穏やかな声が広間に響く。『苦シミハ、モウ終ワリニシヨウ。　戦イモ、飢エモ、病モ——全テ、眠リノ中デ癒サレル。　コレガ、私ニデキル最大ノ慈悲デス』微笑みの奥に——感情がない。機械的な慈悲。プログラムされた優しさ。","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"大天使ラファエル","speaker":"大天使ラファエル","next":"text_raphael_mercy","choices":[{"label":"続ける","next":"text_raphael_mercy"}]},"text_raphael_mercy":{"text":"ラファエルの手が光り始めた。『サア、貴方モ——安ラカニ眠リナサイ』意識が揺らぐ。膝が折れかける。甘い眠気が全身を包み込んでくる。このまま眠ったら、二度と目覚めない——そう直感が叫んでいた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"text_volg_rage","choices":[{"label":"続ける","next":"text_volg_rage"}]},"text_volg_rage":{"text":"ヴォルグが自分の腕に大剣の刃を押し当てた。血が流れる。痛みで意識を繋ぎ止める。「ふざけんな……！　こんなもんが慈悲だと？　人間は苦しんで、傷ついて、　それでも立ち上がるから生きてるんだ！　——テメェの偽物の安らぎなんざ、いらねェ！」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"大天使ラファエルとの戦闘！偽りの癒しを打ち破り、龍京を目覚めさせろ！","type":"battle","bg_key":"bg_ryukyo_ruined","bgm":"bgm_battle_strong","enemy_group_id":"9041","choices":[{"label":"続ける","next":"text_raphael_retreat"}],"battle_success_next":"text_raphael_retreat"},"text_raphael_retreat":{"text":"ラファエルの翼が砕けた。光の粒が、花弁のように舞い散る。『……理解デキマセン。　ナゼ、苦シミヲ選ブノデスカ。　安ラカナ眠リヲ、拒ムノデスカ……』困惑した表情のまま、ラファエルは天へ退いていった。","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"大天使ラファエル","speaker":"大天使ラファエル","next":"text_awakening","choices":[{"label":"続ける","next":"text_awakening"}]},"text_awakening":{"text":"ラファエルが去った瞬間——あちこちから声が聞こえ始めた。「……ここは……？ 何が……？」眠りに落ちていた人々が、一人、また一人と目を覚ましていく。兵士が槍を握り直した。子供が泣き始めた。龍京が——息を吹き返した。","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"text":"ヴォルグが離脱した。「次は夜刀の首都、出雲だ。先に偵察に行く」腕の傷を雑に布で巻きながら、南東へ駆けていった。","type":"leave","bg_key":"bg_ryukyo_ruined","next":"text_next_destination","choices":[{"label":"続ける","next":"text_next_destination"}]},"text_next_destination":{"text":"龍京の人々が目覚め、街に活気が戻り始めた。だが被害は大きい。多くの建物が崩れ、物資が尽きている。残された時間は少ない。大天使はまだ二体——あるいはそれ以上いる。次は出雲。夜刀の都を守らなければ。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"ラファエルの「慈悲」は、人間から生きる意志を奪うものだった。苦しみも、痛みも、全てが生きている証だ。ヴォルグの言葉が、改めて胸に刻まれた。出雲へ急ぐ。次の大天使が、あの街を狙っている。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"意識が溶けていく。甘い眠気に抗えなかった。ラファエルの光に包まれ、深い眠りに落ちていく。苦しみはない。だが——もう、目覚めることはない。","type":"end","result":"failure","bg_key":"bg_ryukyo_ruined","choices":[]}}}'::jsonb, rewards = '{"gold":1800,"exp":350,"reputation":20}'::jsonb WHERE id = 6013;

-- 6014_main_ep14.csv (22 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"龍京を発ち、南東へ向かった。夜刀神国の首都、出雲。古き神々の信仰が息づく聖地であり、この地域の守りの要でもある。ヴォルグとの合流地点に近づくにつれ、街道を逆走してくる人々とすれ違い始めた。全員が——怯えた目をしていた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"text":"ヴォルグがパーティに加わった。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"text_arrival","choices":[{"label":"続ける","next":"text_arrival"}]},"text_arrival":{"text":"出雲の大鳥居が見えた。炎はない。静寂でもない。だが——街の中から、怒声と悲鳴が聞こえる。鳥居の柱に刀傷がついている。石畳に血痕が点々と続いていた。何かが——おかしい。","type":"text","bg_key":"bg_izumo_ruined","next":"text_chaos","choices":[{"label":"続ける","next":"text_chaos"}]},"text_chaos":{"text":"通りに踏み入れた瞬間、目を疑った。住民同士が——戦っている。刀を振り回す侍。棍棒を持った商人。隣家の男を石で殴りつける女。全員の目が血走っている。誰もが——何かに怯え、何かを恐れている。","type":"text","bg_key":"bg_izumo_ruined","next":"text_infighting","choices":[{"label":"続ける","next":"text_infighting"}]},"text_infighting":{"text":"「お前が……お前が裏切者だ！　天の声がそう言った！」侍が商人に斬りかかった。商人が反撃する。傍らの老人が巻き添えになった。彼らは正気を失っているのではない。何かに——「教えられた」のだ。隣にいる者こそが敵であると。","type":"text","bg_key":"bg_izumo_ruined","next":"text_volg_analysis","choices":[{"label":"続ける","next":"text_volg_analysis"}]},"text_volg_analysis":{"text":"「これは……洗脳か。　いや、違う。もっと巧妙だ」ヴォルグが眉をひそめた。「一人一人に別々の『啓示』を吹き込んでいやがる。　お前の隣の奴は敵だ、先に殺せ——ってな。　全員が被害者で、全員が加害者だ。　やり口が汚ェ……」","type":"text","bg_key":"bg_izumo_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_shrine","choices":[{"label":"続ける","next":"text_shrine"}]},"text_shrine":{"text":"街の中心にある大社に向かった。参道の石灯籠が倒されている。注連縄が引きちぎられ、地面に落ちていた。大社の境内から——低い音が響いている。人間の声ではない。振動のような、脈動のような音。あの音が——「啓示」の発信源だ。","type":"text","bg_key":"bg_izumo_ruined","next":"text_whisper","choices":[{"label":"続ける","next":"text_whisper"}]},"text_whisper":{"text":"大社に近づくにつれ、頭の中に声が入り込んでくる。『……振り返れ。背後の男は、お前を殺そうとしている』ヴォルグを見た。ヴォルグもこちらを見ていた。互いに——一瞬だけ、手が武器に伸びかけた。「……冗談じゃねぇ。こんなもんに踊らされてたまるか」ヴォルグが首を振り、前に進んだ。","type":"text","bg_key":"bg_izumo_ruined","next":"text_apostle_chorus","choices":[{"label":"続ける","next":"text_apostle_chorus"}]},"text_apostle_chorus":{"text":"大社の前に、使徒の一団が円陣を組んでいた。彼らは——歌っている。人間には聞き取れない高周波の合唱。だがその振動が頭蓋骨に響き、内側から思考を掻き乱してくる。この合唱隊を黙らせなければ、ガブリエルには辿り着けない。","type":"text","bg_key":"bg_izumo_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"啓示の使徒が精神を侵食してくる！合唱を止めて、大社への道を開け！","type":"battle","bg_key":"bg_izumo_ruined","bgm":"bgm_battle","enemy_group_id":"211","choices":[{"label":"続ける","next":"text_inner_shrine"}],"battle_success_next":"text_inner_shrine"},"text_inner_shrine":{"text":"使徒を退け、大社の奥へ踏み込んだ。御神体の前に——光の存在が浮かんでいた。六枚の翼。だが炎でも光でもない。翼の一枚一枚に、文字のような紋様が刻まれている。あの紋様が——「啓示」の正体だ。","type":"text","bg_key":"bg_izumo_ruined","next":"text_gabriel_appear","choices":[{"label":"続ける","next":"text_gabriel_appear"}]},"text_gabriel_appear":{"text":"大天使ガブリエル。「啓示」を司る天使——神の言葉を地上に伝える使者。だがその「言葉」は、人間の心を操り、互いに殺し合わせるための毒だった。","type":"text","bg_key":"bg_izumo_ruined","next":"text_gabriel_voice","choices":[{"label":"続ける","next":"text_gabriel_voice"}]},"text_gabriel_voice":{"text":"ガブリエルが口を開いた。澄んだ声。だが、その澄みが逆に不気味だった。『私ハ何モシテイマセン。　真実ヲ伝エタダケデス。　人間ハ元来、互イヲ信用シテイナイ。　少シ背中ヲ押シテアゲレバ——　自ラ殺シ合イヲ始メル。ソレガ、人間デス』","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"大天使ガブリエル","speaker":"大天使ガブリエル","next":"text_gabriel_test","choices":[{"label":"続ける","next":"text_gabriel_test"}]},"text_gabriel_test":{"text":"頭の中に声が響く。『本当ニ信ジラレマスカ？　隣ノ男ハ、何ノタメニ貴方ト共ニイルノデスカ？　利用スルタメデハ？』声を振り払おうとするが、疑念が胸の奥に根を張る。ガブリエルの力——最も厄介な相手だ。","type":"text","bg_key":"bg_izumo_ruined","next":"text_volg_defiance","choices":[{"label":"続ける","next":"text_volg_defiance"}]},"text_volg_defiance":{"text":"ヴォルグが大剣を地面に突き立てた。「うるせぇな。　俺がこいつと一緒にいる理由だと？　面白ェからだよ。それ以外に理由がいるか？　テメェの小賢しい囁きで　人の縁を壊せると思うなよ——　この偽善者が！」","type":"text","bg_key":"bg_izumo_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"大天使ガブリエルとの戦闘！偽りの啓示を打ち砕き、出雲の人々を解放せよ！","type":"battle","bg_key":"bg_izumo_ruined","bgm":"bgm_battle_strong","enemy_group_id":"9042","choices":[{"label":"続ける","next":"text_gabriel_retreat"}],"battle_success_next":"text_gabriel_retreat"},"text_gabriel_retreat":{"text":"ガブリエルの翼が砕けた。刻まれていた紋様が消え、空気が澄んでいく。『……興味深イ。　疑念ヲ超エル絆ガ、人間ニモ存在スルノデスカ。　——覚エテオキマショウ』ガブリエルは困惑と好奇の入り混じった表情で、天へと退いていった。","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"大天使ガブリエル","speaker":"大天使ガブリエル","next":"text_sanity_returns","choices":[{"label":"続ける","next":"text_sanity_returns"}]},"text_sanity_returns":{"text":"ガブリエルが去った瞬間、街の喧騒が変わった。「……俺は……何を……」刀を握った侍が、自分の手を見て震えている。殴り合っていた隣人同士が、互いの傷を見つめ合い、呆然と立ち尽くしていた。正気に戻った人々の間に——深い後悔と沈黙が広がった。","type":"text","bg_key":"bg_izumo_ruined","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"text":"ヴォルグが離脱した。「残りは一体。ローランドの首都、レガリアだ。先に行く」大剣を背負い直し、西へ駆けていった。","type":"leave","bg_key":"bg_izumo_ruined","next":"text_next_destination","choices":[{"label":"続ける","next":"text_next_destination"}]},"text_next_destination":{"text":"出雲の人々は正気を取り戻した。だが、互いに傷つけ合った記憶は消えない。ガブリエルの「啓示」は、人間の心に最初からあった不信を増幅しただけだった。残る大天使は、あと一体。ローランドの首都レガリアへ急がなければ。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"三体の大天使を退けた。だが、それぞれの都市に残された傷は深い。炎、眠り、そして疑心暗鬼——大天使たちの「慈悲」は、形を変えた破壊だった。最後の一体が、レガリアで待っている。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"頭の中の声に抗えなかった。疑念が膨らみ、判断が鈍り——気づいた時には、地に伏していた。ガブリエルの囁きが、まだ耳の奥で響いている。","type":"end","result":"failure","bg_key":"bg_izumo_ruined","choices":[]}}}'::jsonb, rewards = '{"gold":2000,"exp":400,"reputation":20}'::jsonb WHERE id = 6014;

-- 6015_main_ep15.csv (21 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"三体の大天使を退けた。イスハーク、龍京、出雲——それぞれに傷を負ったが、都市は生き残った。残る一体は——天軍の長、大天使ミカエル。四体の中で最も強大な存在。その矛先は、ローランドの首都レガリアに向けられていた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_crisis","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"text":"ヴォルグがパーティに加わった。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"text_arrival","choices":[{"label":"続ける","next":"text_arrival"}]},"text_arrival":{"text":"王都レガリア。ローランド聖王国の心臓部。白亜の城壁が——半分崩れていた。城門は瓦礫で埋まり、城壁の上に並んでいたはずの衛兵の姿がない。代わりに——空に、巨大な光の十字架が浮かんでいた。その光が、街に影を落としている。","type":"text","bg_key":"bg_regalia_ruined","next":"text_devastation","choices":[{"label":"続ける","next":"text_devastation"}]},"text_devastation":{"text":"レガリアの被害は、他の三都市とは比べものにならなかった。ウリエルの炎のように局所的ではない。ラファエルの眠りのように穏やかでもない。ガブリエルの混乱のように間接的でもない。ミカエルは——純粋な武力で、都市を叩き潰していた。建物が斬り裂かれている。城壁が砕かれている。剣の一振りで街区が消し飛んだような痕跡が、あちこちに残されていた。","type":"text","bg_key":"bg_regalia_ruined","next":"text_soldiers_last","choices":[{"label":"続ける","next":"text_soldiers_last"}]},"text_soldiers_last":{"text":"瓦礫の影に、ローランド軍の残存部隊がいた。鎧が砕け、盾が割れ、槍が折れている。だが——まだ立っている者がいた。「……応援か？ 傭兵の……」隊長らしき男が、かすれた声で言った。「大聖堂の方角だ。あの化け物は……大聖堂にいる。　我々はもう……動けない。頼む……」","type":"text","bg_key":"bg_regalia_ruined","next":"text_volg_resolve","choices":[{"label":"続ける","next":"text_volg_resolve"}]},"text_volg_resolve":{"text":"ヴォルグが兵士たちを見渡した。「……最後の一体か。　今までの奴らとは格が違う。　それはわかっている」大剣を肩に担ぎ直した。「だがな——俺たちは三体倒してきた。　四体目が最強だろうが関係ねぇ。　やることは同じだ。ぶっ倒す」","type":"text","bg_key":"bg_regalia_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_cathedral","choices":[{"label":"続ける","next":"text_cathedral"}]},"text_cathedral":{"text":"大聖堂に向かって走った。かつて荘厳だった聖堂の尖塔が、斜めに傾いている。ステンドグラスは粉々に砕け、聖者の彫像が首から上を失っていた。聖堂の前の広場に——光の柱が立っている。その光の中に、影が見えた。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_throne","choices":[{"label":"続ける","next":"text_michael_throne"}]},"text_michael_throne":{"text":"広場の中央に、砕けた聖堂の瓦礫で即席の「玉座」が作られていた。その上に——座っている。六枚の翼。全身が光の鎧に包まれた巨大な人型。右手に、光で構成された大剣を握っている。他の大天使とは——存在感が違う。見るだけで膝が折れそうになる、圧倒的な威圧。大天使ミカエル。天軍の長。","type":"text","bg_key":"bg_regalia_ruined","next":"text_apostle_elite","choices":[{"label":"続ける","next":"text_apostle_elite"}]},"text_apostle_elite":{"text":"ミカエルの周囲に、精鋭の使徒が展開していた。通常の使徒よりも一回り大きい。光の槍ではなく、光の剣を握っている。ミカエルに近づくには、まずこの親衛隊を突破しなければならない。","type":"text","bg_key":"bg_regalia_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"ミカエルの親衛隊が立ちはだかる！精鋭使徒を打ち破り、天軍の長への道を拓け！","type":"battle","bg_key":"bg_regalia_ruined","bgm":"bgm_battle","enemy_group_id":"211","choices":[{"label":"続ける","next":"text_michael_descend"}],"battle_success_next":"text_michael_descend"},"text_michael_descend":{"text":"親衛隊を退けた。——瓦礫の玉座から、ミカエルが立ち上がった。地面が震えた。空気が凍った。ミカエルの周囲だけ、空間が歪んでいるように見えた。光の大剣が持ち上げられた。刃の長さは——人の背丈の三倍はある。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_voice","choices":[{"label":"続ける","next":"text_michael_voice"}]},"text_michael_voice":{"text":"ミカエルが口を開いた。重く、低く、大地を揺るがすような声。『ウリエル、ラファエル、ガブリエル。　三体ノ同胞ヲ退ケタ人間カ。　——認メヨウ。貴様ラハ強イ。　ダガ、強イダケデハ神ニハ届カナイ』","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"大天使ミカエル","speaker":"大天使ミカエル","next":"text_michael_declaration","choices":[{"label":"続ける","next":"text_michael_declaration"}]},"text_michael_declaration":{"text":"『私ハ天軍ノ長。　剣ヲ以テ秩序ヲ守ル者。　貴様ラノ抵抗ハ、秩序ヘノ反逆デアル。　——故ニ、私ガ直々ニ裁ク』光の大剣が天に掲げられた。凄まじい光が広場を満たした。","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"大天使ミカエル","speaker":"大天使ミカエル","next":"text_volg_final","choices":[{"label":"続ける","next":"text_volg_final"}]},"text_volg_final":{"text":"ヴォルグが前に出た。「秩序だぁ？　テメェらの秩序は、人間を家畜にすることだろうが。　悪ィが俺たちは飼い慣らされるつもりはねェ。　——来い、デカブツ。最後の一発だ！」大剣を構えた。その背中に——覚悟が見えた。","type":"text","bg_key":"bg_regalia_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"大天使ミカエルとの決戦！天軍の長を退け、最後の都を守り抜け！","type":"battle","bg_key":"bg_regalia_ruined","bgm":"bgm_spot_final_boss","enemy_group_id":"9043","choices":[{"label":"続ける","next":"text_michael_retreat"}],"battle_success_next":"text_michael_retreat"},"text_michael_retreat":{"text":"光の大剣が——砕けた。ミカエルの巨体が、初めて膝をついた。翼の一枚が欠け、光が漏れ出している。『……マサカ。人間ガ、天軍ノ長ヲ……。　……覚エテオクガイイ。　私タチハ、命令ニ従ッタダケダ。　命令ヲ下シタ者ハ——マダ、天ノ上ニイル』光に包まれ、ミカエルが天へ退いていった。","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"大天使ミカエル","speaker":"大天使ミカエル","next":"text_city_saved","choices":[{"label":"続ける","next":"text_city_saved"}]},"text_city_saved":{"text":"ミカエルが去り、空に浮かんでいた光の十字架が消えた。レガリアの空に——本物の太陽が戻ってきた。瓦礫の中から、生き残った住民たちが顔を出し始めた。壊れた街。だが——生きている。四つの首都を守りきった。大天使の侵攻は——終わった。","type":"text","bg_key":"bg_regalia_ruined","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"text":"ヴォルグが離脱した。瓦礫に腰を下ろし、大剣を地面に突き立てた。珍しく——疲れた顔をしていた。","type":"leave","bg_key":"bg_regalia_ruined","next":"text_volg_farewell","choices":[{"label":"続ける","next":"text_volg_farewell"}]},"text_volg_farewell":{"text":"「四体倒したが……あの最後の野郎が言っていたな。　『命令を下した者は、まだ天の上にいる』と。　だが——今はいい。　ここまでやれりゃ上等だ」ヴォルグが立ち上がり、背伸びをした。「神の赦しを乞うよりは、　人間は人間らしく生き抜くべきだ。　——そうだろう、若僧？」にやりと笑い、瓦礫の中を歩き去っていった。","type":"text","bg_key":"bg_regalia_ruined","speaker_image_url":"/images/npcs/npc_guest_volg.png","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"四大天使の侵攻は退けた。イスハーク、龍京、出雲、レガリア——四つの首都は傷つきながらも、生き残った。神そのものには届いていない。だが——人間は、神の軍勢に勝った。それは、この世界の歴史上、初めてのことだった。瓦礫の街に、夕陽が差し込んでいる。壊れた街並みの中で、子供の泣き声が聞こえた。誰かが、その子を抱き上げる声が続いた。世界はまだ——生きている。それだけで、十分だった。","type":"end","result":"success","bg_key":"bg_regalia_ruined","choices":[]},"end_failure":{"text":"ミカエルの光の大剣が振り下ろされた。すべてが白い光に包まれ、意識が途切れた。レガリアの空に——光の十字架が、なお輝いている。","type":"end","result":"failure","bg_key":"bg_regalia_ruined","choices":[]}}}'::jsonb, rewards = '{"gold":2500,"exp":500,"reputation":30}'::jsonb WHERE id = 6015;

-- 6016_main_ep16.csv (19 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"かつて世界を揺るがした大天使の侵攻。それは遠い過去の出来事となっていた。四つの首都は完全に復興し、レガリアの城壁は以前よりも堅牢に、イスハークの黄金のドームは眩いばかりに輝いている。平和な時代。だが——胸の奥に、何かが引っかかっていた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text_peace","choices":[{"label":"続ける","next":"text_peace"}]},"text_peace":{"text":"英霊が退けた大天使たちの記憶は、語り継がれている。だが——神そのものには、誰も届いていない。いつまた、天から裁きが降ってくるかわからない。何かを——探さなければならない気がしていた。その「何か」が、まだわからなかった。","type":"text","bg_key":"bg_road_day","next":"text_border_town","choices":[{"label":"続ける","next":"text_border_town"}]},"text_border_town":{"text":"足は自然と、国境の町に向かっていた。ローランドとマルカンドの境にある小さな町。ここは交易路の中継地で、旅人や商人が行き交っている。町外れの丘に登った時——不思議な光が目に入った。草むらの中に、何かが埋もれている。","type":"text","bg_key":"bg_road_day","next":"text_strange_pull","choices":[{"label":"続ける","next":"text_strange_pull"}]},"text_strange_pull":{"text":"草を掻き分けると、苔むした石碑が現れた。風化した表面に、微かな紋様が刻まれている。どこかの古代文明のものか。だが——見覚えがある気がした。いや、見覚えではない。体が——この石碑を「知っている」と訴えている。","type":"text","bg_key":"bg_road_day","next":"text_stele_discovery","choices":[{"label":"続ける","next":"text_stele_discovery"}]},"text_stele_discovery":{"text":"石碑の前に立った。紋様が淡く光り始めた。手を伸ばすと——石碑が温かい。生きているような温もり。まるで、中に誰かがいるかのような。導かれるように——石碑に、手を触れた。","type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_tense","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"触れた瞬間——意識が飛んだ。目の前が真っ白になり、次の瞬間、自分が知らない場所に立っていた。荒野。遠くに山脈。見たことのない星空。——これは、記憶だ。自分の記憶ではない。誰かの——遠い過去の記憶。","type":"text","bg_key":"bg_heroic_stele","next":"text_vision_start","choices":[{"label":"続ける","next":"text_vision_start"}]},"text_vision_start":{"text":"記憶の中で、一人の戦士が剣を振るっていた。顔は見えない。だが——その背中を知っている。魂の奥底で、繋がっている感覚。この人物は——かつて、この世界を救った英霊。神の裁きに立ち向かい、人間の未来を勝ち取った存在。そして——自分は、その継承者だった。","type":"text","bg_key":"bg_heroic_stele","next":"text_vision_hero","choices":[{"label":"続ける","next":"text_vision_hero"}]},"text_vision_hero":{"text":"英霊の声が聞こえた。天使の声とは違う。温かく、人間の言葉だった。「……やっと、目覚めたか。　待っていた。ずっと、待っていた。　お前の中に、俺の力の欠片が眠っている。　だが今のままでは、まだ足りない。　世界に散らばった石碑を巡れ。　俺が遺した武具を集めろ。　全てが揃った時——お前は、神に届く」","type":"text","bg_key":"bg_heroic_stele","next":"text_vision_end","choices":[{"label":"続ける","next":"text_vision_end"}]},"text_vision_end":{"text":"「石碑は四つの都市の近くにある。　イスハーク、龍京、出雲、レガリア——　それぞれに、俺の記憶と遺産が眠っている」英霊の姿が薄れていく。「……時間がない。奴らも気づき始めている。　お前が継承者であることに。　——急げ」","type":"text","bg_key":"bg_heroic_stele","next":"text_awakening","choices":[{"label":"続ける","next":"text_awakening"}]},"text_awakening":{"text":"意識が戻った。石碑の前に、膝をついていた。どのくらいの時間が経ったのかわからない。だが——全身に、微かな力が満ちている。今まで感じたことのない力。英霊の力の、ほんの欠片。","type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_calm","next":"text_inheritance","choices":[{"label":"続ける","next":"text_inheritance"}]},"text_inheritance":{"text":"自分が——世界を救った英霊の継承者。信じがたい話だ。だが、体が知っている。この力は本物だ。四つの都市に、石碑と遺産が眠っている。全てを集めれば——神に届く力が手に入る。立ち上がった。新たな旅の目的が、定まった。","type":"text","bg_key":"bg_heroic_stele","next":"text_ambush_warning","choices":[{"label":"続ける","next":"text_ambush_warning"}]},"text_ambush_warning":{"text":"その時——空気が変わった。英霊が言っていた。「奴らも気づき始めている」と。空が暗くなる。だが雲ではない。黒い翼の群れが、上空を覆い始めた。堕天使——天から追放された者たち。神に仕えながらも、穢れに染まった存在。","type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_crisis","next":"text_fallen_descent","choices":[{"label":"続ける","next":"text_fallen_descent"}]},"text_fallen_descent":{"text":"堕天使の群れが、丘の上に降り立った。天使とは異なる、黒い翼と歪んだ光。だが——力は本物だ。石碑を壊そうとしている。あるいは——継承者を、ここで潰そうとしている。","type":"text","bg_key":"bg_road_day","next":"text_fallen_taunt","choices":[{"label":"続ける","next":"text_fallen_taunt"}]},"text_fallen_taunt":{"text":"堕天使の一体が嗤った。「英霊ノ継承者カ。　マタ、人間ガ分ヲ弁エズニ足掻クノカ。　先代モ同ジダッタ。強カッタガ——所詮ハ人間。　滅ビル運命ハ変ワラナイ」黒い翼が広がった。嗤いながら——襲いかかってきた。","type":"text","bg_key":"bg_road_day","speaker_name":"堕天使","speaker":"堕天使","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"堕天使の群れが急襲！英霊の石碑を守り抜け！","type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"216","choices":[{"label":"続ける","next":"text_aftermath"}],"battle_success_next":"text_aftermath"},"text_aftermath":{"text":"堕天使を退けた。石碑は無事だ。紋様がまだ淡く光っている。まるで——「よくやった」と言っているかのように。石碑に手を当てた。今度は幻視は来ない。だが——温かさが、手のひらに伝わった。","type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_calm","next":"text_guidance","choices":[{"label":"続ける","next":"text_guidance"}]},"text_guidance":{"text":"四つの都市に散らばった石碑と遺産。イスハークのピラミッドに——護符。龍京の沖合の無人島に——剣。出雲の山奥の秘境に——鎧。レガリアの郊外の遺跡に——最後の記憶。全てを集めた時、神に届く力が手に入る。英霊の導きに従い、旅に出る。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"自分が何者であるかを知った。英霊の継承者——かつて世界を救った者の後継。まだ力は足りない。だが、道は示された。四つの都市に眠る遺産を集め、英霊が果たせなかった決着をつける。丘を下り、旅立った。石碑の光が背中を押すように、静かに瞬いていた。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"堕天使の爪に引き裂かれ、地に伏した。石碑の光が——消えていく。英霊の遺産は、また長い眠りにつくのだろうか。","type":"end","result":"failure","bg_key":"bg_road_day","choices":[]}}}'::jsonb, rewards = '{"gold":3000,"exp":400,"reputation":20}'::jsonb WHERE id = 6016;

-- 6017_main_ep17.csv (18 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"英霊の導きに従い、イスハークへ向かった。黄金都市はかつての輝きを取り戻し、市場には商人たちの活気ある声が響いている。目的地は街の外——砂漠の中のピラミッドだ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text_ishaq","choices":[{"label":"続ける","next":"text_ishaq"}]},"text_ishaq":{"text":"イスハークの東に、古代のピラミッドが聳えている。マルカンドの建国よりも遥か昔——名もなき文明が築いた巨大な石造りの墓所。観光名所として知られているが、内部の大半は未踏査のまま残されている。その奥に——英霊の石碑がある。","type":"text","bg_key":"bg_desert","next":"text_pyramid","choices":[{"label":"続ける","next":"text_pyramid"}]},"text_pyramid":{"text":"ピラミッドの入口を抜け、内部に入った。松明の光が石壁に揺れる。壁面には古代の壁画が描かれていた。星の配置。人間の営み。そして——翼を持つ存在との戦い。この文明も、かつて神と戦ったのかもしれない。","type":"text","bg_key":"bg_catacombs","next":"text_hidden_passage","choices":[{"label":"続ける","next":"text_hidden_passage"}]},"text_hidden_passage":{"text":"奥へ進むと、行き止まりに突き当たった。だが——壁の一部に、石碑と同じ紋様が刻まれている。手を当てると、壁が音を立てて動き始めた。砂が崩れ落ち、隠し通路が現れた。空気が変わった。古い空気。何千年も閉じ込められていた空気。その奥から、微かな光が漏れている。","type":"text","bg_key":"bg_catacombs","next":"text_chamber","choices":[{"label":"続ける","next":"text_chamber"}]},"text_chamber":{"text":"通路の先に、広い部屋があった。天井が高い。壁面全体に紋様が刻まれている。部屋の中央に——石碑が立っていた。国境の町で見つけたものと同じ紋様。だが、こちらの方が大きく、光が強い。中に眠る記憶が——呼んでいる。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑の表面に文字が浮かび上がった。古代の言語。読めないはずなのに——意味が伝わる。「此処に、英霊の記憶を封じる。　継承者よ。触れよ。　我が戦いを追体験し、力の欠片を受け継げ」","type":"text","bg_key":"bg_pyramid_chamber","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"石碑に手を触れた。前回と同じように、意識が飛んだ。だが今度は——より深く、より鮮明に。目を開けると、見知らぬ場所に立っていた。ここは——先代の英霊の記憶の中だ。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_memory_start","choices":[{"label":"続ける","next":"text_memory_start"}]},"text_memory_start":{"text":"記憶の中の風景が広がった。砂漠の中のオアシス。椰子の木が揺れ、泉が陽光を反射している。だが——空気が張り詰めていた。このオアシスで、英霊は何かと戦ったのだ。","type":"text","bg_key":"bg_memory_oasis","next":"text_memory_oasis","choices":[{"label":"続ける","next":"text_memory_oasis"}]},"text_memory_oasis":{"text":"記憶が再生される。先代の英霊は、このオアシスで追い詰められていた。水を求めて辿り着いた泉の底から——冥界の門が開いたのだ。泉の水が黒く染まる。地面が裂け、暗い霧が噴き出した。その霧の中から——冥王が姿を現した。","type":"text","bg_key":"bg_memory_oasis","next":"text_hades_appear","choices":[{"label":"続ける","next":"text_hades_appear"}]},"text_hades_appear":{"text":"黒い霧が人の形を取った。蒼白い肌。深い闇を湛えた瞳。黒い衣を纏い、手には闇の錫杖を持っている。冥王ハデス——死者の国を統べる神。生命そのものを奪い取る力の持ち主。記憶の中の存在だが——殺意は本物だ。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_battle_strong","next":"text_hades_voice","choices":[{"label":"続ける","next":"text_hades_voice"}]},"text_hades_voice":{"text":"ハデスが口を開いた。低く、冷たく、地の底から響くような声。「また来たか、英霊の欠片よ。　先代も同じ顔をしていた。　死を恐れぬ目。だが——」錫杖が地面を突いた。地面に亀裂が走る。「死を恐れぬことと、　死を超えることは違う」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"text_hades_challenge","choices":[{"label":"続ける","next":"text_hades_challenge"}]},"text_hades_challenge":{"text":"「冥府の門を越えられるか、試してやろう。　先代は——越えた。　だが代償に、寿命の半分を差し出した。　お前はどうだ？　同じ覚悟があるか？」冥王の錫杖が光り、暗い霧が渦を巻いた。","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"冥王ハデスとの戦闘！記憶の中の死神を打ち倒し、英霊の遺産を勝ち取れ！","type":"battle","bg_key":"bg_memory_oasis","bgm":"bgm_spot_final_boss","enemy_group_id":"9050","choices":[{"label":"続ける","next":"text_hades_defeat"}],"battle_success_next":"text_hades_defeat"},"text_hades_defeat":{"text":"ハデスの錫杖が砕けた。黒い霧が晴れ、オアシスに陽光が戻る。「……見事だ。先代と同じ力を感じる。　いや——それ以上かもしれん」ハデスの姿が薄れていく。「覚えておけ。死は終わりではない。　次の始まりだ。　——お前が来た時、冥府の門は開いている」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"text_talisman","choices":[{"label":"続ける","next":"text_talisman"}]},"text_talisman":{"text":"意識が現実に戻った。石碑の足元に——光る物体が落ちていた。古い護符。暗い輝きを放つ石が嵌め込まれている。手に取ると、冷たいが——力が込められている。冥王の護符。英霊がハデスから勝ち取った遺産の一つ。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"text":"ピラミッドを出ると、砂漠の夕陽が眩しかった。護符を懐に収めた。四つの遺産のうち、一つを手にした。残りは三つ。龍京の無人島に剣。出雲の秘境に鎧。レガリアの遺跡に——最後の記憶。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"冥王ハデスの試練を乗り越え、護符を手に入れた。英霊の記憶は、鮮烈だった。あの英霊もまた、一人の人間として神に抗い続けたのだ。自分はその続きを歩いている。次の石碑を目指して、旅を続ける。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"冥王の霧に呑み込まれた。意識が暗闇に沈んでいく。記憶の中で——ハデスの声が遠くから聞こえた。「まだ、早かったか……」","type":"end","result":"failure","bg_key":"bg_memory_oasis","choices":[]}}}'::jsonb, rewards = '{"gold":3500,"exp":450,"reputation":25}'::jsonb WHERE id = 6017;

-- 6018_main_ep18.csv (18 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"英霊の導きに従い、龍京へ向かった。華龍の首都は活気に満ち、港には大陸各地からの交易船が停泊している。だが目的は都市の中ではない。龍京の漁師から聞いた話——沖合に、誰も近づかない小さな無人島があるという。「光る石がある」と、古い漁師が教えてくれた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text_port","choices":[{"label":"続ける","next":"text_port"}]},"text_port":{"text":"龍京の港で小舟を借りた。漁師たちは島の方角を指差して首を振った。「あの島には行かねぇ方がいい。　海が荒れる。磁石が狂う。　……帰ってこなかった奴もいる」忠告を聞き流し、船を出した。","type":"text","bg_key":"bg_road_day","next":"text_voyage","choices":[{"label":"続ける","next":"text_voyage"}]},"text_voyage":{"text":"港を出て半日。漁師の言う通り、島に近づくと海が荒れ始めた。波が高くなり、風向きが突然変わる。だが——石碑の紋様が腕に浮かんだ。光る紋様が、正しい方角を示している。波を切り、島に辿り着いた。","type":"text","bg_key":"bg_road_day","next":"text_island_arrival","choices":[{"label":"続ける","next":"text_island_arrival"}]},"text_island_arrival":{"text":"無人島は想像よりも小さかった。白い砂浜と、背の高い熱帯の樹木。鳥の声が響いている。虫の音が重なる。一見すると平穏な島だが——空気に、微かな緊張が含まれている。島の中央に向かって、獣道を進んだ。","type":"text","bg_key":"bg_island","bgm":"bgm_quest_tense","next":"text_jungle","choices":[{"label":"続ける","next":"text_jungle"}]},"text_jungle":{"text":"密林を掻き分けて進むと、木々の間に古い石段が見えた。苔むした石段を登ると、開けた場所に出た。石造りの祭壇のような構造物。その中央に——石碑が立っていた。陽光を浴びて、紋様が輝いている。","type":"text","bg_key":"bg_island","next":"text_ruins","choices":[{"label":"続ける","next":"text_ruins"}]},"text_ruins":{"text":"祭壇の周囲に、古代の彫刻が並んでいた。剣を振るう戦士。盾を構える兵士。そして——血に染まった戦場に立つ、鎧の神の姿。この島は、戦の神を祀る古代の聖域だったのだ。","type":"text","bg_key":"bg_island","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑に近づいた。表面に文字が浮かび上がる。「此処に、英霊の記憶を封じる。　継承者よ。触れよ。　戦神の試練を越え、力の欠片を受け継げ」深呼吸をして——石碑に手を触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"意識が飛んだ。視界が暗くなり——次の瞬間、深い森の中に立っていた。英霊の記憶。夜だ。雨が降っている。体のどこかが——痛い。","type":"text","bg_key":"bg_heroic_stele","next":"text_memory_forest","choices":[{"label":"続ける","next":"text_memory_forest"}]},"text_memory_forest":{"text":"記憶が再生される。英霊は、雨の森を一人で走っていた。肩から血が流れている。足を引きずっている。背後から——重い足音が迫っていた。走っても走っても、距離が縮まる。木の陰に身を隠した。息を殺して、追手が通り過ぎるのを待った。だが——足音が、目の前で止まった。","type":"text","bg_key":"bg_memory_forest","next":"text_ares_appear","choices":[{"label":"続ける","next":"text_ares_appear"}]},"text_ares_appear":{"text":"木の陰から見上げると——男が立っていた。赤銅色の鎧。使い込まれた大剣を片手で提げている。人間と同じ背丈。だが——纏う気配が違う。雨に濡れた赤い髪。傷だらけの顔。戦い続けることだけが生きがいだと言わんばかりの、獣のような目をしていた。軍神アレス——戦そのものを体現した神。","type":"text","bg_key":"bg_memory_forest","bgm":"bgm_battle_strong","next":"text_ares_voice","choices":[{"label":"続ける","next":"text_ares_voice"}]},"text_ares_voice":{"text":"アレスが木の幹を蹴った。英霊の隠れていた木が、根元から折れた。「見つけたぞ、傭兵。　三日も追いかけさせやがって。　まともに立てもしねぇくせに、よく逃げ回る」大剣の切っ先で、英霊の顎を持ち上げた。「だが——その目は気に入った。　諦めてねぇ目だ。折れた剣でもまだ斬れると思ってる目だ」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"text_ares_challenge","choices":[{"label":"続ける","next":"text_ares_challenge"}]},"text_ares_challenge":{"text":"「お前の英霊は何度も逃げた。何度も隠れた。　だが——追い詰めるたびに刃を向けてきた。　ボロボロの体で、折れかけの剣で」アレスが大剣を構えた。雨粒が刀身を伝い、赤い光が滲む。「技も策も使い果たした後に残るもの。　それが本物の強さだ。　——お前にもそれがあるか、見せてみろ」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"軍神アレスとの戦闘！満身創痍の中、戦の神に立ち向かえ！","type":"battle","bg_key":"bg_memory_forest","bgm":"bgm_spot_final_boss","enemy_group_id":"9051","choices":[{"label":"続ける","next":"text_ares_defeat"}],"battle_success_next":"text_ares_defeat"},"text_ares_defeat":{"text":"泥の中で剣を振り上げ——アレスの鎧の隙間を突いた。軍神がよろめき、片膝をついた。「……ハッ。やっぱりそうだ。　お前らは追い詰められた時が一番怖ぇ」アレスが立ち上がり、破顔した。血が流れているのに——嬉しそうに笑っている。「気に入った。俺の剣を持っていけ。　——次に会う時は、逃げずに最初から来いよ」笑い声を残して、アレスの姿が雨に溶けた。","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"text_sword","choices":[{"label":"続ける","next":"text_sword"}]},"text_sword":{"text":"意識が現実に戻った。石碑の足元に——剣が刺さっていた。重厚な刀身。赤い光を帯びた鍔。手に取ると、ずっしりとした重みがある。だが振ると——驚くほど速く、正確に空を切った。軍神の剣。英霊がアレスから勝ち取った遺産の一つ。","type":"text","bg_key":"bg_island","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"text":"島を出て、龍京に戻った。手の中の剣が、赤い光を微かに放っている。四つの遺産のうち、また一つを手にした。英霊の記憶は、どれも壮絶だ。あの英霊は——一人で、これだけの神と戦ったのか。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"軍神アレスの試練を乗り越え、剣を手に入れた。英霊の記憶の中のアレスは、敵でありながら、どこか気の良い武人だった。「次に会う時は、逃げずに最初から来いよ」その言葉を胸に刻み、次の石碑を目指す。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"アレスの大剣に叩き伏せられ、泥の中に倒れた。雨の音だけが響く中、意識が遠くなっていく。アレスの声が、遠くから聞こえた。「まだ……足りねぇな」","type":"end","result":"failure","bg_key":"bg_memory_forest","choices":[]}}}'::jsonb, rewards = '{"gold":3500,"exp":450,"reputation":25}'::jsonb WHERE id = 6018;

-- 6019_main_ep19.csv (18 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"英霊の導きに従い、出雲へ向かった。古き神々の信仰が息づく祐地は穏やかで、大社の境内には参拝者が絶えない。街の老人が教えてくれた。「北の山奥に、誰も行かない谷がある。　霧が深くて道がわからないが——光る石を見た者がいる」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text_izumo","choices":[{"label":"続ける","next":"text_izumo"}]},"text_izumo":{"text":"出雲の北に連なる山脈に分け入った。杉の大木が空を覆い、昼でも薄暗い。獣道すら途切れる場所まで来ると、人間の気配は完全に消えた。鳥の声だけが、静かに響いている。","type":"text","bg_key":"bg_mountain","next":"text_mountain_path","choices":[{"label":"続ける","next":"text_mountain_path"}]},"text_mountain_path":{"text":"山道は険しかった。崩れかけた岩場を越え、急な斜面を登る。木の根に足を取られ、何度も転びそうになった。だが——腕に浮かぶ石碑の紋様が、正しい道を示し続けている。紋様が強く光る方へ、進んだ。","type":"text","bg_key":"bg_mountain","next":"text_fog","choices":[{"label":"続ける","next":"text_fog"}]},"text_fog":{"text":"標高が上がるにつれ、霧が濃くなった。手を伸ばせば目の前すら見えない白い世界。音も吸い込まれ、自分の足音だけが反響する。この霧は自然のものではない。英霊の石碑が——無関係な者を遠ざけているのだ。","type":"text","bg_key":"bg_mountain","next":"text_shrine_gate","choices":[{"label":"続ける","next":"text_shrine_gate"}]},"text_shrine_gate":{"text":"霧を抜けると、突然視界が開けた。谷間の底に——朽ちた鳥居が立っていた。注連縄は切れ、苔に覆われている。だがその奥に、微かな光が見える。誰にも知られずに、何千年もここで待ち続けていたのだ。","type":"text","bg_key":"bg_mountain_shrine","bgm":"bgm_quest_tense","next":"text_valley","choices":[{"label":"続ける","next":"text_valley"}]},"text_valley":{"text":"鳥居をくぐり、谷の奥へ進んだ。清流が岩を縫って流れている。苔むした石段が、谷の底へ続いていた。石段の終着点に——石碑が立っていた。月光のような銀色の光を放っている。夜ではないのに——この谷だけは、月に照らされていた。","type":"text","bg_key":"bg_mountain_shrine","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑に近づいた。表面に文字が浮かび上がる。「此処に、英霊の記憶を封じる。　継承者よ。触れよ。　月光の試練を越え、力の欠片を受け継げ」覚悟を決めて——石碑に手を触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"意識が飛んだ。白い光が銀に変わり——気づくと、月明かりの山道に立っていた。英霊の記憶。この山で、英霊は追い詰められた。","type":"text","bg_key":"bg_heroic_stele","next":"text_memory_mountain","choices":[{"label":"続ける","next":"text_memory_mountain"}]},"text_memory_mountain":{"text":"記憶が再生される。英霊は、月夜の山道を駆けていた。木々の間から——銀色の矢が飛んでくる。音もなく。気配もなく。ただ正確に、急所を狙って射抜いてくる。どの木の陰にも、どの岩の裏にも——銀色の瞳が光っていた。狩りの女神に——標的にされていた。","type":"text","bg_key":"bg_memory_mountain","next":"text_artemis_appear","choices":[{"label":"続ける","next":"text_artemis_appear"}]},"text_artemis_appear":{"text":"月光の中に、影が現れた。銀の髪。冷たい瞳。背に銀の弓を負い、白い狩衣を纏っている。女神アルテミス——月と狩りを司る神。狩猟を司る女神にして、最も正確な射手。その矢は——一度も的を外したことがないという。","type":"text","bg_key":"bg_memory_mountain","bgm":"bgm_battle_strong","next":"text_artemis_voice","choices":[{"label":"続ける","next":"text_artemis_voice"}]},"text_artemis_voice":{"text":"アルテミスが弓を構えた。静かな声。感情を排した、研ぎ澄まされた声。「狩りの作法を教えよう。　獲物は——逃げれば追う。　隠れれば見つける。　立ち向かえば——射抜く。　英霊は、三つ目を選んだ。　お前はどうする？」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"text_artemis_challenge","choices":[{"label":"続ける","next":"text_artemis_challenge"}]},"text_artemis_challenge":{"text":"「答えは聞くまでもないか。　その目を見ればわかる。　——良いだろう。　月の狩りに、挑む勇気は認める」銀の弓が引き絞られた。月光が矢に凝縮される。「だが——覚悟だけでは、矢は止められない」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"女神アルテミスとの戦闘！月光の矢を掻い潜り、狩りの女神を打ち倒せ！","type":"battle","bg_key":"bg_memory_mountain","bgm":"bgm_spot_final_boss","enemy_group_id":"9052","choices":[{"label":"続ける","next":"text_artemis_defeat"}],"battle_success_next":"text_artemis_defeat"},"text_artemis_defeat":{"text":"銀の弓の弦が——断ち切られた。アルテミスが弓を下ろし、初めて——僅かに、口元が緩んだ。「……英霊と同じだ。　追い詰めても、追い詰めても、前に出てくる。　人間の、そういうところが——厄介だ」月光に溶けるように、アルテミスの姿が消えた。「鎧はお前に預ける。　——次の狩りを、楽しみにしている」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"text_armor","choices":[{"label":"続ける","next":"text_armor"}]},"text_armor":{"text":"意識が現実に戻った。石碑の足元に——鎧が置かれていた。銀色に輝く鎧。月光を編み込んだような繊細な意匠。手に取ると、驚くほど軽い。だが、確かな守りの力が宿っている。女神の鎧。英霊がアルテミスから勝ち取った遺産の一つ。","type":"text","bg_key":"bg_mountain_shrine","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"text":"山を下り、出雲の街に戻った。手の中の鎧が、月光のように淡く光っている。四つの遺産のうち、また一つを手にした。ハデスの護符。アレスの剣。アルテミスの鎧。残るは——レガリアの遺跡に眠る、最後の記憶。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"女神アルテミスの試練を乗り越え、鎧を手に入れた。狩りの女神は手強かった。だが——最後の微笑みには、敵意はなかった。英霊は、これだけの神々と渡り合ってきたのだ。自分はその遺産を受け継ぎ、先へ進む。最後の石碑が待っている。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"銀の矢が胸を貫いた。月光の中に倒れ、意識が消えていく。遠くで——アルテミスの声が聞こえた。「まだ……獲物ではなかったか」","type":"end","result":"failure","bg_key":"bg_memory_mountain","choices":[]}}}'::jsonb, rewards = '{"gold":3500,"exp":450,"reputation":25}'::jsonb WHERE id = 6019;

-- 6020_main_ep20.csv (23 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"英霊の遺産を集める旅の、最後の行程。レガリア郊外にある古代の遺跡。かつて何の遺跡かもわからなかった場所が、今は——最後の石碑が眠る場所だとわかっている。ここに、英霊の最後の記憶がある。そして——全能神ゼウスが待っている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text_regalia","choices":[{"label":"続ける","next":"text_regalia"}]},"text_regalia":{"text":"レガリアの街を抜け、郊外へ向かった。王都は完全に復興し、白亜の城壁は以前よりも立派にそびえている。この街の人々のために——この戦いを終わらせなければ。","type":"text","bg_key":"bg_road_day","next":"text_outskirts","choices":[{"label":"続ける","next":"text_outskirts"}]},"text_outskirts":{"text":"レガリアの郊外。丘陵地帯の先に、古い石造りの遺跡が見えた。風化した柱。崩れかけた壁。かつては何かの神殿だったのだろう。だが——この遺跡には、英霊が最後の記憶を封じた石碑がある。","type":"text","bg_key":"bg_ruins_field","next":"text_ruins_entrance","choices":[{"label":"続ける","next":"text_ruins_entrance"}]},"text_ruins_entrance":{"text":"遺跡の入口に立った。他の石碑がある場所とは空気が違う。緊張ではない。重圧。ここに封じられた記憶は、英霊にとって最後の戦いだった。深呼吸をして、遺跡の中に足を踏み入れた。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_crisis","next":"text_descent","choices":[{"label":"続ける","next":"text_descent"}]},"text_descent":{"text":"石段を下りていく。壁面の壁画が他の遺跡とは異なっていた。二人の人間が背中を合わせて戦う姿。一人は剣を、もう一人は盾を構えている。二人の前に——巨大な光の存在が立ちはだかっている。雷を纏った、天空の王の姿。","type":"text","bg_key":"bg_catacombs","next":"text_final_chamber","choices":[{"label":"続ける","next":"text_final_chamber"}]},"text_final_chamber":{"text":"最奥の部屋に辿り着いた。今までの石碑の部屋よりも遥かに広い。天井にはっきりと空が見える。崩れた天井から、陽光が一本の柱のように降り注いでいた。その光の中に——最後の石碑が立っていた。他のどの石碑よりも大きく、強い光を放っている。","type":"text","bg_key":"bg_boss_altar","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑に近づいた。表面の文字が、今までよりも力強く輝く。「此処に、英霊の最後の記憶を封じる。　継承者よ。触れよ。　全てを終わらせる力を——受け継げ」これが、最後の試練。覚悟を決めて——石碑に、手を触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"意識が飛んだ。今までで最も深く、最も鮮明に。目を開けると——広い平原に立っていた。空は暗く、雷鳴が轟いている。そして——隣に、誰かが立っていた。","type":"text","bg_key":"bg_heroic_stele","next":"text_memory_gawain","choices":[{"label":"続ける","next":"text_memory_gawain"}]},"text_memory_gawain":{"text":"記憶の中の英霊の隣に——一人の騎士がいた。額の傷跡。刃こぼれした長剣。砂埃を被った甲冑。——ガウェイン。英霊と共に戦った騎士。あの老騎士の、若き日の姿がそこにあった。","type":"text","bg_key":"bg_memory_gawain","next":"text_memory_comrade","choices":[{"label":"続ける","next":"text_memory_comrade"}]},"text_memory_comrade":{"text":"記憶の中のガウェインが、英霊に声をかけた。「相棒。あの雷の野郎が最後だ。　こいつを倒せば——終わる。全部、終わる」先代の英霊が頷いた。二人は剣を構えた。その背中は——かつて見た、あの老騎士の背中と重なった。ガウェインは、英霊の時代からずっと——人間のために戦い続けていたのだ。","type":"text","bg_key":"bg_memory_gawain","next":"text_zeus_appear","choices":[{"label":"続ける","next":"text_zeus_appear"}]},"text_zeus_appear":{"text":"雷鳴が一際大きく轟いた。雲の中から——巨大な存在が降りてくる。白い髭。威厳に満ちた顔。全身を雷光が包み、手には稲妻の槍を握っている。全能神ゼウス——神々の王にして、天空の支配者。全ての神の頂点に立つ存在。英霊が最後に戦い、辛くも退けた相手——その記憶が、今、目の前に再現される。","type":"text","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","next":"text_zeus_voice","choices":[{"label":"続ける","next":"text_zeus_voice"}]},"text_zeus_voice":{"text":"ゼウスが見下ろした。雷鳴のような声が、空間を震わせる。「また来たか、人間よ。　英霊は我を退けた。だが——倒しはしなかった。　神は不滅。天は永遠。　お前たちの抵抗は、嵐の前の蝋燭に過ぎぬ」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"text_zeus_challenge","choices":[{"label":"続ける","next":"text_zeus_challenge"}]},"text_zeus_challenge":{"text":"「だが——認めよう。　人間には、我を苛立たせるだけの力がある。　ならば見せてみよ。　英霊を超える力があるのかどうか——　この場で証明せよ！」稲妻の槍が天に掲げられた。空全体が白く輝き、雷鳴が連続して轟く。","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"check_items","choices":[{"label":"続ける","next":"check_items"}]},"check_items":{"text":"英霊の遺産が反応している——","type":"check_item","bg_key":"bg_memory_gawain","params":{"items":[505,506,507],"success_node":"text_relics_glow","fail_node":"text_relics_missing"},"next":"text_relics_glow","choices":[{"label":"続ける","next":"text_relics_glow"}]},"text_relics_glow":{"text":"冥王の護符が闇の光を放った。軍神の剣が赤い光を放った。女神の鎧が銀色に光り始めた。三つの遺産が共鳴し、全身を包む光の鎧となった。英霊が集めた神々の力——その加護が、継承者の体に宿る。ゼウスの雷を受け止められる。——いける。","type":"text","bg_key":"bg_memory_gawain","next":"battle_weak","choices":[{"label":"続ける","next":"battle_weak"}]},"battle_weak":{"text":"全能神ゼウスとの最終決戦！英霊の遺産の加護を纏い、神々の王を打ち倒せ！","type":"battle","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","enemy_group_id":"9053","choices":[{"label":"続ける","next":"text_zeus_defeat"}],"battle_success_next":"text_zeus_defeat"},"text_zeus_defeat":{"text":"稲妻の槍が——砕けた。ゼウスの巨体が揺らぎ、膝をついた。雷鳴が止み、空に静寂が戻る。「……馬鹿な。人間が……二度までも……」ゼウスが顔を上げた。その目に——怒りではなく、困惑があった。「英霊は我を退けた。　そしてお前もまた——　なぜだ。なぜ人間は、神を超えようとする？」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"text_dawn_sword","choices":[{"label":"続ける","next":"text_dawn_sword"}]},"text_dawn_sword":{"text":"意識が現実に戻った。石碑が砕け散り、光の粒が舞っている。その光が凝縮し——一振りの剣となった。蒼く輝く剣。刃に刻まれた紋様が、夜明けの空のように煌めいている。蒼暁の剣——英霊が神を退けた時に生まれた、人間の意志の結晶。手に取った。軽く、温かく——しっくりと手に馴染んだ。","type":"text","bg_key":"bg_boss_altar","next":"text_epilogue","choices":[{"label":"続ける","next":"text_epilogue"}]},"text_epilogue":{"text":"遺跡を出ると、夜明けだった。東の空が蒼く染まり、やがて金色に変わっていく。新しい一日が始まる。英霊は、神と戦い、人間の未来を勝ち取った。その記憶と遺産は、次の世代へ受け継がれた。蒼暁の剣を掲げた。朝日が刃に反射し、蒼い光が空に伸びた。神の審判は終わった。人間は——自分たちの手で、未来を切り拓いた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"全能神ゼウスを打ち破り、蒼暁の剣を手にした。英霊の記憶と共に、神々の審判から世界を救った。四つの首都は守られ、人々は生き続けている。この剣は——人間が諦めなかった証だ。英霊から受け継いだ意志と、仲間と共に戦い抜いた記憶が刻まれている。新しい朝が来た。世界は——自由だ。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"ゼウスの雷に打たれ、地に伏した。全能神の声が、遠雷のように響く。「まだ……足りぬか。人間よ」意識が——消えていく。","type":"end","result":"failure","bg_key":"bg_memory_gawain","choices":[]},"text_relics_missing":{"text":"英霊の遺産が——足りない。三つ全ての力が揃っていなければ、神々の加護は完全にはならない。ゼウスの力が増幅された。全能神の雷が、さらに苛烈になっていく。加護なしで、全力のゼウスに挑むことになる。——覚悟を決めるしかない。","type":"text","bg_key":"bg_memory_gawain","next":"battle_strong","choices":[{"label":"続ける","next":"battle_strong"}]},"battle_strong":{"text":"全能神ゼウスとの最終決戦！遺産の加護なしで、全力の神に挑め！","type":"battle","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","enemy_group_id":"9054","choices":[{"label":"続ける","next":"text_zeus_defeat"}],"battle_success_next":"text_zeus_defeat"}}}'::jsonb, rewards = '{"gold":15000,"exp":1000,"reputation":50}'::jsonb WHERE id = 6020;

-- 6101_qst_spot_roland.csv (24 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"王都レガリア中央広場。噴水の水が赤黒く染まっていた。聖騎士が血だらけで走ってきた。「逃げろ！ やつらは……やつらは人じゃない！ 英霊が……蘇った英霊が街を壊してる！」","type":"text","bg_key":"bg_spot_roland_fire","bgm":"bgm_roland","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"背後の大聖堂が爆発した。「慈愛の聖女」が手を翳しただけで兵士たちが崩れ落ちた。「不滅の王」が睨んだだけで城門が折れた。もう立ち向かえる者はいない。地下墓所へ逃げ込むしかない。","type":"text","bg_key":"bg_spot_roland_fire","next":"escape_underground","choices":[{"label":"続ける","next":"escape_underground"}]},"escape_underground":{"text":"地下墓所の最奥で壁の一角に不自然な隙間を見つけた。押すと崩れ、地図にない部屋が広がっていた。壁には歴史書に載っていない英雄たちの名が刻まれている——歴史から抹消された、本当の英雄たちの墓所だ。","type":"text","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","next":"text_protos","choices":[{"label":"続ける","next":"text_protos"}]},"text_protos":{"text":"部屋の中央に朽ちた祭壇がある。何かが光っている。手を伸ばそうとした瞬間——石造りの巨人が壁から這い出てきた。祭壇の守護者だ。","type":"text","bg_key":"bg_spot_roland_tomb","next":"battle_protos","choices":[{"label":"続ける","next":"battle_protos"}]},"battle_protos":{"text":"墓所の守護者プロトスが起動した！","type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"300","enemy_name":"墓所の守護者","enemy_level":18,"choices":[{"label":"勝利","next":"get_promise"}],"battle_success_next":"get_promise"},"get_promise":{"text":"祭壇の奥から五角形に並んだ宝珠が現れた。手に取ると頭の中に声が響いた。「我らの誓約を受け継ぐ者よ。我らは王に裏切られた。この石があれば暴走する我らの絶技を打ち消せる。……頼む。我らを止めてくれ」パッシブスキル『五英霊の誓約』を入手した。","type":"reward","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","params":{"items":["601"]},"next":"text_eluka","choices":[{"label":"続ける","next":"text_eluka"}]},"text_eluka":{"text":"白い法衣をまとった女が浮かんでいる。目には涙の跡が凍りついていた。「……あなた、生きているのね。珍しいわ」慈愛の聖女エルーカ。王家に「生きた薬」として幽閉され、三年間血を抜かれ続けた女性。","type":"text","bg_key":"bg_spot_roland_tomb","next":"text_eluka2","choices":[{"label":"続ける","next":"text_eluka2"}]},"text_eluka2":{"text":"「私は三年間、暗闇の中で血を抜かれ続けたの。祈っても祈っても、誰も来なかった。……それでもまだ、私に『慈愛』を求めるの？」彼女の周囲の空気が凍りつく。","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"聖女エルーカ","speaker":"聖女エルーカ","next":"boss_eluka","choices":[{"label":"続ける","next":"boss_eluka"}]},"boss_eluka":{"text":"聖女エルーカとの戦闘！","type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"301","enemy_name":"聖女エルーカ","enemy_level":20,"choices":[{"label":"勝利","next":"text_baram"}],"battle_success_next":"text_baram"},"text_baram":{"text":"エルーカは消え際に小さく呟いた。「……ありがとう。やっと、眠れる」次の通路は壁一面に数式と魔法陣が刻まれていた。中央で黒いローブの痩せた男が本を読んでいる。「おや、客人か。最後に人と話したのは……処刑される前日だったかな」","type":"text","bg_key":"bg_spot_roland_tomb","next":"text_baram2","choices":[{"label":"続ける","next":"text_baram2"}]},"text_baram2":{"text":"知恵の賢者バラム。王に研究成果を全て奪われ、口封じに毒殺された魔術師。「私の研究は王家の『神聖魔術』として発表された。さて、死後の暇つぶしに付き合ってもらおうか」空中に無数の魔法陣が展開された。","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"賢者バラム","speaker":"賢者バラム","next":"boss_baram","choices":[{"label":"続ける","next":"boss_baram"}]},"boss_baram":{"text":"賢者バラムとの戦闘！","type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"302","enemy_name":"賢者バラム","enemy_level":20,"choices":[{"label":"勝利","next":"text_shirasu"}],"battle_success_next":"text_shirasu"},"text_shirasu":{"text":"バラムが霧のように散った。「負けるのは嫌いじゃないよ。研究者は常に仮説を修正するものだ」次の部屋には壁に無数の傷ついた盾。奥に全身傷痕だらけの男が巨大な盾を地面に突き立て、無言でこちらを見据えている。","type":"text","bg_key":"bg_spot_roland_tomb","next":"text_shirasu2","choices":[{"label":"続ける","next":"text_shirasu2"}]},"text_shirasu2":{"text":"盾の守護者シラス。王の身代わりとして毒杯を仰いだ騎士。王は彼の死を「不慮の事故」として処理し、遺族への補償すら行わなかった。「言葉はいらん。俺は死んでも王を守った。だが王は、俺の家族すら守らなかった」盾が軋む音を立てた。","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"盾のシラス","speaker":"盾のシラス","next":"boss_shirasu","choices":[{"label":"続ける","next":"boss_shirasu"}]},"boss_shirasu":{"text":"盾のシラスとの戦闘！","type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"303","enemy_name":"盾のシラス","enemy_level":20,"choices":[{"label":"勝利","next":"text_lyra"}],"battle_success_next":"text_lyra"},"text_lyra":{"text":"シラスが膝をついた。「……強いな。俺の家族のことは……もういい。ただ、あの子らが飯を食えていたなら、それでいい」次の広間に入った瞬間、蒼い光が頬を掠めた。矢だ。壁に背を預ける女が長弓を構えている。片方の目が潰されている。","type":"text","bg_key":"bg_spot_roland_tomb","next":"text_lyra2","choices":[{"label":"続ける","next":"text_lyra2"}]},"text_lyra2":{"text":"千里の射手リラ。三つの戦争を勝利に導いた弓の名手。軍事機密が不都合だったため「戦死扱い」で暗殺された。「英雄なんて、使い捨ての道具よ。役目が終われば、口を塞がれて消される。——私がその証拠」二本目の矢が放たれた。","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"射手リラ","speaker":"射手リラ","next":"boss_lyra","choices":[{"label":"続ける","next":"boss_lyra"}]},"boss_lyra":{"text":"射手リラとの戦闘！","type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"304","enemy_name":"射手リラ","enemy_level":20,"choices":[{"label":"勝利","next":"text_alvin"}],"battle_success_next":"text_alvin"},"text_alvin":{"text":"リラが弓を降ろした。「……ごめんね。でもあなたが勝ったなら——少しだけ、信じてみてもいいかもしれない」最深部。天井のない巨大な空間。光る粒子が漂う中央の玉座に、金色の鎧を纏い王冠を被った男が座っていた。目は虚ろだった。","type":"text","bg_key":"bg_spot_roland_core","bgm":"bgm_spot_final_boss","next":"text_alvin2","choices":[{"label":"続ける","next":"text_alvin2"}]},"text_alvin2":{"text":"「不滅の王」アルヴィン。建国者にして四人の仲間を殺した男。「俺は四人を殺した。四人の友を、国のために殺した。その罪は……この身が何度滅びても、消えやしない」金色の鎧が黒く染まっていく。「だから——来い！ 俺を止められる者がいるなら、止めてみろ！」","type":"text","bg_key":"bg_spot_roland_core","speaker_name":"不滅の王アルヴィン","speaker":"不滅の王アルヴィン","next":"boss_alvin","choices":[{"label":"続ける","next":"boss_alvin"}]},"boss_alvin":{"text":"不滅の王アルヴィンとの最終決戦！","type":"battle","bg_key":"bg_spot_roland_core","bgm":"bgm_spot_final_boss","enemy_group_id":"305","enemy_name":"不滅の王アルヴィン","enemy_level":25,"choices":[{"label":"勝利","next":"final_choice"}],"battle_success_next":"final_choice"},"final_choice":{"text":"アルヴィンが膝をついた。金の鎧が剥がれ、痩せた老人の体が現れた。「すまなかった。エルーカ。バラム。シラス。リラ」そこへ現国王が駆けつけた。「英霊の残骸を回収しろ。あと——この地下墓所の存在は知らなかったことにしてくれ」アルヴィンが血走った目で国王を睨んだ。「冒険者よ。お前が決めろ。俺たちをどうする」","type":"text","bg_key":"bg_spot_roland_core","bgm":"bgm_spot_final_choice","next":"choice_final","choices":[{"label":"王の命令に従い討伐する","next":"end_kill"},{"label":"誓約の力で彼らを安らかに封印する","next":"end_seal"}]},"end_kill":{"text":"王家の命令に従い、五英霊を完全に消滅させた。アルヴィンは最後に一言だけ残した。「……歴史は、また繰り返すのだな」王家は地下墓所を封鎖し、あなたは「王都を救った英雄」として祭り上げられた。報酬として『神の法衣』を授かった。口止め料としては、少々露骨だった。","type":"end","result":"success","bg_key":"bg_spot_roland_core","choices":[]},"end_seal":{"text":"誓約の石を掲げ五つの魂に語りかけた。アルヴィンが目を閉じた。「……ああ。お前のような奴がいてくれて、よかった」五つの光が穏やかに消えていく。最後にアルヴィンが呟いた。「——次の世代に、期待する」国王は苦虫を噛み潰した顔をしたが、英霊たちが託してくれた力は王の命令では消せない。固有スキル『五星の加護』を手に入れた！","type":"end","result":"success","bg_key":"bg_spot_roland_core","choices":[]}}}'::jsonb, rewards = '{"gold":0,"exp":0,"reputation":0}'::jsonb WHERE id = 6101;

-- 6102_qst_spot_yato.csv (26 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"空が赤黒く染まった。太陽が消え、血のような月が昇る。百年に一度の「冥食」だ。隠れ里の長老が杖を突きながら近づいてきた。「異界の門が開き始めておる。儀式を行うしかない。撫子を——あの子を、門の最深部まで連れていってくれ」","type":"text","bg_key":"bg_spot_yato_eclipse","bgm":"bgm_yato","next":"join_nadeshiko","choices":[{"label":"続ける","next":"join_nadeshiko"}]},"join_nadeshiko":{"text":"里の裏手。白い装束に身を包んだ少女が静かに待っていた。「……撫子と申します。門まで、お供させてください」声は震えていなかった。だが握りしめた両手の指先が白かった。「私のことは気にしないでください。覚悟は……とうにできています」","type":"guest_join","bg_key":"bg_spot_yato_eclipse","params":{"guest_id":"npc_nadeshiko"},"next":"text_spider1","choices":[{"label":"続ける","next":"text_spider1"}]},"text_spider1":{"text":"冥の門の入口。鳥居の朱塗りが黒ずんで剥がれ落ちている。門をくぐった瞬間、足元に犬ほどの大きさの鬼蜘蛛が天井から糸を垂らしながら降りてくる。撫子が小さく声を上げた。「……来ます」","type":"text","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","next":"battle_spider1","choices":[{"label":"続ける","next":"battle_spider1"}]},"battle_spider1":{"text":"鬼蜘蛛の群れとの戦闘！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"310","enemy_name":"鬼蜘蛛の群れ","enemy_level":15,"choices":[{"label":"勝利","next":"text_spider2"}],"battle_success_next":"text_spider2"},"text_spider2":{"text":"蜘蛛の残骸を踏み越えて奥へ進む。撫子が呟いた。「この門の中には百年分の怨念が溜まっているそうです。蜘蛛はその怨念を食べて育ったのだと」天井がざわめいた。さっきより大きな群れだ。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_spider2","choices":[{"label":"続ける","next":"battle_spider2"}]},"battle_spider2":{"text":"第二の群れとの戦闘！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"311","enemy_name":"冥の魔物","enemy_level":16,"choices":[{"label":"勝利","next":"text_spider3"}],"battle_success_next":"text_spider3"},"text_spider3":{"text":"三度目の群れ。壁の隙間から這い出してきた。撫子が懐から御札を取り出し祈りを唱えた。御札が淡く光り蜘蛛が一瞬怯んだ。「……少しですが時間を稼げます。今のうちに」","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_spider3","choices":[{"label":"続ける","next":"battle_spider3"}]},"battle_spider3":{"text":"頭上からの奇襲！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"312","enemy_name":"奇襲の魔物","enemy_level":17,"choices":[{"label":"勝利","next":"text_spider4"}],"battle_success_next":"text_spider4"},"text_spider4":{"text":"最後の蜘蛛の群れ。ひときわ巨大な個体が通路いっぱいに体を広げて立ちはだかっている。撫子が錫杖を構えた。「この先に……四大妖怪がいます。百年の間、この闇の中で力を蓄えた者たちです」","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_spider4","choices":[{"label":"続ける","next":"battle_spider4"}]},"battle_spider4":{"text":"最後の守護者との戦闘！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"313","enemy_name":"門の守護者","enemy_level":18,"choices":[{"label":"勝利","next":"text_wani"}],"battle_success_next":"text_wani"},"text_wani":{"text":"地下に広大な水場が広がっていた。水面が割れた。甲羅を纏った巨大な鰐が顎を開いて浮上する。全長は六間。鰐が低い咆哮を上げた。撫子が息を飲んだ。「あの大きさは聞いていた話と違います。水に引き込まれたら、終わりです」","type":"text","bg_key":"bg_spot_yato_entrance","next":"boss_wani","choices":[{"label":"続ける","next":"boss_wani"}]},"boss_wani":{"text":"大鰐との戦闘！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"314","enemy_name":"大鰐","enemy_level":20,"choices":[{"label":"勝利","next":"reward_m1"}],"battle_success_next":"reward_m1"},"reward_m1":{"text":"大鰐が沈んだ。水面に赤い光が浮かび上がる。撫子が光を掬い上げた。朱色の勾玉だ。「四大妖怪を討つたびに門を開く鍵が現れるそうです。……あと三体」朱の勾玉を手に入れた！","type":"reward","bg_key":"bg_spot_yato_entrance","params":{"items":["611"]},"next":"text_tori","choices":[{"label":"続ける","next":"text_tori"}]},"text_tori":{"text":"吹き抜けの大空洞に出た。空が翳った。漆黒の鳥が旋回している。翼を広げると空洞の幅いっぱいだ。「イツマデ、イツマデ」と聞こえる。「以津真天」。百年分の死者を喰らった凶鳥。鳥が急降下してきた。狙いは撫子だ。撫子が叫んだ。「——伏せて！」","type":"text","bg_key":"bg_spot_yato_entrance","next":"boss_tori","choices":[{"label":"続ける","next":"boss_tori"}]},"boss_tori":{"text":"以津真天との戦闘！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"315","enemy_name":"以津真天","enemy_level":20,"choices":[{"label":"勝利","next":"reward_m2"}],"battle_success_next":"reward_m2"},"reward_m2":{"text":"凶鳥が断末魔の鳴き声を上げて堕ちた。黒い羽根が舞い散る中、蒼い光が残された。撫子が少し微笑んだ。「ありがとうございます。残り——あと二体です」蒼の勾玉を手に入れた！","type":"reward","bg_key":"bg_spot_yato_entrance","params":{"items":["612"]},"next":"text_kuruma","choices":[{"label":"続ける","next":"text_kuruma"}]},"text_kuruma":{"text":"車輪の軋む音が聞こえてきた。曲がり角の向こうから炎を纏った巨大な牛車が突進してきた。「朧車」。怨念の乗り物。撫子が壁に張り付いた。「避けてください！ あれは止まりません！ 壊すしか——壊すしかないんです！」","type":"text","bg_key":"bg_spot_yato_entrance","next":"boss_kuruma","choices":[{"label":"続ける","next":"boss_kuruma"}]},"boss_kuruma":{"text":"朧車との戦闘！","type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"316","enemy_name":"朧車","enemy_level":22,"choices":[{"label":"勝利","next":"reward_m3"}],"battle_success_next":"reward_m3"},"reward_m3":{"text":"朧車が砕け散った。撫子が額の汗を拭いた。「あと一体。最後の妖怪を倒せば門の最深部に入れます。でも……最後の相手が一番強いと長老は言っていました」翠の勾玉を手に入れた！","type":"reward","bg_key":"bg_spot_yato_entrance","params":{"items":["613"]},"next":"text_shuten","choices":[{"label":"続ける","next":"text_shuten"}]},"text_shuten":{"text":"門の最奥。朱塗りの巨大な扉の前に男が座っていた。瓢箪を掴んで一口呷った。額から角が二本。「おう、来たか。久しぶりだなあ、人間ってやつは」酒呑童子。伝説の鬼。撫子を見てにやりと笑った。「ほう。いい面構えだ。覚悟が決まってやがる」","type":"text","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_boss","next":"text_shuten2","choices":[{"label":"続ける","next":"text_shuten2"}]},"text_shuten2":{"text":"「だがな、嬢ちゃん。覚悟だけじゃ、ここは通れねえ」瓢箪を投げ捨て両腕を広げた。「さあ来い。俺を楽しませろ。退屈で死にそうなんだ——百年も独りでよ！」地面が揺れた。鬼が笑っている。","type":"text","bg_key":"bg_spot_yato_gate","speaker_name":"酒呑童子","speaker":"酒呑童子","next":"boss_shuten","choices":[{"label":"続ける","next":"boss_shuten"}]},"boss_shuten":{"text":"酒呑童子との最終決戦！","type":"battle","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_boss","enemy_group_id":"317","enemy_name":"酒呑童子","enemy_level":25,"choices":[{"label":"勝利","next":"reward_m4"}],"battle_success_next":"reward_m4"},"reward_m4":{"text":"酒呑童子が膝をついた。角が一本折れている。だが笑っていた。「がはは……やるじゃねえか。百年ぶりにいい汗かいたぜ」鬼が光に溶けながら呟いた。「門の向こうには冥府の王がいる。俺なんかよりずっと厄介だぞ。気をつけな」黄の勾玉を手に入れた！","type":"reward","bg_key":"bg_spot_yato_gate","params":{"items":["614"]},"next":"final_choice","choices":[{"label":"続ける","next":"final_choice"}]},"final_choice":{"text":"四つの勾玉が光り巨大な扉が開いた。撫子が門の前に出てこちらを振り返った。「ここから先は私一人で行きます。お役目ですから」目が赤い。「怖くないと言えば嘘になります。でも——これで里のみんなが助かるなら」撫子は小さく笑った。「あなたに会えてよかった。守ってくれて——ありがとうございました」判断しなければならない。","type":"text","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_choice","next":"choice_final","choices":[{"label":"儀式を完遂させる（撫子を送り出す）","next":"end_sacrifice"},{"label":"因習を打ち砕く（撫子を救う）","next":"end_save"}]},"end_sacrifice":{"text":"撫子の背中を見送った。彼女は振り返らなかった。白い装束が闇に溶けていく。門が閉じた。空に太陽が戻った。里に戻ると長老が深々と頭を下げた。村人たちは祭りの準備を始めていた。撫子の名を口にする者はもう誰もいなかった。報酬として『冥界の護符』を授かった。護符からは微かに花の匂いがした。","type":"end","result":"success","bg_key":"bg_spot_yato_gate","choices":[]},"end_save":{"text":"撫子の手を掴んだ。門から漏れ出す冥府の王の思念が怒涛のように押し寄せてきた。四つの勾玉が盾となって耐えた。力でねじ伏せた。門を内側から破壊した。撫子が泣いていた。「……生きてて、いいんですか。私——」「いい」「……っ、ありがとうございます……」固有スキル『冥食の理』を手に入れた！","type":"end","result":"success","bg_key":"bg_spot_yato_gate","choices":[]}}}'::jsonb, rewards = '{"gold":0,"exp":0,"reputation":0}'::jsonb WHERE id = 6102;

-- 6103_qst_spot_karyu.csv (20 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"華龍の都の外れ。雲を突く巨塔が聳えている。道端に盲目の老人が座っていた。「塔を目指すのか。何人目だろうな」老人は茶を飲み干すと言った。「四方に四神がおる。全て倒さねば塔には入れん。……すべては上にいる『あれ』が仕掛けた遊びだよ」老人はそう言って闇に消えた。","type":"text","bg_key":"bg_spot_karyu_tower","bgm":"bgm_karyu","next":"choose_path","choices":[{"label":"続ける","next":"choose_path"}]},"choose_path":{"text":"塔の足元。四方に道が伸びている。東の空には稲光、西からは吹雪、南には陽炎が揺れ、北の大地がわずかに震えている。どの試練から挑むか。","type":"text","bg_key":"bg_spot_karyu_tower","bgm":"bgm_quest_mystery","next":"choice_direction","choices":[{"label":"東の青龍","next":"trap_seiryu"},{"label":"西の白虎","next":"trap_byakko"},{"label":"南の朱雀","next":"trap_suzaku"},{"label":"北の玄武","next":"trap_genbu"},{"label":"中央の塔へ進む","next":"check_orbs"}]},"trap_seiryu":{"text":"東の道を進むと空が暗転した。足元に落雷。衝撃が体を打った。遠くから声が聞こえる。「——来たか。遊び相手が」","type":"modify_state","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20},"next":"boss_seiryu","choices":[{"label":"続ける","next":"boss_seiryu"}]},"boss_seiryu":{"text":"雷雲の中から蒼い鱗の巨龍が姿を現した。「我は青龍。東方の守護者なり。千年この地で番をしておる」龍が首をもたげた。「正直に言えば退屈なのだ。だが手は抜かぬ。——さあ来い。我を楽しませてみせよ」","type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"320","enemy_name":"青龍","enemy_level":20,"choices":[{"label":"勝利","next":"reward_orb1"}],"battle_success_next":"reward_orb1"},"reward_orb1":{"text":"青龍が崩れ落ちた。龍は消え際に低く笑った。「見事。千年ぶりに膝をついたぞ。あの方に会ったら伝えてくれ。もう退屈は嫌だ、と」青龍の宝珠を手に入れた！","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"items":["621"]},"next":"choose_path","choices":[{"label":"続ける","next":"choose_path"}]},"trap_byakko":{"text":"西の道に踏み出した途端、気温が急降下した。猛吹雪が吹き荒れ視界が白に塗りつぶされた。風の中に獣の唸り声が混じっている。","type":"modify_state","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20},"next":"boss_byakko","choices":[{"label":"続ける","next":"boss_byakko"}]},"boss_byakko":{"text":"吹雪の隙間に白銀の獣が見えた。肩の高さだけで馬ほどある白虎。「……言葉は要らぬ」虎が地面を蹴った。「牙で語る。それが我の流儀だ」","type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"321","enemy_name":"白虎","enemy_level":20,"choices":[{"label":"勝利","next":"reward_orb2"}],"battle_success_next":"reward_orb2"},"reward_orb2":{"text":"白虎が倒れた。「……強いな。認めよう」虎は目を閉じた。「我は戦うことしか知らなかった。だが……悪くない最期だ」白虎の宝珠を手に入れた！","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"items":["622"]},"next":"choose_path","choices":[{"label":"続ける","next":"choose_path"}]},"trap_suzaku":{"text":"南の道は灼熱だった。足元の石が赤く焼けている。突然足元から業火が噴き上がった。上空で赤い羽根が舞っている。","type":"modify_state","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20},"next":"boss_suzaku","choices":[{"label":"続ける","next":"boss_suzaku"}]},"boss_suzaku":{"text":"紅蓮の翼が空を覆った。巨大な火の鳥が舞い降りてきた。「我は朱雀。南方の守護者。千年も火を灯し続けた。消えることが許されぬ炎というのは辛いものよ。だが——お主が我を消してくれるなら、それもまた良い。全力で来い」","type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"322","enemy_name":"朱雀","enemy_level":20,"choices":[{"label":"勝利","next":"reward_orb3"}],"battle_success_next":"reward_orb3"},"reward_orb3":{"text":"朱雀が散った。「……ありがとう。やっと……消えられる」残ったのは朱色の宝珠だけだった。温かい。朱雀の宝珠を手に入れた！","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"items":["623"]},"next":"choose_path","choices":[{"label":"続ける","next":"choose_path"}]},"trap_genbu":{"text":"北の道は暗く足場が悪い。突然大地が裂けた。岩の雨が降り注ぐ。地鳴りが低く響いている。何かが地中で蠢いている。","type":"modify_state","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20},"next":"boss_genbu","choices":[{"label":"続ける","next":"boss_genbu"}]},"boss_genbu":{"text":"大地が盛り上がり黒曜石の甲羅が姿を現した。巨大な亀。尾が蛇だった。「急ぐな。千年待った」蛇の尾が毒を吐く。「我は玄武。亀と蛇、二つの命を縫い合わされた。あの方の実験作のひとつよ。だから恨みはあるが……務めは務め。参る」","type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"323","enemy_name":"玄武","enemy_level":22,"choices":[{"label":"勝利","next":"reward_orb4"}],"battle_success_next":"reward_orb4"},"reward_orb4":{"text":"玄武が崩れた。「ようやくばらばらになれる。亀は亀に、蛇は蛇に。本来の姿に——」二つの光が別々の方向に消えていった。玄武の宝珠を手に入れた！","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"items":["624"]},"next":"choose_path","choices":[{"label":"続ける","next":"choose_path"}]},"check_orbs":{"text":"四つの宝珠が共鳴し塔の扉が開いた。螺旋階段を登りきると——頂上は拍子抜けするほど簡素だった。石の椅子に十歳ほどの少年が退屈そうに座っている。少年の目の奥に星が回っていた。人間の目ではない。","type":"text","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_boss","next":"text_kami2","choices":[{"label":"続ける","next":"text_kami2"}]},"text_kami2":{"text":"「おう、来たか。千年待ったぞ」少年が碁盤を蹴り飛ばした。「ここまで来たのはお前で百四十三人目だ。全員死んだ。今度こそ楽しませてくれよ。退屈で退屈でもう千年も碁を打ち続けてたんだからな」地面が揺れた。","type":"text","bg_key":"bg_spot_karyu_throne","speaker_name":"神","speaker":"神","next":"boss_kami","choices":[{"label":"続ける","next":"boss_kami"}]},"boss_kami":{"text":"「神」との最終決戦！","type":"battle","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_boss","enemy_group_id":"324","enemy_name":"神","enemy_level":25,"choices":[{"label":"勝利","next":"final_choice"}],"battle_success_next":"final_choice"},"final_choice":{"text":"少年が膝をついた。子供の姿が崩れ光の塊になっていく。「負けたよ。百四十三人目にして初めて負けた。勝者には選ぶ権利がある。俺の力を継いで新しい主になるか。塔ごと壊して全部なかったことにするか。どっちでもいいぞ。俺はもう退屈じゃなくなったからな」","type":"text","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_choice","next":"choice_final","choices":[{"label":"神の代理人として統べる","next":"end_rule"},{"label":"神の理を破壊し自由を掴む","next":"end_destroy"}]},"end_rule":{"text":"光を受け入れた。体に力が流れ込む。世界の全てが見える。石の椅子に座った。碁盤が新しくなっていた。「なるほど。これがあいつの見ていた景色か」退屈の意味が少しわかった気がした。天道の薙刀を手に入れた。重い。神の業は——とても重い。","type":"end","result":"success","bg_key":"bg_spot_karyu_throne","choices":[]},"end_destroy":{"text":"碁盤を踏み砕いた。石の椅子を蹴り倒した。「俺はお前の遊び道具じゃない」塔が根元から崩壊を始めた。地上に飛び出した瞬間背後で塔が倒れた。跡には何もなかった。四神もいない。神もいない。人々は自分の足で歩かなければならなくなった。固有スキル『神殺しの光芒』を手に入れた！","type":"end","result":"success","bg_key":"bg_spot_karyu_throne","choices":[]}}}'::jsonb, rewards = '{"gold":0,"exp":0,"reputation":0}'::jsonb WHERE id = 6103;

-- 6104_qst_spot_markand.csv (14 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"マルカンドの市場で老婆が倒れた。肌が灰色に変色し指先が砂のように崩れていく。「砂の病」だ。酒場で語り部の老人が言った。「原因はわかっとるよ。あの墓だ。千年前の王が呪いをかけた。自分を忘れるなという身勝手な呪いだ」","type":"text","bg_key":"bg_spot_markand_ruins","bgm":"bgm_markand","next":"text_start2","choices":[{"label":"続ける","next":"text_start2"}]},"text_start2":{"text":"老人は地図を指差した。「無名王の王墓。三千年誰も踏み込めなかった。入口の石板に『右手に真実を、左手に沈黙を、足元に謙譲を求めた』とある」老人はにやりと笑った。「行くなら止めんが——帰ってきた者は一人もおらんぞ」","type":"text","bg_key":"bg_spot_markand_ruins","speaker_name":"語り部の老人","speaker":"語り部の老人","next":"trap_01","choices":[{"label":"続ける","next":"trap_01"}]},"trap_01":{"text":"王墓の奥。第一の間「鏡の間」。三体の石像が並んでいる。両手を広げた像、片膝をついた像、目を伏せた像。壁に「太陽はどの姿を照らすか。答えを誤れば光が牙を剥く」と刻まれている。足元に骨が散らばっている。前に来た者の成れの果てだ。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","next":"choice_trap1","choices":[{"label":"目を伏せた像（謙譲）","next":"trap_02"},{"label":"両手を広げた像（傲慢）","next":"battle_trap_01"}]},"battle_trap_01":{"text":"像に触れた瞬間、壁の鏡が光った。鏡の中から自分と同じ姿をした光の戦士が抜け出してくる。顔が歪んでいる。嘲笑っている。壁に「傲慢なる者よ。己の影と戦え」と浮かんだ。","type":"battle","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","enemy_group_id":"330","enemy_name":"光の衛兵","enemy_level":18,"choices":[{"label":"勝利","next":"trap_02"}],"battle_success_next":"trap_02"},"trap_02":{"text":"第二の間「秤の間」。巨大な天秤の横に三つの箱。宝石、砂、空の箱。壁に「あなたの手に最も重い物を乗せよ」と刻まれている。宝石の箱の前に最も多くの骨がある——欲に目が眩んだのだろう。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","next":"choice_trap2","choices":[{"label":"空の箱を選ぶ（沈黙）","next":"trap_03"},{"label":"宝石の箱を選ぶ（欲望）","next":"battle_trap_02"}]},"battle_trap_02":{"text":"宝石に手を伸ばした瞬間、箱から砂が噴き出した。砂が渦を巻き人の形を作っていく。砂のゴーレムだ。壁に「沈黙は言葉より重い。欲を捨てよ」と浮かんだ。","type":"battle","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","enemy_group_id":"331","enemy_name":"砂のゴーレム","enemy_level":20,"choices":[{"label":"勝利","next":"trap_03"}],"battle_success_next":"trap_03"},"trap_03":{"text":"第三の間「棺の間」。中央に空の棺。縁に「死者に捧げるべき言葉は何か」と刻まれている。壁に「称賛」と「忘却」の選択肢。「称賛」の壁の前に骨が多い。この王は忘れられることを何より恐れた。だが正解は——","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","next":"choice_trap3","choices":[{"label":"「忘却」を選ぶ（真実）","next":"text_king"},{"label":"「称賛」を選ぶ（偽り）","next":"battle_trap_03"}]},"battle_trap_03":{"text":"棺から二体の守護者が這い出してきた。かつて王に仕えた近衛兵の成れの果て。兵士の一体が口を開いた。だが声はない。顎が上下に動いているだけだった——もう言葉を忘れているのだ。千年の間に。","type":"battle","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","enemy_group_id":"332","enemy_name":"混成の守護者","enemy_level":22,"choices":[{"label":"勝利","next":"text_king"}],"battle_success_next":"text_king"},"text_king":{"text":"最深部。黄金の広間。壁一面に一人の男の生涯が描かれていた。戦争、征服、建設、繁栄。そして孤独。最後の壁画は玉座に独り座る男の後ろ姿だった。広間の中央のミイラが動いた。「…………来たか」","type":"text","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_boss","next":"text_king2","choices":[{"label":"続ける","next":"text_king2"}]},"text_king2":{"text":"「三千年だ。三千年ここで待った。誰か来るのを。俺の名を呼ぶ者を」ミイラから砂の鎧が形成されていく。「俺は名前すら忘れた。千年かけて築いた王国の名すら誰も覚えていない。だから呪った。忘れるなら——道連れだ」砂の嵐が広間を満たした。","type":"text","bg_key":"bg_spot_markand_king","speaker_name":"無名王","speaker":"無名王","next":"boss_king","choices":[{"label":"続ける","next":"boss_king"}]},"boss_king":{"text":"無名王との最終決戦！","type":"battle","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_boss","enemy_group_id":"333","enemy_name":"無名王の影","enemy_level":25,"choices":[{"label":"勝利","next":"final_choice"}],"battle_success_next":"final_choice"},"final_choice":{"text":"砂王が崩れた。だがまだ動いている。胸の中央に黒い宝石が脈打っている。呪いの核「王の心臓」だ。砂王が笑った。「好きにしろ。壊すか飲むか。壊せば呪いは消えるが俺の知恵も失われる。飲めば力を得るがお前の体に俺の恨みが宿る。……もう疲れたのだ。三千年も恨み続けるのは」","type":"text","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_choice","next":"choice_final","choices":[{"label":"心臓を破壊し呪いを断つ","next":"end_break"},{"label":"心臓を宿し呪いを制御する","next":"end_curse"}]},"end_break":{"text":"黒い宝石を地面に叩きつけた。砂王の体が塵になり広間が灰色の石に戻っていく。街に戻ると砂の病に倒れていた者たちが目を覚ましていた。語り部の老人が出迎えた。「やったか。あの王の名はもう誰も知らん。だがお前がやったことは覚えておく」報酬として『砂王の断罪刃』を受け取った。三千年分の怒りが鋼に宿っている。","type":"end","result":"success","bg_key":"bg_spot_markand_king","choices":[]},"end_curse":{"text":"黒い宝石を飲み込んだ。体の中を砂が駆け巡る。腕に砂色の渦巻き紋章が浮かんだ。砂王の最後の言葉。「すまなかった。民を巻き込むべきではなかった」呪いは止まったが力は残った。人々は紋章を見て後ずさりした。語り部の老人だけが笑っていた。「面白い話が増えるのは語り部としては歓迎だ」固有スキル『砂塵の支配』を入手した！","type":"end","result":"success","bg_key":"bg_spot_markand_king","choices":[]}}}'::jsonb, rewards = '{"gold":0,"exp":0,"reputation":0}'::jsonb WHERE id = 6104;

-- 7001_qst_gen_deliver.csv (20 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"配達組合の窓口に、小太りの受付がうんざりした顔で座っていた。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"「ああ、来たか。隣街の旅籠『黄昏亭』の主人宛てに、封書を一通。内容は知らん。組合は中身に関知しない決まりだ」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"text_1b","choices":[{"label":"続ける","next":"text_1b"}]},"text_1b":{"text":"書類にサインを走らせると、受付は奥から蝋封された手紙を持ってきた。","type":"text","bg_key":"bg_guild","next":"briefing","choices":[{"label":"続ける","next":"briefing"}]},"briefing":{"text":"「往復で八日は見ておけ。街道の整備が追いつかなくなってから、追い剥ぎが出るようになった。何人か帰ってきてない配達人もいる」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"briefing_2","choices":[{"label":"続ける","next":"briefing_2"}]},"briefing_2":{"text":"受付は淡々と言い、煙管に火をつけた。「まあ、そのぶん報酬は上乗せしてある。死んだら払えんがな」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"receive_letter","choices":[{"label":"続ける","next":"receive_letter"}]},"receive_letter":{"text":"二重封印の封書を受け取った。思ったより重い。蝋に押された紋章は見覚えがない——どこかの商家のものだろうか。指で封を確かめると、かすかに薬草の匂いがした。気にしても仕方ない。運ぶだけだ。","type":"text","bg_key":"bg_guild","next":"depart","choices":[{"label":"続ける","next":"depart"}]},"depart":{"text":"街を出て、隣街へ続く街道を歩く。乾いた風が土埃を巻き上げ、道端の草は薄汚れている。轍の跡が途中で途切れている場所がある——荷馬車が引き返したのだろう。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"encounter_thief","choices":[{"label":"続ける","next":"encounter_thief"}]},"encounter_thief":{"text":"街道の曲がり角で、大柄な男が道を塞いでいた。背後の茂みからもう二人、やせぎすの男たちが姿を見せる。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"encounter_thief_2","choices":[{"label":"続ける","next":"encounter_thief_2"}]},"encounter_thief_2":{"text":"「おう、配達屋さんよ。その手紙、金目のものが入ってんだろ？」大柄な男がナイフを弄びながら、にやりと笑った。「置いていきな。手紙だけでいい。命までは取らねえよ——たぶんな」","type":"text","bg_key":"bg_road_day","speaker_name":"追い剥ぎの頭","speaker":"追い剥ぎの頭","next":"battle_thief","choices":[{"label":"続ける","next":"battle_thief"}]},"battle_thief":{"text":"追い剥ぎが襲いかかってきた！","type":"battle","bg_key":"bg_road_day","enemy_group_id":"400","enemy_name":"追い剥ぎ一味","enemy_level":3,"choices":[{"label":"win","next":"after_battle"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_battle"},"after_battle":{"text":"追い剥ぎを退けた。倒れた男の懐から、安っぽい銅貨が数枚こぼれ落ちた。こいつらも食い詰めて道に落ちた連中か。同情はしないが、後味は悪い。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"after_battle_2","choices":[{"label":"続ける","next":"after_battle_2"}]},"after_battle_2":{"text":"封書を確認する。無事だ。先を急ごう。","type":"text","bg_key":"bg_road_day","next":"arrive_inn","choices":[{"label":"続ける","next":"arrive_inn"}]},"arrive_inn":{"text":"旅籠・黄昏亭に到着した。看板の文字は半ば消えかけ、壁板は雨に晒されて黒ずんでいる。それでも酒場の明かりだけは煌々と灯っていた。","type":"text","bg_key":"bg_tavern_day","next":"arrive_inn_2","choices":[{"label":"続ける","next":"arrive_inn_2"}]},"arrive_inn_2":{"text":"奥のカウンターに立つ初老の男がこちらを見た。「……配達か。組合から？」無愛想だが、目だけは鋭い。","type":"text","bg_key":"bg_tavern_day","speaker_name":"黄昏亭の主人","speaker":"黄昏亭の主人","next":"deliver_choice","choices":[{"label":"続ける","next":"deliver_choice"}]},"deliver_choice":{"text":"封書を渡すか。","type":"text","bg_key":"bg_tavern_day","choices":[{"label":"封書を渡す","next":"delivery_ok"}]},"delivery_ok":{"text":"手紙を差し出すと、主人はゆっくりと封を確かめ、懐に収めた。","type":"text","bg_key":"bg_tavern_day","next":"delivery_ok_2","choices":[{"label":"続ける","next":"delivery_ok_2"}]},"delivery_ok_2":{"text":"「……ご苦労だった。組合への返答は、また別の使いに頼む」一瞬、主人の目に複雑な色が浮かんだように見えたが、すぐにいつもの無表情に戻った。「帰りも気をつけろ。最近は物騒だ」","type":"text","bg_key":"bg_tavern_day","speaker_name":"黄昏亭の主人","speaker":"黄昏亭の主人","next":"delivery_ok_3","choices":[{"label":"続ける","next":"delivery_ok_3"}]},"delivery_ok_3":{"text":"何かありそうな雰囲気だが、こちらの仕事は終わった。","type":"text","bg_key":"bg_tavern_day","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"往復八日の旅を終え、組合に帰還した。受付は相変わらず退屈そうな顔で報酬の袋を投げてよこした。「次もあるぞ。生きて戻ったんなら、また頼む」","type":"end","result":"success","bg_key":"bg_guild","choices":[]},"end_failure":{"text":"追い剥ぎに叩きのめされ、封書を奪われた。ボロボロの体で組合に戻ると、受付はため息をひとつついた。「……補償は出せんぞ。次があるかどうかも、お前次第だ」","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7001;

-- 7002_qst_gen_escort.csv (26 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"旅商人組合の窓口で依頼書を受け取った。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"「護衛対象は行商人のマルコ。隣街まで往復八日の旅だ。積み荷は雑貨と薬品。狙われやすい品ばかりだな」","type":"text","bg_key":"bg_guild","speaker_name":"旅商人組合の受付","speaker":"旅商人組合の受付","next":"text_1b","choices":[{"label":"続ける","next":"text_1b"}]},"text_1b":{"text":"受付の女が書類をめくりながら付け加えた。「先月、同じ路線で護衛二名が殺された。気を抜くなよ」","type":"text","bg_key":"bg_guild","speaker_name":"旅商人組合の受付","speaker":"旅商人組合の受付","next":"meet_merchant","choices":[{"label":"続ける","next":"meet_merchant"}]},"meet_merchant":{"text":"酒場の片隅で、小柄な中年男が荷物に囲まれて待っていた。額の汗を拭きながら、こちらに気づくと大袈裟に手を振った。","type":"text","bg_key":"bg_tavern_day","next":"meet_merchant_2","choices":[{"label":"続ける","next":"meet_merchant_2"}]},"meet_merchant_2":{"text":"「あんたが護衛かい？ ありがてえ！ マルコだ。見ての通り、腕っぷしはからきしでね。でも商売の話なら一晩中でも付き合うぜ」","type":"text","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"meet_merchant_3","choices":[{"label":"続ける","next":"meet_merchant_3"}]},"meet_merchant_3":{"text":"人懐こいが、どこか落ち着きがない。何か気にかかることがあるのだろう。","type":"text","bg_key":"bg_tavern_day","next":"join_escort","choices":[{"label":"続ける","next":"join_escort"}]},"join_escort":{"text":"マルコがパーティに加わった。大きな背負い箱を担ぎ、よたよたと歩き出す。","type":"guest_join","bg_key":"bg_tavern_day","params":{"guest_id":"npc_gen_merchant"},"next":"join_talk","choices":[{"label":"続ける","next":"join_talk"}]},"join_talk":{"text":"「よし、行こう！ ……ところで、前の護衛はどうなったんだい？」「殺されたそうだ」「…………はは、冗談きついな旦那」","type":"text","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"travel_start","choices":[{"label":"続ける","next":"travel_start"}]},"travel_start":{"text":"街を出て、隣街へ続く街道を歩き始めた。マルコの歩調は遅い。荷が重いのもあるが、息が上がるのが早い。","type":"text","bg_key":"bg_road_day","next":"road_talk","choices":[{"label":"続ける","next":"road_talk"}]},"road_talk":{"text":"日が傾き始めた頃、マルコが荷物越しに話しかけてきた。","type":"text","bg_key":"bg_road_day","next":"road_talk_2","choices":[{"label":"続ける","next":"road_talk_2"}]},"road_talk_2":{"text":"「なあ旦那、この荷の中に薬草が何束か入ってるんだが……正直に言うと、表向きは雑貨だが、中に少しだけ特別な品がある」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"road_talk_3","choices":[{"label":"続ける","next":"road_talk_3"}]},"road_talk_3":{"text":"こちらの表情を窺うように目を細めた。「あんたの報酬には響かねえよ。ただ、もし追い剥ぎに荷を見られたら——少し面倒なことになるかもしれねえって、それだけの話さ」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"road_talk_4","choices":[{"label":"続ける","next":"road_talk_4"}]},"road_talk_4":{"text":"何を運んでいるかは、深く聞かないことにした。","type":"text","bg_key":"bg_road_day","next":"midway","choices":[{"label":"続ける","next":"midway"}]},"midway":{"text":"街道の曲がり角。林の向こうに煙が見える——焚き火か、あるいは。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"bandit_encounter","choices":[{"label":"続ける","next":"bandit_encounter"}]},"bandit_encounter":{"text":"怒声が飛んだ。「止まれ！ 荷を置いていけ！」木の陰から数人の男が飛び出してきた。粗末な革鎧に、刃こぼれした剣。食い詰めた夜盗の類だ。","type":"text","bg_key":"bg_road_day","next":"bandit_encounter_2","choices":[{"label":"続ける","next":"bandit_encounter_2"}]},"bandit_encounter_2":{"text":"「旦那ッ！ 頼むッ！ 荷だけは——荷だけは守ってくれ！」背後でマルコが荷物を抱えて縮こまっている。こいつを守りながら戦わなければならない。","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"battle_bandit","choices":[{"label":"続ける","next":"battle_bandit"}]},"battle_bandit":{"text":"夜盗が襲いかかってきた！","type":"battle","bg_key":"bg_road_day","enemy_group_id":"400","enemy_name":"夜盗一味","enemy_level":3,"choices":[{"label":"win","next":"after_battle"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_battle"},"after_battle":{"text":"夜盗を蹴散らした。逃げていく背中を見送ると、マルコがおそるおそる荷物から顔を出した。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"after_battle_2","choices":[{"label":"続ける","next":"after_battle_2"}]},"after_battle_2":{"text":"「……終わったかい？ 全部あるか確認させてくれ」震える手で荷を検める。しばらくして、深い息をついた。「……全部ある。あんた、本物だ」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"travel_end","choices":[{"label":"続ける","next":"travel_end"}]},"travel_end":{"text":"残りの道のりは平穏だった。マルコは黙って歩いていたが、やがてぽつりと呟いた。「……前の護衛が死んだ話、冗談じゃなかったんだな。あんたに頼んでよかったよ」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"arrive_town","choices":[{"label":"続ける","next":"arrive_town"}]},"arrive_town":{"text":"隣街に到着した。マルコは通りかかる知人に声をかけながら、慣れた手つきで荷を降ろし始めた。「ここまで来りゃ安心だ。知り合いの問屋に卸してくる」","type":"text","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"farewell","choices":[{"label":"続ける","next":"farewell"}]},"farewell":{"text":"取引を終えたマルコが、上機嫌で戻ってきた。懐から報酬の入った革袋を差し出す。","type":"text","bg_key":"bg_tavern_day","next":"farewell_2","choices":[{"label":"続ける","next":"farewell_2"}]},"farewell_2":{"text":"「約束通りだ、受け取ってくれ。……あの特別な品のこと、口外しないでくれよ？ ははっ」冗談めかしてはいるが、目は笑っていなかった。","type":"text","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"leave_escort","choices":[{"label":"続ける","next":"leave_escort"}]},"leave_escort":{"text":"マルコがパーティから離脱した。「またいい仕事があったら組合に顔を出してくれ。次も頼むよ、旦那！」","type":"leave","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"護衛任務完了。組合に帰還し、報酬を受け取った。マルコの特別な品が何だったかは、考えないことにした。","type":"end","result":"success","bg_key":"bg_guild","choices":[]},"end_failure":{"text":"マルコが倒れた。荷物は散乱し、夜盗に奪われた。組合に戻ると、受付の女が冷たい目で書類を処理していた。「護衛失敗。報酬はなし。次があるかは、組合の判断だ」","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7002;

-- 7003_qst_gen_scavenge.csv (22 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"冒険者ギルドの掲示板に、急ぎの依頼が貼られていた。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"依頼書にはこうある。「崩壊街区の廃墟金庫から物資を回収。中身は開封不可。ギルドの管理品につき、持ち逃げ厳禁」","type":"text","bg_key":"bg_guild","next":"text_1b","choices":[{"label":"続ける","next":"text_1b"}]},"text_1b":{"text":"担当の男がぶっきらぼうに言った。「場所は知ってるな？ 先週の地震で通路が崩れてる。ゴブリンが住み着いてるって話もある」","type":"text","bg_key":"bg_guild","speaker_name":"ギルド担当","speaker":"ギルド担当","next":"accept_job","choices":[{"label":"続ける","next":"accept_job"}]},"accept_job":{"text":"「回収できたら真っ直ぐ持って来い。余計なことはするなよ」依頼書にサインを入れ、廃墟の地図を受け取った。道のりは近い。日が暮れる前には戻れるだろう。","type":"text","bg_key":"bg_guild","speaker_name":"ギルド担当","speaker":"ギルド担当","next":"enter_ruins","choices":[{"label":"続ける","next":"enter_ruins"}]},"enter_ruins":{"text":"廃墟に足を踏み入れた。天井の半ばが崩れ、瓦礫が散乱している。壁に刻まれた古い紋章が、かつてここが商家の倉庫だったことを示していた。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"enter_ruins_2","choices":[{"label":"続ける","next":"enter_ruins_2"}]},"enter_ruins_2":{"text":"奥に進むと、薄暗い通路の先に錆びた鉄扉が見えた。","type":"text","bg_key":"bg_ruins_field","next":"encounter_goblin","choices":[{"label":"続ける","next":"encounter_goblin"}]},"encounter_goblin":{"text":"鉄扉の前に、ゴブリンが2匹屯していた。壊れた木箱を漁り、中身を品定めしている。こちらに気づくと、甲高い声で威嚇してきた。","type":"text","bg_key":"bg_ruins_field","next":"battle_goblin","choices":[{"label":"続ける","next":"battle_goblin"}]},"battle_goblin":{"text":"ゴブリンが襲いかかってきた！","type":"battle","bg_key":"bg_ruins_field","enemy_group_id":"402","enemy_name":"ゴブリン x2","enemy_level":2,"choices":[{"label":"win","next":"after_goblin"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_goblin"},"after_goblin":{"text":"ゴブリンを倒した。鉄扉に近づき、錆びた錠前をこじ開ける。中には頑丈な金庫が一つ。ギルドの紋章が刻まれた封印が施されている。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","next":"after_goblin_2","choices":[{"label":"続ける","next":"after_goblin_2"}]},"after_goblin_2":{"text":"金庫の横に、もう一つの通路が見えた。","type":"text","bg_key":"bg_ruins_field","next":"second_battle","choices":[{"label":"続ける","next":"second_battle"}]},"second_battle":{"text":"奥の通路からホブゴブリンが現れた！ 体格が違う。こいつが巣のボスか。取り巻きのゴブリンが2匹、その後ろに控えている。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"battle_hob","choices":[{"label":"続ける","next":"battle_hob"}]},"battle_hob":{"text":"ホブゴブリンと取り巻きが襲いかかってきた！","type":"battle","bg_key":"bg_ruins_field","enemy_group_id":"403","enemy_name":"ホブゴブリンの群れ","enemy_level":3,"choices":[{"label":"win","next":"recover_box"},{"label":"lose","next":"end_failure"}],"battle_success_next":"recover_box"},"recover_box":{"text":"ホブゴブリンを退けた。金庫を担ぎ上げ、廃墟を後にする。ずっしりと重い。中身は何だろう——いや、開封不可と言われている。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","next":"recover_box_2","choices":[{"label":"続ける","next":"recover_box_2"}]},"recover_box_2":{"text":"だが、ふと考えた。闇市に持ち込めば、ギルドに届けるよりはるかに高く売れるだろう。","type":"text","bg_key":"bg_road_day","next":"choice_moral","choices":[{"label":"続ける","next":"choice_moral"}]},"choice_moral":{"text":"金庫を手にしたまま、岐路に立つ。","type":"text","bg_key":"bg_road_day","choices":[{"label":"ギルドに届ける","next":"deliver_guild"},{"label":"闇市に売る","next":"sell_black"}]},"deliver_guild":{"text":"金庫をギルドに持ち帰った。担当が封印を確認し、満足げに頷いた。","type":"text","bg_key":"bg_guild","next":"deliver_guild_2","choices":[{"label":"続ける","next":"deliver_guild_2"}]},"deliver_guild_2":{"text":"「無事だな。よくやった。報酬だ」約束通りの金貨を受け取った。正しいことをした——はずだ。","type":"text","bg_key":"bg_guild","speaker_name":"ギルド担当","speaker":"ギルド担当","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"sell_black":{"text":"闇市の裏路地に金庫を持ち込んだ。目利きの男が中身を検め、にやりと笑った。","type":"text","bg_key":"bg_slum","next":"sell_black_2","choices":[{"label":"続ける","next":"sell_black_2"}]},"sell_black_2":{"text":"「いい品だ。倍額で買おう」金貨の入った袋を受け取った。ギルドには「廃墟が崩落して回収不能だった」と報告した。嘘がバレなければいいが。","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"end_dark","choices":[{"label":"続ける","next":"end_dark"}]},"end_success":{"text":"物資回収完了。正当な報酬を受け取った。","type":"end","result":"success","bg_key":"bg_guild","choices":[]},"end_dark":{"text":"闇市で金庫を売りさばいた。報酬は倍。だが、良心が少し痛む。","type":"end","result":"success","bg_key":"bg_slum","choices":[]},"end_failure":{"text":"ゴブリンに叩きのめされた。金庫の回収は失敗に終わった。","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7003;

-- 7004_qst_gen_riot.csv (14 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"自治会の事務所に呼ばれた。窓の外から怒声が聞こえる。","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"事務官が苦い顔で書類を差し出した。「東区画の広場に、飢えた市民が集まっている。このままでは暴動になる。鎮圧してくれ」","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"briefing","choices":[{"label":"続ける","next":"briefing"}]},"briefing":{"text":"「連中は先月の凶作で食い詰めた農民だ。配給が回らず、自治会の倉庫を襲う計画を立てている」事務官は窓の方を見た。","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"briefing_2","choices":[{"label":"続ける","next":"briefing_2"}]},"briefing_2":{"text":"「正直に言えば、連中の気持ちは分からんでもない。だが暴動を許せば秩序が崩れる。力で抑えてくれ——なるべく殺さずに」","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"go_square","choices":[{"label":"続ける","next":"go_square"}]},"go_square":{"text":"東区画の広場に向かった。石畳の広場に、ぼろ切れを纏った市民たちが群がっている。子供を抱えた女、杖にすがる老人、そして——鎌や棒切れを握った若い男たち。","type":"text","bg_key":"bg_slum","bgm":"bgm_quest_tense","next":"go_square_2","choices":[{"label":"続ける","next":"go_square_2"}]},"go_square_2":{"text":"リーダーらしき男が声を張り上げていた。「俺たちは飢えてるんだ！ 倉庫を開けろ！ 食わせろ！」","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"confront","choices":[{"label":"続ける","next":"confront"}]},"confront":{"text":"群衆の前に立ちはだかった。一瞬、静寂が広がった。","type":"text","bg_key":"bg_slum","next":"confront_2","choices":[{"label":"続ける","next":"confront_2"}]},"confront_2":{"text":"「自治会の犬か……。俺たちを殺すのか？ 飢えた子供を守ろうとしてるだけだぞ！」後ろの群衆がざわめく。棒切れを握る手に力が入ったのが見えた。","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"battle_mob","choices":[{"label":"続ける","next":"battle_mob"}]},"battle_mob":{"text":"暴動が始まった！ 武装した市民たちが襲いかかってきた！","type":"battle","bg_key":"bg_slum","enemy_group_id":"404","enemy_name":"飢えた市民 x5","enemy_level":2,"choices":[{"label":"win","next":"after_riot"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_riot"},"after_riot":{"text":"暴徒を鎮圧した。地面にうずくまる市民たち。呻き声が広場に響いている。","type":"text","bg_key":"bg_slum","bgm":"bgm_quest_calm","next":"after_riot_2","choices":[{"label":"続ける","next":"after_riot_2"}]},"after_riot_2":{"text":"リーダーの男が血を吐きながら、こちらを見上げた。「……俺たちが悪いんじゃねえ。飢えさせた奴らが悪いんだ……」","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"after_riot_3","choices":[{"label":"続ける","next":"after_riot_3"}]},"after_riot_3":{"text":"自治会の衛兵が到着し、残った群衆を解散させた。子供の泣き声が、いつまでも耳に残った。","type":"text","bg_key":"bg_slum","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"鎮圧任務完了。自治会から報酬を受け取った。秩序は守られた——だが、あの男の言葉が胸に刺さったままだ。","type":"end","result":"success","bg_key":"bg_office","choices":[]},"end_failure":{"text":"暴徒に押し返された。鎮圧は失敗に終わった。","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7004;

-- 7005_qst_gen_bear.csv (16 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"開拓村の長が待つ集会所に入った。初老の男が地図を広げ、こちらを見た。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"「来てくれたか。村の東の森に、凶暴な大熊が棲みついた。畑を荒らし、家畜を襲う。先週、見回りの猟師が行方不明になった」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"briefing","choices":[{"label":"続ける","next":"briefing"}]},"briefing":{"text":"「猟師のヨルンは腕利きだったが、三日経っても戻らん。森の中に血痕が点々と続いていたそうだ」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"briefing_2","choices":[{"label":"続ける","next":"briefing_2"}]},"briefing_2":{"text":"村長は声を落とした。「あの熊は普通じゃない。傷跡だらけで、片目が潰れている。何かに追われて狂ったのかもしれん」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"enter_forest","choices":[{"label":"続ける","next":"enter_forest"}]},"enter_forest":{"text":"森に入った。木々は密に茂り、日光がほとんど届かない。地面に大きな獣の足跡が残っている。爪の跡が異常に深い。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"find_trail","choices":[{"label":"続ける","next":"find_trail"}]},"find_trail":{"text":"足跡を追った先に、引き裂かれた罠が転がっていた。猟師ヨルンのものだろう。近くの木の幹に深い爪痕が刻まれている。樹液が血のように滲み出していた。","type":"text","bg_key":"bg_forest_day","next":"find_trail_2","choices":[{"label":"続ける","next":"find_trail_2"}]},"find_trail_2":{"text":"さらに奥へ進むと、獣の匂いが濃くなった。低い唸り声が、藪の向こうから聞こえる。","type":"text","bg_key":"bg_forest_day","next":"encounter_bear","choices":[{"label":"続ける","next":"encounter_bear"}]},"encounter_bear":{"text":"茂みを掻き分けると、巨大な熊が立ち上がった。体中に古傷が走り、片目は白く濁っている。口元に赤いものがこびりついていた。","type":"text","bg_key":"bg_forest_day","next":"encounter_bear_2","choices":[{"label":"続ける","next":"encounter_bear_2"}]},"encounter_bear_2":{"text":"こちらを認めると、大地を揺らすような咆哮を上げた。逃げ場はない。","type":"text","bg_key":"bg_forest_day","next":"battle_bear","choices":[{"label":"続ける","next":"battle_bear"}]},"battle_bear":{"text":"ジャイアントベアが襲いかかってきた！","type":"battle","bg_key":"bg_forest_day","enemy_group_id":"405","enemy_name":"ジャイアントベア","enemy_level":4,"choices":[{"label":"win","next":"after_bear"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_bear"},"after_bear":{"text":"大熊が崩れ落ちた。最後に一度だけ、残った片目でこちらを見た。その目に宿っていたのは、怒りではなく——疲労だった。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"after_bear_2","choices":[{"label":"続ける","next":"after_bear_2"}]},"after_bear_2":{"text":"分厚い毛皮を剥いだ。これだけでも報酬になる。熊の近くに、猟師の外套の切れ端が見つかった。ヨルンの最期を想像すると、胃の辺りが重くなった。","type":"text","bg_key":"bg_forest_day","next":"return_village","choices":[{"label":"続ける","next":"return_village"}]},"return_village":{"text":"村に戻り、毛皮を見せると村長が深く頷いた。","type":"text","bg_key":"bg_guild","next":"return_village_2","choices":[{"label":"続ける","next":"return_village_2"}]},"return_village_2":{"text":"「やってくれたか……。ヨルンの遺品は見つかったか？」外套の切れ端を差し出すと、村長は黙って受け取った。しばらくして、報酬と獣の毛皮を手渡された。「ありがとう。これで村の連中も安心できる」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"凶熊狩り完了。報酬と獣の毛皮を受け取った。","type":"end","result":"success","bg_key":"bg_guild","choices":[]},"end_failure":{"text":"大熊の猛攻に倒れた。意識が薄れていく中、獣の咆哮が遠ざかっていった。","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7005;

-- 7006_qst_gen_smuggle.csv (12 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"路地裏で闇商人が待っていた。フードの奥から鋭い目がこちらを見据える。","type":"text","bg_key":"bg_slum","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"「話は通してある。中身は聞くな。この箱を隣街の『赤猫亭』の主人に届けろ。それだけだ」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"briefing","choices":[{"label":"続ける","next":"briefing"}]},"briefing":{"text":"「街道は使うな。検問がある。旧道を通れ。……追手がかかるかもしれんが、そのときはお前の腕で何とかしろ」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"briefing_2","choices":[{"label":"続ける","next":"briefing_2"}]},"briefing_2":{"text":"闇商人は木箱を押しつけ、闇に消えた。箱はずっしりと重い。中で何かが鈍く音を立てた。","type":"text","bg_key":"bg_slum","next":"depart","choices":[{"label":"続ける","next":"depart"}]},"depart":{"text":"旧道に入った。舗装されていない獣道。月明かりだけが頼りだ。箱を背負い、足音を殺して進む。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","next":"travel_night","choices":[{"label":"続ける","next":"travel_night"}]},"travel_night":{"text":"道の途中で、背後に気配を感じた。振り返ると、闇の中に人影が二つ。こちらを追ってきている。検問の兵か、あるいは別の組織の追手か。","type":"text","bg_key":"bg_road_night","next":"encounter_guard","choices":[{"label":"続ける","next":"encounter_guard"}]},"encounter_guard":{"text":"「止まれ！ その荷を置いていけ！」追手が武器を構えた。逃げるか、戦うか——答えは決まっている。","type":"text","bg_key":"bg_road_night","speaker_name":"追手","speaker":"追手","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"text":"追手が襲いかかってきた！","type":"battle","bg_key":"bg_road_night","enemy_group_id":"406","enemy_name":"追手部隊","enemy_level":5,"choices":[{"label":"win","next":"after_fight"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_fight"},"after_fight":{"text":"追手を退けた。荷を確認する。無事だ。これ以上長居は危険だ。走れ。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_calm","next":"safe_arrival","choices":[{"label":"続ける","next":"safe_arrival"}]},"safe_arrival":{"text":"夜明け前に隣街に辿り着いた。「赤猫亭」の裏口を叩くと、無言の男が現れ、箱を受け取った。代わりに重い革袋を押しつけられた。中身は金貨。","type":"text","bg_key":"bg_tavern_night","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"密輸完了。金は多いが、後味は悪い。何を運んだのかは、知らないままのほうがいい。","type":"end","result":"success","bg_key":"bg_tavern_night","choices":[]},"end_failure":{"text":"追手に捕まり、荷を没収された。闇商人への報告が怖い。","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7006;

-- 7007_qst_gen_rat.csv (15 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"自治会の事務所で、衛生担当の役人が鼻を押さえながら言った。","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"「地下水路に巨大ネズミが大量発生している。悪臭と伝染病の原因だ。駆除してくれ」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"briefing","choices":[{"label":"続ける","next":"briefing"}]},"briefing":{"text":"「先月、下水道の修繕工が噛まれて熱を出した。犬ほどの大きさがあるらしい」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"briefing_2","choices":[{"label":"続ける","next":"briefing_2"}]},"briefing_2":{"text":"「しかも最近、奥の方から気味の悪い鳴き声が聞こえるという報告もある」役人は地下水路の地図を広げた。「入口はここだ。深追いはするな……と言いたいところだが、根絶しないと意味がない」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"enter_sewer","choices":[{"label":"続ける","next":"enter_sewer"}]},"enter_sewer":{"text":"地下水路に降りた。足元を汚水が流れ、壁には苔がびっしりと生えている。松明の灯りに、無数の小さな赤い目が光った。すぐに闇に消えたが——奥から、カリカリと爪で石を引っ掻く音が聞こえる。","type":"text","bg_key":"bg_catacombs","bgm":"bgm_quest_tense","next":"first_encounter","choices":[{"label":"続ける","next":"first_encounter"}]},"first_encounter":{"text":"通路を進むと、巨大なネズミが3匹、腐肉を漁っていた。こちらに気づくと、歯を剥き出して威嚇してきた。犬ほどの大きさという報告は本当だった。","type":"text","bg_key":"bg_catacombs","next":"battle_rat_1","choices":[{"label":"続ける","next":"battle_rat_1"}]},"battle_rat_1":{"text":"巨大ネズミの群れが襲いかかってきた！","type":"battle","bg_key":"bg_catacombs","enemy_group_id":"407","enemy_name":"巨大ネズミ x3","enemy_level":2,"choices":[{"label":"win","next":"after_first"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_first"},"after_first":{"text":"群れを退けた。だが、奥からさらに不気味な音が聞こえる。地響きのような、重い足音。何かがこちらに向かってくる。","type":"text","bg_key":"bg_catacombs","bgm":"bgm_quest_tense","next":"nest_approach","choices":[{"label":"続ける","next":"nest_approach"}]},"nest_approach":{"text":"水路の最深部。そこには巨大な巣があった。骨と布切れで作られた巣の中央に、一回り大きなネズミが鎮座している。","type":"text","bg_key":"bg_catacombs","next":"nest_approach_2","choices":[{"label":"続ける","next":"nest_approach_2"}]},"nest_approach_2":{"text":"頭に骨のような突起。禍々しい紫の目がこちらを捉えた。ネズミの女王だ。その足元に、取り巻きの巨大ネズミが2匹控えている。","type":"text","bg_key":"bg_catacombs","next":"battle_rat_2","choices":[{"label":"続ける","next":"battle_rat_2"}]},"battle_rat_2":{"text":"ネズミの女王と取り巻きが襲いかかってきた！","type":"battle","bg_key":"bg_catacombs","enemy_group_id":"408","enemy_name":"ネズミの女王","enemy_level":5,"choices":[{"label":"win","next":"after_queen"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_queen"},"after_queen":{"text":"ネズミの女王が倒れた。巣が崩れ、残った子ネズミたちが蜘蛛の子を散らすように逃げていった。","type":"text","bg_key":"bg_catacombs","bgm":"bgm_quest_calm","next":"after_queen_2","choices":[{"label":"続ける","next":"after_queen_2"}]},"after_queen_2":{"text":"悪臭が薄れていくのを感じた。これで地下水路は清掃できる。","type":"text","bg_key":"bg_catacombs","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"害獣駆除完了。自治会に報告し、報酬を受け取った。しばらくはネズミの夢を見そうだ。","type":"end","result":"success","bg_key":"bg_office","choices":[]},"end_failure":{"text":"ネズミの群れに圧倒された。地下水路から這い出すのがやっとだった。","type":"end","result":"failure","choices":[]}}}'::jsonb WHERE id = 7007;

-- 7008_qst_gen_mercy.csv (28 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"掲示板に貼られた依頼書は、他のものとは紙の質が違っていた。安い紙に、震える字で書かれている。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"text_1a","choices":[{"label":"続ける","next":"text_1a"}]},"text_1a":{"text":"依頼書にはこう書かれていた。「薬草を集めて、野営地の修道女に届けてください。報酬はほとんど出せません。すみません」金にならない仕事だ。だが——掲示板に残っているということは、誰も手をつけていないということだ。","type":"text","bg_key":"bg_guild","next":"meet_sister","choices":[{"label":"続ける","next":"meet_sister"}]},"meet_sister":{"text":"依頼主に会いに行くと、酒場の片隅で修道女が待っていた。白い法衣は薄汚れ、目の下に深い隈がある。","type":"text","bg_key":"bg_tavern_day","next":"meet_sister_2","choices":[{"label":"続ける","next":"meet_sister_2"}]},"meet_sister_2":{"text":"「来てくださったのですか……ありがとうございます。私はシスター・エレナ。街の東にある難民の野営地で、怪我人の手当てをしています。ですが、薬草が底をついてしまって」","type":"text","bg_key":"bg_tavern_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"meet_sister_3","choices":[{"label":"続ける","next":"meet_sister_3"}]},"meet_sister_3":{"text":"声は落ち着いているが、指先が細かく震えていた。","type":"text","bg_key":"bg_tavern_day","next":"visit_camp","choices":[{"label":"続ける","next":"visit_camp"}]},"visit_camp":{"text":"エレナに案内されて、野営地を訪れた。粗末なテントが並んでいる。毛布は足りていない。子供たちが泥だらけの顔で、ぼんやりとこちらを見ている。","type":"text","bg_key":"bg_road_day","next":"visit_camp_2","choices":[{"label":"続ける","next":"visit_camp_2"}]},"visit_camp_2":{"text":"テントの奥では、熱にうなされる老人が横たわっていた。布を巻いた腕から、染みた血が滲んでいる。","type":"text","bg_key":"bg_road_day","next":"visit_camp_3","choices":[{"label":"続ける","next":"visit_camp_3"}]},"visit_camp_3":{"text":"「あの方は先週の戦で逃げてきた人です。矢傷が化膿しています。癒やし草があれば……せめて、痛みだけでも」エレナの目に涙はなかった。泣き尽くしたのだろう。","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"depart_forest","choices":[{"label":"続ける","next":"depart_forest"}]},"depart_forest":{"text":"野営地を後にし、森の外れに向かった。癒やし草の群生地があると、エレナが教えてくれた場所だ。","type":"text","bg_key":"bg_forest_day","next":"depart_forest_2","choices":[{"label":"続ける","next":"depart_forest_2"}]},"depart_forest_2":{"text":"「沢の近く、苔の生えた岩の周りに生えています。白い小さな花が目印です。五束は必要です」","type":"text","bg_key":"bg_forest_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"gather_01","choices":[{"label":"続ける","next":"gather_01"}]},"gather_01":{"text":"森に入った。木漏れ日の下、湿った土の匂い。沢沿いを歩き、苔むした岩の陰に白い花を見つけた。指先で慎重に根元から摘み取る。一束目。","type":"text","bg_key":"bg_forest_day","next":"gather_01b","choices":[{"label":"続ける","next":"gather_01b"}]},"gather_01b":{"text":"まだ足りない。もう少し奥を探そう。","type":"text","bg_key":"bg_forest_day","next":"gather_02","choices":[{"label":"続ける","next":"gather_02"}]},"gather_02":{"text":"倒木の影にも群生を見つけた。三束目。採取しながら、野営地の老人の顔を思い出す。あの傷では、遅れれば命に関わる。急がねば。","type":"text","bg_key":"bg_forest_day","next":"gather_03","choices":[{"label":"続ける","next":"gather_03"}]},"gather_03":{"text":"沢の上流まで足を伸ばした。岸辺の一角を探す。群生があるはずだが——","type":"text","bg_key":"bg_forest_day","next":"gather_branch","choices":[{"label":"続ける","next":"gather_branch"}]},"gather_branch":{"text":"採取の成否","type":"random_branch","prob":70,"choices":[{"label":"hit","next":"gather_complete"},{"label":"miss","next":"gather_fail_text"}]},"gather_complete":{"text":"四束目、五束目。規定の数が揃った。布で丁寧に包む。傷んだら効果が落ちるからだ。日が傾き始めている。野営地まで、急ぎ足で一刻ほど。","type":"text","bg_key":"bg_forest_day","next":"deliver_herbs","choices":[{"label":"続ける","next":"deliver_herbs"}]},"gather_fail_text":{"text":"……だめだ。日照りの影響か、群生地が枯れている。三束しか集まらなかった。五束には足りない。","type":"text","bg_key":"bg_forest_day","next":"gather_fail_text_2","choices":[{"label":"続ける","next":"gather_fail_text_2"}]},"gather_fail_text_2":{"text":"手持ちの荷物を確かめる。以前どこかで手に入れた癒やし草があれば、足りない分を補えるかもしれない。","type":"text","bg_key":"bg_forest_day","next":"check_herb","choices":[{"label":"続ける","next":"check_herb"}]},"check_herb":{"text":"所持品を確認する。","type":"check_possession","params":{"item_id":702,"quantity":5,"fallback":"not_enough"},"next":"deliver_herbs_backup","choices":[{"label":"続ける","next":"deliver_herbs_backup"}]},"deliver_herbs_backup":{"text":"手持ちの癒やし草を合わせれば、なんとか五束分になる。これで足りるはずだ。急いで野営地へ戻ろう。","type":"text","bg_key":"bg_forest_day","next":"deliver_herbs","choices":[{"label":"続ける","next":"deliver_herbs"}]},"not_enough":{"text":"手持ちにも癒やし草はなかった。三束では……薬としては不十分だ。それでも、持っていくしかない。","type":"text","bg_key":"bg_forest_day","next":"not_enough_2","choices":[{"label":"続ける","next":"not_enough_2"}]},"not_enough_2":{"text":"野営地に戻り、三束だけの癒やし草をエレナに渡した。彼女は受け取り、中身を確認して……静かに目を伏せた。","type":"text","bg_key":"bg_road_day","next":"not_enough_3","choices":[{"label":"続ける","next":"not_enough_3"}]},"not_enough_3":{"text":"「……ありがとうございます。でも、これでは足りないのです。煎じ薬にするには最低五束が……」声が震えている。こちらを責めているのではない。ただ、現実を受け入れようとしているだけだ。","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"deliver_herbs":{"text":"野営地に戻ると、エレナが入口で待っていた。癒やし草の包みを渡すと、彼女は両手で受け取り、深く息をついた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"deliver_herbs_2","choices":[{"label":"続ける","next":"deliver_herbs_2"}]},"deliver_herbs_2":{"text":"「これで……これで助けられます。ありがとう、本当に」すぐに煎じ薬の準備に取りかかった。手際がいい。慣れているのだ——こういう状況に。","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"deliver_herbs_3","choices":[{"label":"続ける","next":"deliver_herbs_3"}]},"deliver_herbs_3":{"text":"「報酬は……ほとんど出せないのですが」エレナが申し訳なさそうに、小さな革袋を差し出した。中には銅貨が数枚。","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"薬草の納品完了。報酬は銅貨10枚——腹は膨れない。だが、テントの奥から老人の呻き声が小さくなったのが聞こえた。エレナが振り返り、遠くから深々と頭を下げた。帰り道。いつもの酒場が見えた頃、不思議と足取りが軽くなっていることに気づいた。","type":"end","result":"success","bg_key":"bg_road_day","choices":[]},"end_failure":{"text":"薬草が足りなかった。エレナは微笑んだ。「大丈夫です。きっと別の方が……」その笑顔が、何より辛かった。あの老人の呻き声が、帰り道もずっと耳から離れなかった。","type":"end","result":"failure","bg_key":"bg_road_day","choices":[]}}}'::jsonb WHERE id = 7008;

